window.PACTO.acts["reg-2021-1060"]={"label": "REGOLAMENTO (UE) 2021/1060 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2021/1060", "file": "ext-reg-2021-1060.html", "external": true, "version": "consolidato 2026-07-01", "eurlex": "https://eur-lex.europa.eu/eli/reg/2021/1060/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e ambito di applicazione", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il presente regolamento stabilisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le disposizioni finanziarie applicabili al Fondo europeo di sviluppo regionale (FESR), al Fondo sociale europeo Plus (FSE+), al Fondo di coesione, al Fondo per una transizione giusta (JTF), al Fondo europeo per gli affari marittimi, la pesca e l’acquacoltura (FEAMPA), al Fondo Asilo, migrazione e integrazione (AMIF), al Fondo Sicurezza interna (ISF) e allo Strumento di sostegno finanziario per la politica di gestione delle frontiere e la politica dei visti (BMVI) (collettivamente, i «fondi») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le disposizioni comuni applicabili al FESR, al FSE+, al Fondo di coesione, al JTF e al FEAMPA.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il presente regolamento non si applica alla componente Occupazione e innovazione sociale del FSE+ né alle componenti in gestione diretta o indiretta del FEAMPA, dell’AMIF, dell’ISF e del BMVI, ad eccezione dell’assistenza tecnica su iniziativa della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli articoli 5, 14, 19, da 28 a 34 e da 108 a 112 non si applicano all’AMIF, all’ISF o al BMVI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Articolo da 108 a 112 non si applicano al FEAMPA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli articoli 14, 15, 18, da 21 a 27, da 37 a 42, l’articolo 43, paragrafi da 1 a 4, gli articoli 44 e 50, l’articolo 55, paragrafo 1, e gli articoli 73, 77, 80 e da 83 a 85 non si applicano ai programmi Interreg.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I regolamenti specifici relativi a ciascun fondo indicati di seguito possono stabilire regole per integrare il presente regolamento senza contraddirlo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento (UE) 2021/1060 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n) («regolamento FESR e Fondo di coesione») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento (UE) 2021/1060 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n) («regolamento FSE+») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento (UE) 2021/1060 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n) («regolamento Interreg») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento (UE) 2021/1060 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n) («regolamento JTF»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento del Parlamento europeo e del Consiglio che istituisce il Fondo europeo per gli affari marittimi, la pesca e l’acquacoltura e che modifica il regolamento (UE) 2017/1004 («regolamento FEAMPA») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento del Parlamento europeo e del Consiglio che istituisce il Fondo Asilo, migrazione e integrazione («regolamento AMIF») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento del Parlamento europeo e del Consiglio che istituisce il Fondo Sicurezza interna («regolamento ISF») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regolamento del Parlamento europeo e del Consiglio che istituisce, nell’ambito del Fondo per la gestione integrata delle frontiere, lo Strumento di sostegno finanziario per la gestione delle frontiere e la politica dei visti («regolamento BMVI») ;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In caso di dubbio sull’applicazione del presente regolamento o dei regolamenti specifici relativi a ciascun fondo, è preminente il presente regolamento.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si applicano le definizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«pertinenti raccomandazioni specifiche per paese»: le raccomandazioni del Consiglio adottate a norma degli articoli 121, paragrafo 2, e 148, paragrafo 4, TFUE relative alle sfide strutturali, nonché le raccomandazioni complementari della Commissione formulate conformemente all’articolo 34 del regolamento (UE) 2018/1999, cui è appropriato dare seguito mediante investimenti pluriennali che ricadono nell’ambito di applicazione dei fondi come stabilito nei regolamenti specifici relativi ai ciascun fondo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«condizione abilitante»: una condizione preliminare per l’attuazione efficace ed efficiente degli obiettivi specifici;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«diritto applicabile»: il diritto dell’Unione e il diritto nazionale relativo alla sua applicazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operazione»:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un progetto, un contratto, un’azione o un gruppo di progetti selezionati nell’ambito dei programmi in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel contesto degli strumenti finanziari, il contributo del programma a uno strumento finanziario e il successivo sostegno finanziario fornito ai destinatari finali da tale strumento finanziario;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operazione di importanza strategica»: operazione che fornisce un contributo significativo al conseguimento degli obiettivi di un programma e che è soggetta a particolari misure di sorveglianza e comunicazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«priorità» nel contesto dell’AMIF, dell’ISF e del BMVI: un obiettivo specifico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«priorità» nel contesto del FEAMPA, unicamente ai fini del titolo VII: un «obiettivo specifico»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«organismo intermedio»: un organismo pubblico o privato che agisce sotto la responsabilità di un’autorità di gestione o che svolge compiti o funzioni per conto di questa autorità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«beneficiario»:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un organismo pubblico o privato, un soggetto dotato o non dotato di personalità giuridica o una persona fisica, responsabile dell’avvio o sia dell’avvio che dell’attuazione delle operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel contesto dei partenariati pubblico-privato («PPP») , l’organismo pubblico che ha avviato l’operazione PPP o il partner privato selezionato per attuarla;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel contesto dei regimi di aiuti di Stato, l’impresa che riceve l’aiuto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel contesto degli aiuti «de minimis» forniti a norma dei regolamenti (UE) n. 1407/2013 (\n<span class=\"superscript\">5</span>\n) o (UE) n. 717/2014 (\n<span class=\"superscript\">6</span>\n) della Commissione, lo Stato membro può decidere che il beneficiario ai fini del presente regolamento è l’organismo che concede gli aiuti, se è responsabile dell’avvio o sia dell’avvio che dell’attuazione dell’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel contesto degli strumenti finanziari, l’organismo che attua il fondo di partecipazione o, in assenza di un fondo di partecipazione, l’organismo che attua il fondo specifico o, se l’autorità di gestione gestisce lo strumento finanziario, l’autorità di gestione;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«fondo per piccoli progetti»: l’operazione di un programma Interreg finalizzata a selezionare e attuare progetti, tra cui azioni che prevedono contatti tra persone, di volume finanziario modesto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«target finale»: valore concordato in anticipo da conseguire entro il termine del periodo di ammissibilità in relazione a un indicatore compreso in un obiettivo specifico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«target intermedio»: valore intermedio da conseguire entro una data scadenza temporale durante il periodo di ammissibilità in relazione a un indicatore di output compreso in un obiettivo specifico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>13) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«indicatore di output»: indicatore per misurare i risultati tangibili specifici dell’intervento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>14) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«indicatore di risultato»: indicatore per misurare gli effetti degli interventi finanziati, particolarmente in riferimento ai destinatari diretti, alla popolazione mirata o agli utenti dell’infrastruttura;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>15) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operazione PPP»: operazione attuata tramite un partenariato tra organismi pubblici e settore privato in conformità di un accordo di PPP, finalizzata a fornire servizi pubblici mediante la condivisione del rischio concentrando competenze del settore privato o fonti aggiuntive di capitale o entrambe;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>16) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«strumento finanziario»: una forma di sostegno attuata mediante una struttura per la fornitura di prodotti finanziari ai destinatari finali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>17) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«prodotto finanziario»: investimenti azionari o quasi azionari, prestiti e garanzie, come definiti all’articolo 2 del regolamento finanziario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>18) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«destinatario finale»: persona giuridica o fisica che riceve sostegno dai fondi mediante il beneficiario di un fondo per piccoli progetti o da uno strumento finanziario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>19) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contributo del programma»: sostegno fornito dai fondi e dai cofinanziamenti nazionali, pubblici ed eventualmente privati, ad uno strumento finanziario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>20) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«fondo di partecipazione»: fondo istituito sotto la responsabilità di un’autorità di gestione nell’ambito di uno o più programmi per attuare uno o più fondi specifici;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>21) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«fondo specifico»: fondo mediante il quale un’autorità di gestione o un fondo di partecipazione forniscono prodotti finanziari a destinatari finali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>22) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«organismo che attua uno strumento finanziario»: organismo di diritto pubblico o privato che adempie i compiti di un fondo di partecipazione o di un fondo specifico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>23) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«effetto leva»: l’importo del finanziamento rimborsabile fornito ai destinatari finali diviso per l’importo del contributo dei fondi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>24) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«coefficiente di moltiplicazione»: nel contesto degli strumenti di garanzia, coefficiente – stabilito sulla base di una prudente valutazione ex ante dei rischi rispetto a ciascun prodotto di garanzia da offrire, che esprime il rapporto tra il valore dei nuovi prestiti e investimenti azionari o quasi azionari erogati sottostanti e l’importo del contributo del programma accantonato per contratti di garanzia a copertura di perdite previste e impreviste dovute a tali nuovi prestiti o investimenti azionari o quasi azionari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>25) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«costi di gestione»: costi diretti o indiretti rimborsati dietro presentazione di prove delle spese sostenute per l’attuazione degli strumenti finanziari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>26) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«commissioni di gestione»: prezzo dei servizi resi, determinato nell’accordo di finanziamento tra l’autorità di gestione e l’organismo che attua un fondo di partecipazione o un fondo specifico e, ove applicabile, tra l’organismo che attua un fondo di partecipazione e l’organismo che attua un fondo specifico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>27) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«delocalizzazione»: trasferimento della stessa attività o attività analoga o di una loro parte ai sensi dell’articolo 2, punto 61 <span class=\"italics\">bis</span>, del regolamento (UE) n. 651/2014;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>28) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contributo pubblico»: qualsiasi contributo al finanziamento di operazioni proveniente dal bilancio di un’autorità pubblica nazionale, regionale o locale, o da qualsiasi gruppo europeo di cooperazione territoriale (GECT) istituito a norma del regolamento (CE) n. 1082/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">7</span>\n), dal bilancio dell’Unione messo a disposizione dei fondi, dal bilancio di organismi di diritto pubblico o dal bilancio di associazioni di autorità pubbliche o di organismi di diritto pubblico e che, allo scopo di determinare il tasso di cofinanziamento dei programmi o delle priorità FSE+, può comprendere eventuali risorse finanziarie conferite collettivamente da datori di lavoro e lavoratori;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>29) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«periodo contabile»: il periodo che va dal 1<span class=\"superscript\">o</span> luglio al 30 giugno dell’anno successivo, tranne che per il primo periodo contabile del periodo di programmazione, per il quale si intende il periodo che va dalla data di inizio dell’ammissibilità delle spese al 30 giugno 2022; per il periodo contabile finale, si intende il periodo dal 1<span class=\"superscript\">o</span> luglio 2029 al 30 giugno 2030;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>30) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operatore economico»: qualsiasi persona fisica o giuridica o altra entità che partecipa all’esecuzione dell’intervento dei fondi, ad eccezione di uno Stato membro nell’esercizio delle sue prerogative di autorità pubblica;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>31) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«irregolarità»: qualsiasi violazione del diritto applicabile, derivante da un’azione o un’omissione di un operatore economico, che ha o può avere come conseguenza un pregiudizio al bilancio dell’Unione imputando a tale bilancio una spesa indebita;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>32) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«carenza grave»: carenza nel funzionamento efficace del sistema di gestione e controllo di un programma per la quale risultano necessari miglioramenti sostanziali dei sistemi di gestione e controllo e in base alla quale a un qualsiasi requisito fondamentale tra quelli ai numeri 2, 4, 5, 9, 12, 13 e 15 di cui all’allegato X oppure a due o più degli altri requisiti fondamentali sono attribuite le categorie 3 e 4 di detto allegato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>33) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«irregolarità sistemica»: qualsiasi irregolarità che possa essere di natura ricorrente, con un’elevata probabilità di verificarsi in tipi simili di operazioni, che deriva da una carenza grave, compresa la mancata istituzione di procedure adeguate conformemente al presente regolamento e alle norme specifiche di ciascun fondo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>34) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«errori totali»: la somma degli errori casuali e, se del caso, degli errori sistemici delimitati e degli errori anomali non corretti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>35) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«tasso di errore totale»: gli errori totali divisi per la popolazione sottoposta ad audit;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>36) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«tasso di errore residuo»: gli errori totali meno le rettifiche finanziarie applicate dallo Stato membro al fine di ridurre i rischi individuati dall’autorità di audit, divisi per le spese da dichiarare nei conti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>37) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operazione completata»: un’operazione che è stata materialmente completata o pienamente attuata e per la quale tutti i relativi pagamenti sono stati effettuati dai beneficiari e il relativo contributo pubblico è stato versato ai beneficiari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>38) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«unità di campionamento»: una delle unità, che può essere rappresentata da un’operazione, un progetto nel contesto di un’operazione o una domanda di pagamento di un beneficiario, nelle quali una popolazione sottoposta ad audit viene suddivisa ai fini del campionamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>39) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«conto di garanzia»: nel caso di un’operazione PPP, un conto bancario oggetto di un accordo scritto tra un organismo pubblico beneficiario e il partner privato approvato dall’autorità di gestione o da un organismo intermedio utilizzato per i pagamenti durante o dopo il periodo di ammissibilità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>40) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«partecipante»: persona fisica che trae direttamente beneficio da un’operazione senza essere responsabile dell’avvio, o sia dell’avvio che dell’attuazione, dell’operazione e che, nel contesto del FEAMPA, non riceve sostegno finanziario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>41) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«efficienza energetica al primo posto»: tenere nella massima considerazione, nella pianificazione energetica e nelle decisioni strategiche e di investimento, misure alternative di efficienza energetica efficienti in termini di costi per ottimizzare la domanda e l’offerta di energia, in particolare mediante risparmi energetici nell’uso finale efficaci sotto il profilo dei costi, iniziative di gestione della domanda e una conversione, trasmissione e distribuzione più efficienti dell’energia, pur continuando a conseguire gli obiettivi di tali decisioni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>42) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«immunizzazione dagli effetti del clima»: un processo volto a evitare che le infrastrutture siano vulnerabili ai potenziali impatti climatici a lungo termine, garantendo nel contempo che sia rispettato il principio dell’efficienza energetica al primo posto e che il livello delle emissioni di gas a effetto serra derivanti dal progetto sia coerente con l’obiettivo della neutralità climatica per il 2050;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>43) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sovvenzioni soggette a condizioni»: una categoria di sovvenzione soggetta a condizioni collegate al rimborso del sostegno;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>44) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«BEI»: la Banca europea per gli investimenti, il Fondo europeo per gli investimenti o una società controllata della Banca europea per gli investimenti;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>45) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«marchio di eccellenza»: il marchio di qualità della Commissione riguardo a una proposta, indicante che una proposta che è stata valutata nel quadro di un invito a presentare proposte nell'ambito di uno strumento dell'Unione e che è ritenuta conforme ai requisiti minimi di qualità di tale strumento dell'Unione, ma che non ha potuto essere finanziata a causa della dotazione di bilancio insufficiente per tale invito a presentare proposte, può beneficiare del sostegno a titolo di altre fonti di finanziamento dell'Unione o nazionali; o il «marchio di sovranità» di cui all'articolo 4 del regolamento (UE) 2024/795 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">8</span>\n).</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "Computo dei termini per le azioni della Commissione", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">Se è stabilito un termine per le azioni della Commissione, tale termine ha inizio una volta che lo Stato membro ha presentato tutte le informazioni in conformità delle prescrizioni del presente regolamento o dei regolamenti specifici relativi ai fondi interessati.</p>"], [null, "<p class=\"norm\">Tale termine è sospeso dal giorno successivo alla data in cui la Commissione trasmette a uno Stato membro le sue osservazioni o una richiesta di documenti riveduti e fino a quando lo Stato membro non risponde alla Commissione.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Trattamento e protezione dei dati personali", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Gli Stati membri e la Commissione sono autorizzati a trattare i dati personali solo se necessario al fine di adempiere i rispettivi obblighi a norma del presente regolamento, in particolare per quanto riguarda la sorveglianza, la rendicontazione, la comunicazione, la pubblicazione, la valutazione, la gestione finanziaria, le verifiche e gli audit e, se del caso, per determinare l’idoneità dei partecipanti. I dati personali sono trattati in conformità del regolamento (UE) 2016/679 o del regolamento (UE) 2018/1725 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">9</span>\n), a seconda dei casi.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Obiettivi strategici", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il FESR, il FSE+, il Fondo di coesione e il FEAMPA sostengono gli obiettivi strategici seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’Europa più competitiva e intelligente attraverso la promozione di una trasformazione economica innovativa e intelligente e della connettività regionale alle tecnologie dell’informazione e della comunicazione (TIC);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’Europa resiliente, più verde e a basse emissioni di carbonio ma in transizione verso un’economia a zero emissioni nette di carbonio attraverso la promozione di una transizione verso un’energia pulita ed equa, di investimenti verdi e blu, dell’economia circolare, dell’adattamento ai cambiamenti climatici e della loro mitigazione, della gestione e prevenzione dei rischi nonché della mobilità urbana sostenibile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’Europa più connessa attraverso il rafforzamento della mobilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’Europa più sociale e inclusiva attraverso l’attuazione del pilastro europeo dei diritti sociali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’Europa più vicina ai cittadini attraverso la promozione dello sviluppo sostenibile e integrato di tutti i tipi di territorio e delle iniziative locali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il JTF sostiene l’obiettivo specifico di consentire alle regioni e alle persone di affrontare gli effetti sociali, occupazionali, economici e ambientali della transizione verso gli obiettivi 2030 dell’Unione per l’energia e il clima e un’economia dell’Unione climaticamente neutra entro il 2050, sulla base dell’accordo di Parigi.</p>"], [null, "<p class=\"norm\">Il paragrafo 1, primo comma, del presente articolo, non si applica alle risorse del FESR e del FSE+ che sono trasferite al JTF in conformità dell’articolo 27.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il FESR, il FSE+, il Fondo di coesione e il JTF contribuiscono alle azioni dell’Unione intese a rafforzare la sua coesione economica, sociale e territoriale in conformità dell’articolo 174 TFUE perseguendo gli obiettivi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’obiettivo «Investimenti a favore dell’occupazione e della crescita» negli Stati membri e nelle regioni, con il sostegno del FESR, del FSE+, del Fondo di coesione e del JTF; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’obiettivo «Cooperazione territoriale europea» (Interreg), con il sostegno del FESR.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione promuovono il coordinamento, la complementarità e la coerenza tra i fondi e altri strumenti e fondi dell’Unione. Essi ottimizzano i meccanismi per il coordinamento dei responsabili al fine di evitare duplicazioni durante la programmazione e l’attuazione. Conseguentemente, gli Stati membri e la Commissione tengono conto altresì delle pertinenti raccomandazioni specifiche per paese nella programmazione e nell’attuazione dei fondi.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Obiettivi climatici e meccanismo di adeguamento in materia di clima", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri forniscono informazioni sul sostegno agli obiettivi riguardanti l’ambiente e il clima applicando una metodologia basata sulle tipologie di intervento per ciascuno dei fondi. Tale metodologia consiste nell’assegnare una ponderazione specifica al sostegno fornito a un livello che riflette in quale misura il sostegno apporta un contributo agli obiettivi riguardanti l’ambiente e il clima. Per quanto riguarda il FESR, il FSE+ e il Fondo di coesione, si attribuiscono ponderazioni alle dimensioni e ai codici delle tipologie di intervento stabiliti nell’allegato I. Il FESR e il Fondo di coesione contribuiscono rispettivamente al 30 % e al 37 % del contributo dell’Unione alle spese sostenute per il conseguimento degli obiettivi climatici fissati per il bilancio dell’Unione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<p class=\"norm\">Qualora, a seguito della modifica di un programma nel quadro della piattaforma per le tecnologie strategiche per l'Europa (STEP), istituita dal regolamento (UE) 2024/795, il contributo del Fondo di coesione all'azione per il clima superi l'obiettivo del 37 % della sua dotazione totale, l'importo che supera tale obiettivo può essere preso in considerazione nel calcolo del contributo del FESR all'azione per il clima al fine di raggiungere l'obiettivo del 30 % della sua dotazione totale. Gli importi che superano l'obiettivo volto a destinare il 30 % della dotazione totale del FESR all'azione per il clima possono essere presi in considerazione nel calcolo del contributo del Fondo di coesione all'azione per il clima.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’obiettivo relativo al contributo all’azione per il clima a livello di ciascuno Stato membro è stabilito come percentuale della dotazione complessiva nazionale a titolo del FESR e del Fondo di coesione e incluso nei programmi a seguito delle tipologie di intervento e della ripartizione finanziaria indicativa di cui all’articolo 22, paragrafo 3, lettera d), punto viii). Come previsto all’articolo 11, paragrafo 1, l’obiettivo preliminare relativo al contributo all’azione per il clima è stabilito nell’accordo di partenariato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro e la Commissione sorvegliano periodicamente il rispetto degli obiettivi relativi al contributo all’azione per il clima, sulla base delle spese totali ammissibili dichiarate dai beneficiari all’autorità di gestione, ripartite per tipologia di intervento in conformità dell’articolo 42, e sulla base dei dati presentati dallo Stato membro. Qualora a seguito della sorveglianza emergano progressi insufficienti verso il conseguimento dell’obiettivo relativo al contributo all’azione per il clima, lo Stato membro e la Commissione concordano misure correttive nella riunione annuale di riesame.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora non vi siano progressi sufficienti verso il conseguimento dell’obiettivo relativo al contributo all’azione per il clima a livello nazionale entro il 31 dicembre 2024, lo Stato membro ne tiene conto nell’ambito del proprio riesame intermedio a norma dell’articolo 18, paragrafo 1.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Gestione concorrente", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione eseguono la parte del bilancio dell’Unione assegnata ai fondi in regime di gestione concorrente in conformità dell’articolo 63 del regolamento finanziario. Gli Stati membri preparano e attuano i programmi al livello territoriale appropriato, conformemente al proprio quadro istituzionale, giuridico e finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione esegue l’importo del sostegno del Fondo di coesione trasferito al meccanismo per collegare l’Europa («MCE»), dell’Iniziativa urbana europea, degli investimenti in materia di innovazione interregionale, l’importo del sostegno del FSE+ trasferito alla cooperazione transnazionale, gli importi dei contributi al programma InvestEU e l’assistenza tecnica su iniziativa della Commissione in regime di gestione diretta o indiretta in conformità dell’articolo 62, paragrafo 1, primo comma, lettere a) e c), del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Con l’accordo dello Stato membro e delle regioni interessate, la Commissione può attuare la cooperazione per le regioni ultraperiferiche nell’ambito dell’obiettivo «Cooperazione territoriale europea» (Interreg) in regime di gestione indiretta.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Partenariato e governance a più livelli", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per l’accordo di partenariato e per ogni programma ciascuno Stato membro organizza e attua un partenariato globale conformemente al proprio quadro istituzionale e giuridico, tenendo conto delle specificità dei fondi. Tale partenariato include almeno i partner seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le autorità a livello regionale, locale, cittadino e altre autorità pubbliche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le parti economiche e sociali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli organismi pertinenti che rappresentano la società civile, quali i partner ambientali, le organizzazioni non governative e gli organismi incaricati di promuove l’inclusione sociale, i diritti fondamentali, i diritti delle persone con disabilità, la parità di genere e la non discriminazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le organizzazioni di ricerca e le università, se del caso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il partenariato istituito ai sensi del paragrafo 1 del presente articolo opera in conformità del principio della governance a più livelli e seguendo un approccio dal basso verso l’alto. Lo Stato membro coinvolge i partner di cui al paragrafo 1 nella preparazione degli accordi di partenariato e in tutte le fasi della preparazione, dell’attuazione e della valutazione dei programmi, anche attraverso la partecipazione a comitati di sorveglianza ai sensi dell’articolo 39.</div>\n</div>"], [null, "<p class=\"norm\">In tale contesto, se del caso, gli Stati membri assegnano una percentuale adeguata delle risorse provenienti dai fondi allo sviluppo della capacità amministrativa delle parti sociali e delle organizzazioni della società civile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per i programmi Interreg il partenariato comprende partner provenienti da tutti gli Stati membri partecipanti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’organizzazione e l’attuazione dei partenariati sono effettuate conformemente al codice di condotta europeo in materia di partenariato istituito dal regolamento delegato (UE) n. 240/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Almeno una volta l’anno la Commissione consulta le organizzazioni che rappresentano i partner a livello dell’Unione in merito all’attuazione dei programmi e riferisce al Parlamento europeo e al Consiglio in merito ai risultati.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Principi orizzontali", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In sede di attuazione dei fondi, gli Stati membri e la Commissione garantiscono il rispetto dei diritti fondamentali e la conformità alla Carta dei diritti fondamentali dell’Unione europea.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione provvedono affinché la parità tra uomini e donne, l’integrazione di genere e l’integrazione della prospettiva di genere siano prese in considerazione e promosse in tutte le fasi della preparazione, dell’attuazione, della sorveglianza, della rendicontazione e della valutazione dei programmi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione adottano le misure necessarie per prevenire qualsiasi discriminazione fondata su genere, origine razziale o etnica, religione o convinzioni personali, disabilità, età o orientamento sessuale durante le fasi di preparazione, attuazione, sorveglianza, rendicontazione e valutazione dei programmi. In particolare, in tutte le fasi della preparazione e dell’attuazione dei programmi si tiene conto dell’accessibilità per le persone con disabilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli obiettivi dei fondi sono perseguiti in linea con l’obiettivo di promuovere lo sviluppo sostenibile di cui all’articolo 11 TFUE, tenendo conto degli obiettivi di sviluppo sostenibile delle Nazioni Unite, dell’accordo di Parigi e del principio «non arrecare un danno significativo».</div>\n</div>"], [null, "<p class=\"norm\">Gli obiettivi dei fondi sono perseguiti nel pieno rispetto dell’<span class=\"italics\">acquis</span> ambientale dell’Unione.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Preparazione e presentazione dell’accordo di partenariato", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro prepara un accordo di partenariato che espone l’orientamento strategico per la programmazione e le modalità per un impiego efficace ed efficiente del FESR, del FSE+, del Fondo di coesione, del JTF e del FEAMPA per il periodo compreso fra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accordo di partenariato è redatto in conformità del codice di condotta europeo in materia di partenariato. Se uno Stato membro prevede un partenariato globale già nel corso della preparazione dei suoi programmi, tale requisito si considera rispettato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro presenta l’accordo di partenariato alla Commissione prima della presentazione del primo programma o contestualmente alla stessa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’accordo di partenariato può essere presentato unitamente al pertinente programma nazionale di riforma annuale e al piano nazionale integrato per l’energia e il clima.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’accordo di partenariato è un documento strategico e conciso. Non supera le 35 pagine a meno che lo Stato membro, di propria iniziativa, non decida di estendere la lunghezza del documento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro redige l’accordo di partenariato in conformità del modello riportato nell’allegato II. Lo Stato membro può inserire l’accordo di partenariato in uno dei suoi programmi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I programmi Interreg possono essere presentati alla Commissione prima della presentazione dell’accordo di partenariato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Su richiesta dello Stato membro interessato, la BEI può partecipare alla preparazione dell’accordo di partenariato, nonché ad attività connesse alla preparazione delle operazioni, degli strumenti finanziari e dei PPP.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Contenuto dell’accordo di partenariato", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’accordo di partenariato contiene gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi strategici selezionati e l’obiettivo specifico del JTF, comprensivi dell’indicazione di quali fondi oggetto dell’accordo di partenariato e programmi perseguiranno tali obiettivi strategici e della relativa giustificazione, tenendo presenti le pertinenti raccomandazioni specifiche per paese, il piano nazionale integrato per l’energia e il clima, i principi del pilastro europeo dei diritti sociali e, se del caso, le sfide regionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ciascuno degli obiettivi strategici selezionati e per l’obiettivo specifico del JTF:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una sintesi delle scelte strategiche e dei principali risultati attesi per ciascuno dei fondi oggetto dell’accordo di partenariato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il coordinamento, la delimitazione e la complementarità tra i fondi e, se del caso, il coordinamento tra i programmi nazionali e regionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le complementarità e le sinergie tra i fondi oggetto dell’accordo di partenariato, l’AMIF, l’ISF, il BMVI e altri strumenti dell’Unione, compresi i progetti strategici integrati e i progetti strategici per la natura del programma LIFE e, se del caso, i progetti finanziati nell’ambito di Orizzonte Europa;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la dotazione finanziaria preliminare a carico di ciascuno dei fondi oggetto dell’accordo di partenariato suddivisa per obiettivo strategico a livello nazionale e, se del caso, regionale, rispettando le norme specifiche di ciascun fondo sulla concentrazione tematica e la dotazione finanziaria preliminare per l’obiettivo specifico del JTF, comprese eventuali risorse del FESR e del FSE+ da trasferire al JTF in conformità dell’articolo 27;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’obiettivo preliminare relativo al contributo all’azione per il clima in conformità dell’articolo 6, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se applicabile, la ripartizione delle risorse finanziarie per categoria di regioni, redatta in conformità dell’articolo 108, paragrafo 2, e gli importi delle dotazioni di cui si propone il trasferimento a norma degli articoli 26 e 111, compresa una giustificazione di tali trasferimenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per l’assistenza tecnica, la scelta dello Stato membro in relazione alla forma di contributo dell’Unione conformemente all’articolo 36, paragrafo 3, e, se del caso, la dotazione finanziaria preliminare a carico di ciascuno dei fondi oggetto dell’accordo di partenariato a livello nazionale e la ripartizione delle risorse finanziarie per programma e per categoria di regioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi dеi contributi da versare al programma InvestEU suddivisi per fondo e per categoria di regione, se applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elenco dei programmi previsti nell’ambito dei fondi oggetto dell’accordo di partenariato con le rispettive dotazioni finanziarie preliminari suddivise per fondo e il corrispondente contributo nazionale per categoria di regione, se applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una sintesi delle azioni che lo Stato membro interessato prevede di adottare per rafforzare la propria capacità amministrativa di attuazione dei fondi oggetto dell’accordo di partenariato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, un approccio integrato volto ad affrontare le sfide demografiche o le esigenze specifiche delle regioni e delle aree.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda l’obiettivo «Cooperazione territoriale europea» (Interreg), l’accordo di partenariato contiene solo l’elenco dei programmi previsti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accordo di partenariato può inoltre contenere una sintesi della valutazione del soddisfacimento delle pertinenti condizioni abilitanti di cui all’articolo 15 e agli allegati III e IV.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Approvazione dell’accordo di partenariato", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione valuta l’accordo di partenariato e la sua conformità al presente regolamento e alle norme specifiche dei fondi nel rispetto del principio di proporzionalità, tenendo conto della natura strategica del documento, del numero di programmi interessati e dell’importo totale delle risorse destinate allo Stato membro interessato. Nella valutazione la Commissione tiene conto in particolare del modo in cui lo Stato membro intende dar seguito alle pertinenti raccomandazioni specifiche per paese, al suo piano nazionale integrato per l’energia e il clima e al pilastro europeo dei diritti sociali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può formulare osservazioni entro tre mesi dalla data di presentazione dell’accordo di partenariato da parte dello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro rivede l’accordo di partenariato tenendo conto delle osservazioni formulate dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante un atto di esecuzione, una decisione che approva l’accordo di partenariato entro quattro mesi dalla data della prima presentazione dell’accordo di partenariato da parte dello Stato membro interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se, conformemente all’articolo 10, paragrafo 6, l’accordo di partenariato è inserito in un programma, entro sei mesi dalla data di presentazione del programma da parte dello Stato membro interessato la Commissione adotta, mediante un atto di esecuzione, un’unica decisione in cui si approvano sia l’accordo di partenariato che il programma.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Modifica dell’accordo di partenariato", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può presentare alla Commissione, entro il 31 marzo 2025, un accordo di partenariato modificato che tenga conto dei risultati del riesame intermedio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione valuta la modifica e può formulare osservazioni entro tre mesi dalla presentazione dell’accordo di partenariato modificato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro rivede l’accordo di partenariato modificato tenendo conto delle osservazioni formulate dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione approva la modifica di un accordo di partenariato non oltre sei mesi dalla sua prima presentazione da parte dello Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatta salva la possibilità di cui al paragrafo 1 del presente articolo di modificare l'accordo di partenariato entro il 31 marzo 2025, uno Stato membro può presentare alla Commissione un accordo di partenariato modificato per tenere conto dell'introduzione nei programmi di priorità che contribuiscono agli obiettivi STEP di cui all'articolo 2 del regolamento (UE) 2024/795.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In deroga ai paragrafi 2 e 4 del presente articolo, la Commissione approva l'accordo di partenariato modificato di cui al paragrafo 5 entro tre mesi dalla sua prima presentazione da parte dello Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "14": {"label": "Articolo 14", "heading": "Uso del FESR, del FSE+, del Fondo di coesione e del FEAMPA attuati tramite il programma InvestEU", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nell’accordo di partenariato gli Stati membri possono assegnare un importo che va fino al 2 % della dotazione nazionale iniziale rispettivamente per il FESR, il FSE+, il Fondo di coesione e il FEAMPA, che deve essere versato a titolo di contributo al programma InvestEU e attuato tramite la garanzia dell’UE e il polo di consulenza InvestEU in conformità dell’articolo 10 del regolamento InvestEU. Con l’accordo dell’autorità di gestione interessata, gli Stati membri possono assegnare un ulteriore importo che va fino al 3 % della dotazione nazionale iniziale di ciascuno di tali fondi dopo il 1<span class=\"superscript\">o</span> gennaio 2023 mediante una o più richieste di modifica del programma.</div>\n</div>"], [null, "<p class=\"norm\">Detti importi contribuiscono al conseguimento degli obiettivi strategici selezionati nell’accordo di partenariato o nel programma e sostengono gli investimenti essenzialmente nella categoria delle regioni contribuenti.</p>"], [null, "<p class=\"norm\">Tali contributi sono attuati in conformità delle norme stabilite nel regolamento InvestEU e non costituiscono trasferimenti di risorse ai sensi dell’articolo 26.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri stabiliscono l’importo totale versato a titolo di contributo per ogni anno, suddiviso per fondo e per categoria di regione, se applicabile. Per l’accordo di partenariato possono essere assegnate risorse inerenti all’anno civile in corso e a quelli futuri. Se uno Stato membro richiede una modifica di un programma possono essere assegnate solo risorse di anni civili futuri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli importi di cui al paragrafo 1 del presente articolo sono impiegati per creare la dotazione della parte della garanzia dell’UE che si riferisce al comparto dello Stato membro e per il polo di consulenza InvestEU, una volta concluso l’accordo di contributo in conformità dell’articolo 10, paragrafo 3, del regolamento InvestEU. Gli impegni di bilancio dell’Unione per ciascun accordo di contributo possono essere assunti dalla Commissione in frazioni annue nel periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 12 del regolamento finanziario, se entro i quattro mesi successivi alla data della decisione della Commissione che adotta l’accordo di partenariato non è stato concluso un accordo di contributo in conformità dell’articolo 10, paragrafo 2, del regolamento InvestEU per l’importo di cui al paragrafo 1 del presente articolo assegnato nell’accordo di partenariato, l’importo corrispondente è assegnato a uno o più programmi nell’ambito del fondo contribuente o della categoria di regioni, se del caso su richiesta dello Stato membro.</div>\n</div>"], [null, "<p class=\"norm\">L’accordo di contributo per gli importi di cui al paragrafo 1, assegnato nella richiesta di modifica del programma, è concluso simultaneamente all’adozione della decisione di modifica del programma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<span>\n<span class=\"boldface\">►M4</span>\n</span> In conformità dell'articolo 10, paragrafo 4, secondo comma, del regolamento (UE) 2021/523, se entro 12 mesi dalla conclusione dell'accordo di contributo non è stato concluso un accordo di garanzia, l'accordo di contributo è risolto o prorogato di comune accordo.<span class=\"boldface\"> ◄ </span>\n</div>\n</div>"], [null, "<p class=\"norm\">Laddove la partecipazione di uno Stato membro al Fondo InvestEU sia interrotta, gli importi in questione versati nel fondo comune di copertura a titolo di copertura sono recuperati sotto forma di entrate con destinazione specifica interne ai sensi dell’articolo 21, paragrafo 5, del regolamento finanziario. Lo Stato membro interessato presenta una richiesta relativa a una o più modifiche del programma per utilizzare gli importi recuperati e gli importi assegnati agli anni civili futuri in conformità del paragrafo 2 del presente articolo. La risoluzione o la modifica dell’accordo di contributo è conclusa contestualmente all’adozione delle decisioni che modificano il programma o i programmi in questione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se entro quattro anni dalla sua conclusione, un accordo di garanzia, in conformità dell’articolo 10, paragrafo 4, terzo comma, del regolamento InvestEU, non è stato attuato completamente, l’accordo di contributo è modificato. Lo Stato membro può chiedere che gli importi versati a titolo di contributo alla garanzia dell’UE ai sensi del paragrafo 1 del presente articolo e impegnati nell’accordo di garanzia, ma non riservati a copertura di prestiti, investimenti azionari o altri strumenti di rischio sottostanti siano trattati come indicato nel paragrafo 5 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le risorse generate dagli importi dei contributi alla garanzia dell’UE o ad essi imputabili sono messe a disposizione dello Stato membro in conformità dell’articolo 10, paragrafo 5, lettera a), del regolamento InvestEU e impiegate a fini di sostegno a titolo dello stesso obiettivo od obiettivi sotto forma di strumenti finanziari o garanzie di bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Per gli importi da riutilizzare in un programma in conformità dei paragrafi 4, 5 e 6 del presente articolo, il termine per il disimpegno definito all’articolo 105, paragrafo 1, decorre dall’anno in cui vengono assunti i corrispettivi impegni di bilancio.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Condizioni abilitanti", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento stabilisce le condizioni abilitanti degli obiettivi specifici.</div>\n</div>"], [null, "<p class=\"norm\">L’allegato III contiene le condizioni abilitanti orizzontali applicabili a tutti gli obiettivi specifici e i criteri necessari per valutarne il soddisfacimento.</p>"], [null, "<p class=\"norm\">L’allegato IV contiene le condizioni abilitanti tematiche applicabili al FESR, al FSE+ e al Fondo di coesione e i criteri necessari per valutare se sono soddisfatte.</p>"], [null, "<p class=\"norm\">La condizione abilitante concernente gli strumenti e la capacità per un’efficace applicazione delle norme in materia di aiuti di Stato non è applicabile ai programmi sostenuti dall’AMIF, dall’ISF o dal BMVI.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In fase di elaborazione di un programma o di introduzione di un nuovo obiettivo specifico nel contesto della modifica di un programma, lo Stato membro valuta se sono soddisfatte le condizioni abilitanti collegate all’obiettivo specifico selezionato. Una condizione abilitante è soddisfatta se sono soddisfatti tutti i criteri correlati. Lo Stato membro individua in ciascun programma o nella modifica di un programma le condizioni abilitanti soddisfatte e quelle non soddisfatte e indica la relativa giustificazione, se ritiene soddisfatta una condizione abilitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se una condizione abilitante non è soddisfatta al momento dell’approvazione del programma o della modifica del programma, lo Stato membro informa la Commissione appena ritiene soddisfatta tale condizione indicandone la giustificazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non appena possibile e non oltre tre mesi dal ricevimento delle informazioni di cui al paragrafo 3, la Commissione effettua una valutazione e informa lo Stato membro se concorda con lo Stato membro circa il soddisfacimento della condizione abilitante.</div>\n</div>"], [null, "<p class=\"norm\">Se la Commissione non concorda con lo Stato membro circa il soddisfacimento della condizione abilitante, ne informa lo Stato membro indicando la propria valutazione.</p>"], [null, "<p class=\"norm\">Se lo Stato membro non condivide la valutazione della Commissione, presenta le sue osservazioni entro 1 mese e la Commissione procede in conformità del primo comma.</p>"], [null, "<p class=\"norm\">Se lo Stato membro accetta la valutazione della Commissione, procede in conformità del paragrafo 3.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 105, le spese relative a operazioni collegate all’obiettivo specifico possono essere inserite nelle domande di pagamento, ma la Commissione non le rimborsa fino a quando non ha informato lo Stato membro del soddisfacimento della condizione abilitante a norma del paragrafo 4, primo comma, del presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">Il primo comma non si applica alle operazioni che contribuiscono al soddisfacimento della corrispondente condizione abilitante.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro garantisce che le condizioni abilitanti continuino a essere soddisfatte e rispettate durante l’intero periodo di programmazione. Esso informa la Commissione in merito a qualsiasi modifica che incida sul soddisfacimento delle condizioni abilitanti.</div>\n</div>"], [null, "<p class=\"norm\">Se la Commissione ritiene che una condizione abilitante non sia più soddisfatta, ne informa lo Stato membro indicando la propria valutazione. In seguito si applica la procedura di cui al paragrafo 4, secondo e terzo comma.</p>"], [null, "<p class=\"norm\">Se la Commissione giunge alla conclusione che la condizione abilitante sia ancora insoddisfatta, fatto salvo l’articolo 105 e sulla base delle osservazioni dello Stato membro, le spese relative all’obiettivo specifico interessato possono essere inserite nelle domande di pagamento, ma la Commissione non le rimborsa fino a quando non ha informato lo Stato membro del soddisfacimento della condizione abilitante a norma del paragrafo 4, primo comma, del presente articolo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’allegato IV non si applica alle priorità sostenute dal JTF o a qualsiasi delle risorse del FESR e del FSE+ trasferite al JTF in conformità dell’articolo 27.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Quadro di riferimento dell’efficacia dell’attuazione", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro istituisce un quadro di riferimento dell’efficacia dell’attuazione che prevede la sorveglianza, la rendicontazione e la valutazione della performance di un programma durante la sua attuazione e contribuisce a misurare la performance generale dei fondi.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il quadro di riferimento dell’efficacia dell’attuazione consta di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indicatori di output e di risultato collegati a obiettivi specifici stabiliti nei regolamenti specifici relativi ai fondi selezionati per il programma;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">target intermedi da conseguire entro la fine dell’anno 2024 per gli indicatori di output; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">target finali da conseguire entro la fine dell’anno 2029 per gli indicatori di output e di risultato.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I target intermedi e i target finali sono stabiliti in relazione a ciascun obiettivo specifico nell’ambito di un programma, eccettuati l’assistenza tecnica e l’obiettivo specifico volto a contrastare la deprivazione materiale di cui all’articolo 4, paragrafo 1, lettera m)<span class=\"italics\">,</span> del regolamento FSE+.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I target intermedi e i target finali permettono alla Commissione e agli Stati membri di misurare i progressi compiuti verso il conseguimento degli obiettivi specifici. Essi rispondono alle prescrizioni dell’articolo 33, paragrafo 3, del regolamento finanziario.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Metodologia per istituire il quadro di riferimento dell’efficacia dell’attuazione", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La metodologia per istituire il quadro di riferimento dell’efficacia dell’attuazione comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri applicati dagli Stati membri per selezionare gli indicatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati o gli elementi di prova utilizzati, il sistema di garanzia di qualità dei dati e il metodo di calcolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fattori che possono influire sul conseguimento dei target intermedi e dei target finali e come sono stati tenuti presenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Su richiesta, lo Stato membro mette a disposizione della Commissione la metodologia per istituire il quadro di riferimento dell’efficacia.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Riesame intermedio e importo di flessibilità", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione e dal JTF, lo Stato membro rivede ciascun programma tenendo presenti gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le nuove sfide individuate nelle pertinenti raccomandazioni specifiche per paese adottate nel 2024;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’attuazione del piano nazionale integrato per l’energia e il clima, se del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’attuazione dei principi del pilastro europeo dei diritti sociali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la situazione socioeconomica dello Stato membro interessato o della regione interessata, con particolare riguardo alle esigenze territoriali e tenendo conto di eventuali sviluppi negativi di grande rilievo sul piano finanziario, economico o sociale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i principali risultati delle valutazioni pertinenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti verso il conseguimento dei target intermedi, tenendo conto delle considerevoli difficoltà riscontrate nell’attuazione del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi sostenuti dal JTF, la valutazione effettuata dalla Commissione a norma dell’articolo 29, paragrafo 1, lettera b), del regolamento (UE) 2018/1999.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 31 marzo 2025 lo Stato membro presenta alla Commissione, per ciascun programma, una valutazione relativa ai risultati del riesame intermedio, compresa una proposta riguardante l’assegnazione definitiva dell’importo di flessibilità di cui all’articolo 86, paragrafo 1, secondo comma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se ritenuto necessario in seguito al riesame intermedio del programma, o nel caso in cui siano state individuate nuove sfide in conformità del paragrafo 1, lettera a), lo Stato membro presenta alla Commissione la valutazione di cui al paragrafo 2 unitamente al programma modificato.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Le revisioni comprendono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le dotazioni di risorse finanziarie per priorità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i target finali riveduti o nuovi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi dei contributi da versare al programma InvestEU suddivisi per fondo e categoria di regioni, se applicabile.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione approva il programma riveduto conformemente all’articolo 24, compresa l’assegnazione definitiva dell’importo di flessibilità.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se, in seguito al riesame intermedio, lo Stato membro ritiene che il programma non debba essere modificato, la Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, entro tre mesi dalla presentazione della valutazione di cui al paragrafo 2, una decisione in cui conferma l’assegnazione definitiva dell’importo di flessibilità; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">chiede allo Stato membro, entro due mesi dalla presentazione della valutazione di cui al paragrafo 2 del presente articolo, di presentare un programma modificato in conformità dell’articolo 24.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fino all’adozione della decisione della Commissione in cui si conferma l’assegnazione definitiva dell’importo di flessibilità, tale importo non è disponibile per la selezione delle operazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Entro la fine del 2026 la Commissione elabora una relazione sui risultati del riesame intermedio e la trasmette al Parlamento europeo e al Consiglio.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Misure per collegare l’efficacia dei fondi a una sana governance economica", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione può chiedere a uno Stato membro di rivedere i programmi pertinenti e proporre modifiche degli stessi, qualora ciò sia necessario a sostegno dell’attuazione delle pertinenti raccomandazioni del Consiglio.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Tale richiesta può essere presentata per le finalità seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’attuazione di una pertinente raccomandazione specifica per paese adottata a norma dell’articolo 121, paragrafo 2, TFUE e di una pertinente raccomandazione del Consiglio adottata a norma dell’articolo 148, paragrafo 4, TFUE e destinata allo Stato membro interessato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’attuazione di pertinenti raccomandazioni del Consiglio destinate allo Stato membro interessato e adottate a norma dell’articolo 7, paragrafo 2, o dell’articolo 8, paragrafo 2, del regolamento (UE) n. 1176/2011 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">10</span>\n), purché tali modifiche siano ritenute necessarie per contribuire a correggere gli squilibri macroeconomici.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Una richiesta della Commissione a uno Stato membro a norma del paragrafo 1 è motivata in riferimento all’esigenza di sostenere l’attuazione delle pertinenti raccomandazioni e indica i programmi o le priorità che essa ritiene interessati e la natura delle modifiche previste. Tale richiesta è formulata non prima del 2023 o dopo il 2026 e non riguarda gli stessi programmi in due anni consecutivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro trasmette la propria risposta alla richiesta di cui al paragrafo 1 entro due mesi dal ricevimento, esponendo le modifiche che considera necessarie nei programmi pertinenti, i motivi delle modifiche, indicando i programmi interessati e la natura delle modifiche proposte e gli effetti previsti sull’attuazione delle raccomandazioni e sull’attuazione dei fondi. Se necessario, la Commissione formula osservazioni entro 1 mese dal ricevimento di tale risposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo Stato membro presenta una proposta di modifica dei programmi pertinenti entro due mesi dalla data di presentazione della risposta di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se la Commissione non ha presentato osservazioni o se essa ritiene che le osservazioni formulate siano state debitamente recepite, adotta una decisione di approvazione delle modifiche ai pertinenti programmi entro quattro mesi dopo la sua presentazione agli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro omette di adottare un’azione efficace in risposta a una richiesta formulata a norma del paragrafo 1 entro i termini di cui ai paragrafi 3 e 4, la Commissione può, entro tre mesi dalla presentazione delle sue osservazioni ai sensi del paragrafo 3 o successivamente alla presentazione della proposta dello Stato membro di cui al paragrafo 4, proporre al Consiglio di sospendere parzialmente o totalmente i pagamenti relativi ai programmi o alle priorità in questione. Nella sua proposta la Commissione indica i motivi per cui è giunta alla conclusione che lo Stato membro ha omesso di adottare un’azione efficace. Nel formulare la sua proposta la Commissione tiene conto di tutte le informazioni pertinenti e prende in debita considerazione ogni elemento emerso o parere espresso nell’ambito del dialogo strutturato di cui al paragrafo 14.</div>\n</div>"], [null, "<p class=\"norm\">Il Consiglio decide in merito a tale proposta mediante un atto di esecuzione. Tale atto di esecuzione si applica soltanto alle domande di pagamento presentate successivamente alla data della sua adozione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione presenta al Consiglio una proposta di sospendere totalmente o parzialmente i pagamenti relativi a uno o più programmi di uno Stato membro qualora il Consiglio decida a norma dell’articolo 126, paragrafo 8, o dell’articolo 126, paragrafo 11, TFUE che lo Stato membro interessato non ha adottato azioni efficaci per correggere il suo disavanzo eccessivo, a meno che non abbia constatato l’esistenza di una grave recessione economica nella zona euro o nell’intera Unione ai sensi dell’articolo 3, paragrafo 5, e dell’articolo 5, paragrafo 2, del regolamento (CE) n. 1467/97 del Consiglio (\n<span class=\"superscript\">11</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può presentare al Consiglio una proposta di sospendere totalmente o parzialmente i pagamenti relativi a uno o più programmi di uno Stato membro nei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il Consiglio adotta due raccomandazioni successive nella stessa procedura per gli squilibri eccessivi, a norma dell’articolo 8, paragrafo 3, del regolamento (UE) n. 1176/2011 del Parlamento europeo e del Consiglio, motivate dal fatto che uno Stato membro ha presentato un piano d’azione correttivo insufficiente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il Consiglio adotta due decisioni successive nella stessa procedura per gli squilibri eccessivi, a norma dell’articolo 10, paragrafo 4, del regolamento (UE) n. 1176/2011, con cui accerta l’inadempimento dello Stato membro per non aver adottato l’azione correttiva raccomandata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la Commissione conclude che lo Stato membro non ha adottato misure di cui al regolamento (CE) n. 332/2002 del Consiglio (\n<span class=\"superscript\">12</span>\n) e, di conseguenza, decide di non autorizzare l’erogazione del sostegno finanziario concesso a tale Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il Consiglio decide che uno Stato membro non adempie al programma di aggiustamento macroeconomico di cui all’articolo 7 del regolamento (UE) n. 472/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">13</span>\n) o alle misure richieste da una decisione del Consiglio adottata a norma dell’articolo 136, paragrafo 1, TFUE.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Si riserva la priorità alla sospensione degli impegni. I pagamenti sono sospesi solo qualora si richieda un intervento immediato e in caso di grave inadempienza. La sospensione dei pagamenti si applica alle domande di pagamento presentate per i programmi interessati dopo la data della decisione di sospensione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Una proposta di decisione di sospensione degli impegni presentata dalla Commissione si ritiene adottata dal Consiglio a meno che esso non decida, tramite un atto di esecuzione, di respingere la proposta a maggioranza qualificata entro 1 mese della presentazione della proposta della Commissione.</div>\n</div>"], [null, "<p class=\"norm\">La sospensione degli impegni si applica agli impegni a carico dei fondi a favore dello Stato membro interessato a partire dal 1<span class=\"superscript\">o</span> gennaio dell’anno successivo all’adozione della decisione di sospensione.</p>"], [null, "<p class=\"norm\">Il Consiglio adotta una decisione, tramite un atto di esecuzione, su una proposta della Commissione di cui ai paragrafi 7 e 8 riguardo alla sospensione dei pagamenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">L’ambito e il livello della sospensione degli impegni o dei pagamenti da imporre sono proporzionati, rispettano la parità di trattamento tra Stati membri e tengono conto della situazione socioeconomica dello Stato membro interessato, in particolare del livello di disoccupazione, povertà o esclusione sociale nello Stato membro interessato rispetto alla media dell’Unione e dell’impatto della sospensione sull’economia dello Stato membro interessato. L’impatto della sospensione sui programmi di importanza critica per contrastare condizioni difficili di natura economica o sociale rappresenta un fattore specifico da considerare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La sospensione degli impegni è soggetta a un massimale pari al 25 % degli impegni per l’anno civile successivo per i fondi, o allo 0,25 % del PIL nominale se inferiore, in ciascuno dei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel primo caso di inadempienza riguardante una procedura per disavanzi eccessivi di cui al paragrafo 7;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel primo caso di inadempienza riguardante un piano d’azione correttivo in una procedura per gli squilibri eccessivi di cui al paragrafo 8, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di inadempienza dell’azione correttiva raccomandata in seguito a una procedura per gli squilibri eccessivi di cui al paragrafo 8, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel primo caso di inadempienza di cui al paragrafo 8, lettere c) e d).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In caso di inadempienza persistente, la sospensione degli impegni può superare le percentuali massimali indicate al primo comma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Dietro proposta della Commissione il Consiglio revoca la sospensione degli impegni nei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la procedura per i disavanzi eccessivi è sospesa a norma dell’articolo 9 del regolamento (CE) n. 1467/97 o il Consiglio ha deciso, a norma dell’articolo 126, paragrafo 12, TFUE, di abrogare la decisione riguardante l’esistenza di un disavanzo eccessivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il Consiglio ha approvato il piano d’azione correttivo presentato dallo Stato membro interessato a norma dell’articolo 8, paragrafo 2, del regolamento (UE) n. 1176/2011 o la procedura per gli squilibri eccessivi è sospesa a norma dell’articolo 10, paragrafo 5, di tale regolamento o il Consiglio ha chiuso la procedura per gli squilibri eccessivi a norma dell’articolo 11 di tale regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la Commissione ha concluso che lo Stato membro interessato ha adottato le misure opportune di cui al regolamento (CE) n. 332/2002;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la Commissione ha concluso che lo Stato membro interessato ha adottato le misure opportune per attuare il programma di aggiustamento macroeconomico di cui all’articolo 7 del regolamento (UE) n. 472/2013 o le misure richieste con decisione del Consiglio adottata a norma dell’articolo 136, paragrafo 1, TFUE.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In seguito alla revoca, da parte del Consiglio, della sospensione degli impegni, la Commissione iscrive nuovamente in bilancio gli impegni sospesi a norma dell’articolo 6 del regolamento (UE, Euratom) 2020/2093.</p>"], [null, "<p class=\"norm\">Gli impegni sospesi non possono essere iscritti nuovamente in bilancio per anni successivi al 2027.</p>"], [null, "<p class=\"norm\">Il termine per il disimpegno dell’importo iscritto nuovamente in bilancio a norma dell’articolo 105 decorre dall’anno in cui l’impegno sospeso è stato iscritto nuovamente in bilancio.</p>"], [null, "<p class=\"norm\">Una decisione di revoca della sospensione dei pagamenti è adottata dal Consiglio su proposta della Commissione se sono soddisfatte le condizioni applicabili di cui al primo comma. Una proposta di decisione di revoca della sospensione degli impegni presentata dalla Commissione si ritiene adottata dal Consiglio a meno che esso non decida, tramite un atto di esecuzione, di respingere la proposta a maggioranza qualificata entro 1 mese dalla presentazione della proposta della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">14.  </span>\n<div class=\"norm inline-element\">La Commissione informa il Parlamento europeo in merito all’attuazione del presente articolo. In particolare, ove per uno Stato membro risulti soddisfatta una delle condizioni di cui al paragrafo 6, 7 o 8, la Commissione informa immediatamente il Parlamento europeo e trasmette informazioni dettagliate sui fondi e sui programmi che potrebbero formare oggetto di sospensione.</div>\n</div>"], [null, "<p class=\"norm\">Il Parlamento europeo può invitare la Commissione a un dialogo strutturato sull’applicazione del presente articolo, alla luce della trasmissione delle informazioni a norma del primo comma.</p>"], [null, "<p class=\"norm\">La Commissione trasmette la proposta di sospensione o la proposta di revoca della sospensione al Parlamento europeo e al Consiglio senza indugio dopo la sua adozione. Il Parlamento europeo può invitare la Commissione a spiegare le motivazioni della sua proposta.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">15.  </span>\n<div class=\"norm inline-element\">Entro il 31 dicembre 2025 la Commissione procede a un riesame dell’applicazione del presente articolo. A tal fine la Commissione elabora una relazione che trasmette al Parlamento europeo e al Consiglio, corredata se del caso di una proposta legislativa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">16.  </span>\n<div class=\"norm inline-element\">Qualora si verifichino importanti cambiamenti nella situazione socioeconomica dell’Unione, la Commissione può presentare una proposta di riesame dell’applicazione del presente articolo, oppure il Parlamento europeo o il Consiglio, agendo a norma dell’articolo 225 o dell’articolo 241 TFUE rispettivamente, possono chiedere alla Commissione di presentare tale proposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">17.  </span>\n<div class=\"norm inline-element\">Il presente articolo non si applica al FSE+, all’AMIF, all’ISF, al BMVI o ai programmi Interreg.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Misure temporanee per l’utilizzo dei fondi in risposta a circostanze eccezionali o inconsuete", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora il Consiglio, dopo il 1<span class=\"superscript\">o</span> luglio 2021, abbia riconosciuto il prodursi di un evento inconsueto al di fuori del controllo di uno o più Stati membri che abbia rilevanti ripercussioni sulla situazione finanziaria delle pubbliche amministrazioni oppure di una grave recessione economica della zona euro o dell’intera Unione, come previsto all’articolo 5, paragrafo 1, decimo comma, all’articolo 6, paragrafo 3, quarto comma, all’articolo 9, paragrafo 1, decimo comma, e all’articolo 10, paragrafo 3, quarto comma, del regolamento (CE) n. 1466/97 (\n<span class=\"superscript\">14</span>\n), oppure del verificarsi di eventi economici sfavorevoli imprevisti con importanti conseguenze negative per le finanze pubbliche, come previsto all’articolo 3, paragrafo 5, e all’articolo 5, paragrafo 2, del regolamento (CE) n. 1467/97, la Commissione può, mediante una decisione di esecuzione e per un periodo massimo di diciotto mesi, adottare una o più delle misure seguenti, a condizione che siano strettamente necessarie per rispondere a tali circostanze eccezionali o inconsuete:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">su richiesta di uno o più Stati membri interessati, aumentare i pagamenti intermedi di 10 punti percentuali in aggiunta al tasso di cofinanziamento applicabile, senza superare il 100 %, in deroga all’articolo 112, paragrafi 3 e 4 del presente regolamento, nonché all’articolo 40 del regolamento FEAMPA, all’articolo 15 del regolamento AMIF, all’articolo 12 del regolamento ISF e all’articolo 12 del regolamento BMVI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consentire alle autorità di uno Stato membro di selezionare, per ricevere sostegno, le operazioni portate materialmente a termine o pienamente attuate prima che la domanda di finanziamento a titolo del programma sia debitamente presentata all’autorità di gestione, in deroga all’articolo 63, paragrafo 6, a condizione che l’operazione costituisca una risposta alle circostanze eccezionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevedere che le spese per le operazioni che costituiscono una risposta a tali circostanze siano ammissibili a partire dalla data in cui il Consiglio ha confermato il verificarsi di tali circostanze, in deroga all’articolo 63, paragrafo 7;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prorogare al massimo di tre mesi i termini per la presentazione di documenti e la trasmissione di dati alla Commissione, in deroga agli articoli 41, paragrafo 6, 42, paragrafo 1, 44, paragrafo 2, e 49, paragrafo 3, primo comma.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione informa il Parlamento europeo e il Consiglio in merito all’attuazione del presente articolo. Quando sia soddisfatta una delle condizioni di cui al paragrafo 1, la Commissione informa immediatamente il Parlamento europeo e il Consiglio riguardo alla sua valutazione della situazione e al seguito che prevede di dare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo o il Consiglio possono invitare la Commissione a un dialogo strutturato sull’applicazione del presente articolo. All’atto di valutare la situazione e di prevedere un seguito, la Commissione tiene in debita considerazione le posizioni adottate e i pareri espressi nell’ambito del dialogo strutturato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se, trascorso il periodo non superiore a diciotto mesi di cui al paragrafo 1, persistono le circostanze specifiche che hanno portato all’adozione di tali misure temporanee, la Commissione riesamina la situazione e avanza, se del caso, una proposta legislativa che modifica il presente regolamento prevedendo la flessibilità necessaria ad affrontare tali circostanze.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione informa il Parlamento europeo e il Consiglio della decisione di esecuzione adottata a norma del paragrafo 1 senza ritardo, al più tardi entro 2 giorni lavorativi dalla sua adozione.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Preparazione e presentazione dei programmi", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri preparano, in cooperazione con i partner di cui all’articolo 8, paragrafo 1, i programmi per attuare i fondi per il periodo compreso fra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri presentano i programmi alla Commissione non oltre tre mesi dopo la presentazione dell’accordo di partenariato. Per l’AMIF, l’ISF e il BMVI gli Stati membri presentano i programmi alla Commissione non oltre tre mesi dopo l’entrata in vigore del presente regolamento o del pertinente regolamento specifico del fondo, a seconda di quale sia posteriore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri preparano i programmi in conformità del modello di programma riportato nell’allegato V.</div>\n</div>"], [null, "<p class=\"norm\">Per l’AMIF, l’ISF e il BMVI gli Stati membri preparano i programmi in conformità del modello di programma riportato nell’allegato VI.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un eventuale rapporto ambientale, redatto conformemente alla direttiva 2001/42/CE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">15</span>\n), è pubblicato sul sito web del programma di cui all’articolo 49, paragrafo 1, del presente regolamento.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Contenuto dei programmi", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascun programma stabilisce una strategia che indichi il contributo del programma agli obiettivi strategici o dell’obiettivo specifico del JTF e la comunicazione dei risultati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Un programma è costituito da una o più priorità. Ciascuna priorità corrisponde a un unico obiettivo strategico, all’obiettivo specifico del JTF oppure all’assistenza tecnica, se attuata a norma dell’articolo 36, paragrafo 4, o dell’articolo 37. Una priorità può avvalersi del sostegno di uno o più fondi, a meno che non riceva il sostegno del JTF o riguardi l’assistenza tecnica attuata a norma dell’articolo 36, paragrafo 4, o dell’articolo 37. Una priorità che corrisponde a un obiettivo strategico consiste di uno o più obiettivi specifici. Più priorità possono corrispondere allo stesso obiettivo strategico o all’obiettivo specifico del JTF.</div>\n</div>"], [null, "<p class=\"norm\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, un programma si avvale del sostegno di un fondo ed è composto da obiettivi specifici e da obiettivi specifici relativi all’assistenza tecnica.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascun programma stabilisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una sintesi delle principali sfide, tenendo presenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le disuguaglianze e le disparità di carattere economico, sociale e territoriale, ad eccezione dei programmi sostenuti dal FEAMPA;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fallimenti del mercato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la necessità di investimenti e la complementarità e le sinergie con altre forme di sostegno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le sfide individuate nelle pertinenti raccomandazioni specifiche per paese, nelle pertinenti strategie nazionali o regionali di tale Stato membro, tra cui il piano nazionale integrato per l’energia e il clima e in relazione ai principi del pilastro europeo dei diritti sociali, e, per l’AMIF, l’ISF e il BMVI, in altre raccomandazioni pertinenti dell’Unione destinate allo Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le sfide relative alla capacità amministrativa e alla governance e alle misure di semplificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un approccio integrato per affrontare le sfide demografiche, ove pertinente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli insegnamenti tratti da esperienze passate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>viii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le strategie macroregionali e per i bacini marittimi qualora gli Stati membri e le regioni partecipino a tali strategie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ix) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, i progressi conseguiti nell’attuazione del pertinente <span class=\"italics\">acquis</span> e dei pertinenti piani di azione dell’Unione e una giustificazione della scelta degli obiettivi specifici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>x) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi sostenuti dal JTF, le sfide dovute alla transizione individuate nei piani territoriali per una transizione giusta.</p>\n</div>\n</div>\n<p class=\"list\">I punti i), ii) e viii) non si applicano ai programmi sostenuti dall’AMIF, dall’ISF o dal BMVI.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la giustificazione degli obiettivi strategici selezionati, delle priorità, degli obiettivi specifici e delle forme di sostegno corrispondenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ciascuna priorità, ad eccezione dell’assistenza tecnica, gli obiettivi specifici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ciascun obiettivo specifico:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tipologie di azioni correlate e il loro contributo previsto a tali obiettivi specifici e, se del caso, alle strategie macroregionali, alle strategie per i bacini marittimi e ai piani territoriali per una transizione giusta sostenuti dal JTF;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli indicatori di output e gli indicatori di risultato con i corrispondenti target intermedi e target finali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i principali gruppi di destinatari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni a tutela dell’uguaglianza, dell’inclusione e della non discriminazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’indicazione dei territori specifici cui è diretta l’azione, compreso l’utilizzo previsto degli investimenti territoriali integrati, dello sviluppo locale di tipo partecipativo o di altri strumenti territoriali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni interregionali, transfrontaliere e transnazionali con beneficiari situati in almeno un altro Stato membro o al di fuori dell’Unione, se pertinente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’utilizzo previsto degli strumenti finanziari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>viii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tipologie di intervento e una ripartizione indicativa delle risorse programmate per tipologia di intervento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ix) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per l’obiettivo specifico del JTF, la giustificazione di eventuali importi trasferiti dalle risorse del FESR e del FSE+ in conformità dell’articolo 27, nonché la sua ripartizione per categoria di regioni, sulla base delle tipologie di intervento previste in conformità dei piani territoriali per una transizione giusta;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ciascuna priorità relativa all’assistenza tecnica attuata a norma dell’articolo 36, paragrafo 4:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tipologie di azioni correlate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli indicatori di output con i corrispondenti target intermedi e target finali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i principali gruppi di destinatari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tipologie di intervento e una ripartizione indicativa delle risorse programmate per tipologia di intervento;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il ricorso previsto all’assistenza tecnica in conformità dell’articolo 37, se applicabile, e le pertinenti tipologie di intervento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un piano di finanziamento che contenga:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una tabella che specifichi le dotazioni finanziarie per ciascuno dei fondi e, se applicabile, per ciascuna categoria di regioni, per l'intero periodo di programmazione e per anno, compresi gli eventuali importi trasferiti in conformità dell'articolo 26 o 27 e la richiesta da parte degli Stati membri di misure di sostegno che contribuiscano al conseguimento degli obiettivi di cui all'articolo 21 <span class=\"italics\">quater</span>, paragrafo 3, del regolamento (UE) 2021/241 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">16</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi sostenuti dal FESR, dal FSE+ e dal Fondo di coesione, una tabella che specifichi le dotazioni finanziarie complessive per ogni priorità, suddivisa per fondo e per categoria di regioni, se applicabile, e il contributo nazionale, e se è composto da contributi pubblici o privati, o da entrambi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi sostenuti dal FEAMPA, una tabella che specifichi per ciascun obiettivo specifico l’importo delle dotazioni finanziarie totali del sostegno a carico del fondo e il contributo nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI una tabella che specifichi, per obiettivo specifico, le dotazioni finanziarie totali per tipologia di azione, il contributo nazionale, e se è composto da contributi pubblici o privati, o da entrambi;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni adottate per coinvolgere i partner pertinenti di cui all’articolo 8, paragrafo 1, nella preparazione del programma e il loro ruolo nelle attività di esecuzione, sorveglianza e valutazione del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ciascuna condizione abilitante collegata all’obiettivo specifico selezionato, stabilita in conformità dell’articolo 15 e degli allegati III e IV, una valutazione che indichi se la condizione abilitante è soddisfatta alla data di presentazione del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’approccio previsto in termini di comunicazione e visibilità del programma mediante la definizione dei suoi obiettivi, del pubblico destinatario, dei canali di comunicazione, compresa la diffusione sui social media, ove opportuno, del bilancio previsto e dei pertinenti indicatori di sorveglianza e valutazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le autorità del programma e l’organo o, in caso di assistenza tecnica a norma dell’articolo 36, paragrafo 5, se del caso, gli organismi che ricevono i pagamenti della Commissione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I punti i), ii) e viii) della lettera a) del presente paragrafo non si applicano ai programmi che si limitano a sostenere l’obiettivo specifico di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+. La lettera d) del presente paragrafo non si applica all’obiettivo specifico di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+.</p>"], [null, "<p class=\"norm\">Per il FESR, il Fondo di coesione, il FSE+, il JTF e il FEAMPA, il programma è corredato, a fini informativi, di un elenco delle operazioni pianificate di importanza strategica e del relativo calendario.</p>"], [null, "<p class=\"norm\">Se, in conformità della lettera k), viene individuato più di un organismo che riceve i pagamenti della Commissione, lo Stato membro fissa la quota degli importi rimborsati a ciascuno di tali organi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 3, lettere da b) a e), per ciascun obiettivo specifico dei programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, sono presentate le informazioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione della situazione di partenza, delle sfide e delle risposte cui il fondo fornisce sostegno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’indicazione delle misure di attuazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un elenco indicativo delle azioni e del contributo previsto agli obiettivi specifici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove applicabile, una giustificazione del sostegno operativo, delle azioni specifiche, dell’assistenza emergenziale e delle azioni di cui agli articoli 19 e 20 del regolamento AMIF;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli indicatori di output e di risultato con i corrispondenti target intermedi e target finali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una ripartizione indicativa delle risorse programmate per tipologia di intervento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le tipologie di intervento si basano su una nomenclatura riportata nell’allegato I. Per i programmi sostenuti dal FEAMPA, dall’AMIF, dall’ISF e dal BMVI le tipologie di intervento si basano su una nomenclatura stabilita nei regolamenti specifici relativi ai fondi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Per i programmi del FESR, del FSE+, del Fondo di coesione e del JTF, la tabella di cui al paragrafo 3, lettera g), punto ii), riporta gli importi per gli anni dal 2021 al 2027, compreso l’importo di flessibilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Lo Stato membro comunica alla Commissione qualsiasi variazione delle informazioni di cui al paragrafo 3, primo comma, lettera k), senza necessità di una modifica del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dal JTF, gli Stati membri presentano alla Commissione i piani territoriali per una transizione giusta nell’ambito del programma o dei programmi o di una richiesta di modifica.</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Approvazione dei programmi", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione valuta il programma e la sua conformità al presente regolamento e ai regolamenti specifici relativi ai fondi, oltre che, per il FESR, il FSE+, il Fondo di coesione, il JTF e il FEAMPA, la coerenza con il pertinente accordo di partenariato. Nella sua valutazione la Commissione tiene conto in particolare delle pertinenti raccomandazioni specifiche per paese, delle pertinenti sfide individuate nei piani nazionali integrati per l’energia e il clima e dei principi del pilastro europeo dei diritti sociali, nonché del modo in cui vi si è dato seguito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può formulare osservazioni entro tre mesi dalla data di presentazione del programma da parte dello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro rivede il programma tenendo conto delle osservazioni formulate dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante un atto di esecuzione, una decisione che approva il programma entro cinque mesi dalla data di prima presentazione del programma da parte dello Stato membro.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Modifica dei programmi", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può presentare una richiesta motivata di modifica di un programma unitamente al programma modificato, indicando l’effetto previsto della modifica sul conseguimento degli obiettivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione valuta la modifica e la sua conformità al presente regolamento e ai regolamenti specifici relativi ai fondi, comprese le prescrizioni a livello nazionale, e può formulare osservazioni entro due mesi dalla presentazione del programma modificato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro rivede il programma modificato tenendo presenti le osservazioni formulate dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta una decisione di approvazione della modifica di un programma non oltre quattro mesi dalla sua presentazione da parte dello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione e dal JTF, lo Stato membro può trasferire durante il periodo di programmazione un importo che va fino all’8 % della dotazione iniziale di una priorità e non superiore al 4 % del bilancio del programma a un’altra priorità dello stesso fondo a sostegno dello stesso programma. Per i programmi sostenuti dal FESR, dal FSE+ e dal JTF, il trasferimento riguarda solo dotazioni per la stessa categoria di regioni.</div>\n</div>"], [null, "<p class=\"norm\">Per i programmi sostenuti dal FEAMPA, lo Stato membro può trasferire durante il periodo di programmazione un importo che va fino all’8 % della dotazione iniziale di un obiettivo specifico a un altro obiettivo specifico, compresa l’assistenza tecnica attuata a norma dell’articolo 36, paragrafo 4.</p>"], [null, "<p class=\"norm\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, lo Stato membro può trasferire durante il periodo di programmazione dotazioni tra tipologie di azioni all’interno della stessa priorità e, inoltre, un importo che va fino al 15 % della dotazione iniziale di una priorità a un’altra priorità dello stesso fondo.</p>"], [null, "<p class=\"norm\">Tali trasferimenti non incidono sugli anni precedenti. I trasferimenti e le relative modifiche sono considerati non rilevanti e non richiedono una decisione della Commissione che approvi la modifica del programma. Essi avvengono comunque nel rispetto di tutti i requisiti normativi e sono approvati in anticipo dal comitato di sorveglianza a norma dell’articolo 40, paragrafo 2, lettera d). Lo Stato membro presenta alla Commissione la versione modificata della tabella di cui all’articolo 22, paragrafo 3, lettera g), punto ii), iii) o iv), a seconda dei casi, assieme ad ogni relativa modifica nel programma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Non è richiesta l’approvazione della Commissione per le correzioni di natura puramente materiale o editoriale che non influiscono sull’attuazione del programma. Gli Stati membri comunicano tali correzioni alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dal FEAMPA, le modifiche dei programmi relative all’introduzione di indicatori non richiedono l’approvazione della Commissione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dal FESR, dal FSE+ o dal Fondo di coesione, lo Stato membro può presentare una modifica di un programma, conformemente al presente articolo, chiedendo che le misure che contribuiscono al conseguimento degli obiettivi di cui all'articolo 21 <span class=\"italics\">quater</span>, paragrafo 3, del regolamento (UE) 2021/241, siano incluse in un programma, se tale sostegno contribuisce agli obiettivi specifici del fondo in questione stabiliti nei regolamenti specifici di ciascun fondo. Gli importi richiesti per tali misure sono programmati nell'ambito di un obiettivo specifico conformemente ai regolamenti specifici di ciascun fondo e inclusi in una priorità. Tali importi non superano complessivamente il limite del 7,5 % della dotazione nazionale iniziale per ciascun fondo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">In deroga all'articolo 18 del presente regolamento, qualora le priorità dedicate agli investimenti che contribuiscono agli obiettivi STEP di cui all'articolo 2 del regolamento (UE) 2024/795 sono state incluse in un programma a seguito dell'approvazione di una modifica del programma presentata dallo Stato membro entro il 31 agosto 2024, tali priorità non sono prese in considerazione ai fini della revisione intermedia. La decisione che approva le modifiche di tale programma può comportare l'assegnazione definitiva della totalità o di parte dell'importo di flessibilità per gli anni 2026 e 2027 per affrontare le priorità dedicate agli investimenti che contribuiscono agli obiettivi STEP. Se l'intero importo di flessibilità di un programma è assegnato in via definitiva a tali priorità, la revisione intermedia non è effettuata per tale programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 4 del presente articolo, la Commissione adotta la decisione che approva la modifica di un programma, che è stata presentata entro il 31 agosto 2024, entro due mesi dalla sua presentazione da parte di uno Stato membro, a condizione che riguardi esclusivamente l'introduzione di priorità dedicate agli investimenti che contribuiscono agli obiettivi STEP di cui all'articolo 2 del regolamento (UE) 2024/795</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "25": {"label": "Articolo 25", "heading": "Sostegno congiunto del FESR, del FSE+, del Fondo di coesione e del JTF", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il FESR, il FSE+, il Fondo di coesione e il JTF possono fornire sostegno congiuntamente ai programmi dell’obiettivo «Investimenti a favore dell’occupazione e della crescita».</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il FESR e il FSE+ possono finanziare, in modo complementare ed entro il limite del 15 % del sostegno di tali fondi a ciascuna priorità di un programma, totalmente o parzialmente un’operazione i cui costi sono ammissibili al sostegno dell’altro fondo in base alle regole di ammissibilità applicate a tale fondo, a condizione che tali costi siano necessari per l’attuazione. Tale opzione non si applica alle risorse del FESR e del FSE+ che sono trasferite al JTF in conformità dell’articolo 27.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Trasferimento di risorse", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono chiedere, nell’accordo di partenariato o in una richiesta di modifica di un programma previo accordo del comitato di sorveglianza del programma ai sensi dell’articolo 40, paragrafo 2, lettera d), di trasferire un importo che va fino al 5 % della dotazione nazionale iniziale di ciascun fondo a qualsiasi altro strumento in regime di gestione diretta o indiretta, se tale possibilità è prevista nell’atto di base di tale strumento.</div>\n</div>"], [null, "<p class=\"norm\">La somma dei trasferimenti di cui al primo comma del presente articolo e dei contributi a norma dell’articolo 14, paragrafo 1, primo comma, non supera il 5 % della dotazione nazionale iniziale di ciascun fondo.</p>"], [null, "<p class=\"norm\">Nell’accordo di partenariato o nella richiesta di modifica di un programma gli Stati membri possono inoltre chiedere di trasferire un importo che va fino al 5 % della dotazione nazionale iniziale di ciascun fondo a un altro fondo o ad altri fondi, ad eccezione dei trasferimenti di cui al quarto comma.</p>"], [null, "<p class=\"norm\">Nell’accordo di partenariato o nella richiesta di modifica di un programma gli Stati membri possono inoltre chiedere di trasferire un importo supplementare che va fino al 20 % della dotazione nazionale iniziale per fondo tra il FESR, il FSE+ o il Fondo di coesione entro i limiti delle risorse globali dello Stato membro per l’obiettivo «Investimenti a favore dell’occupazione e della crescita». Gli Stati membri il cui tasso medio di disoccupazione totale per il periodo 2017-2019 è inferiore al 3 % possono chiedere di trasferire un importo supplementare che va fino al 25 % della dotazione nazionale iniziale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le risorse trasferite sono attuate in conformità delle regole del fondo o dello strumento cui esse sono trasferite e, nel caso di trasferimenti a strumenti in regime di gestione diretta o indiretta, a favore dello Stato membro interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le richieste di modifica di un programma stabiliscono l’importo totale trasferito ogni anno per fondo e per categoria di regioni; se applicabile, le richieste sono debitamente giustificate in vista delle complementarità e dell’impatto da conseguire e sono accompagnate dal programma o dai programmi modificati in conformità dell’articolo 24.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Previa consultazione dello Stato membro interessato, la Commissione si oppone a una richiesta di trasferimento nella pertinente modifica del programma qualora tale trasferimento possa pregiudicare il conseguimento degli obiettivi del programma da cui proverrebbero le risorse trasferite.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione si oppone altresì alla richiesta se ritiene che lo Stato membro non abbia fornito una giustificazione adeguata del trasferimento relativamente ai risultati da conseguire o al contributo che sarà apportato agli obiettivi del fondo o dello strumento ricevente in regime di gestione diretta o indiretta.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora la richiesta di trasferimento riguardi la modifica di un programma, possono essere trasferite solo le risorse di anni civili futuri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le risorse del JTF, comprese le risorse trasferite dal FESR e dal FSE+ in conformità dell’articolo 27, non sono trasferibili ad altri fondi o strumenti a norma dei paragrafi da 1 a 5 del presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">Il JTF non riceve trasferimenti a norma dei paragrafi da 1 a 5.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se la Commissione non ha assunto un impegno giuridico in regime di gestione diretta o indiretta per le risorse trasferite a norma del paragrafo 1, le corrispondenti risorse non impegnate possono essere ritrasferite al fondo dal quale sono state inizialmente trasferite e assegnate a uno o più programmi.</div>\n</div>"], [null, "<p class=\"norm\">A tal fine lo Stato membro presenta una richiesta di modifica del programma a norma dell’articolo 24, paragrafo 1, al più tardi quattro mesi prima del termine per gli impegni di cui all’articolo 114, paragrafo 2, primo comma, del regolamento finanziario.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Le risorse ritrasferite al fondo dal quale sono state inizialmente trasferite e assegnate a uno o più programmi sono attuate in conformità delle norme stabilite nel presente regolamento e nei regolamenti specifici relativi a ciascun fondo a decorrere dalla data di presentazione della richiesta di modifica del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Per le risorse ritrasferite al fondo dal quale sono state inizialmente trasferite e assegnate a un programma in conformità del paragrafo 7 del presente articolo, il termine per il disimpegno definito all’articolo 105, paragrafo 1, decorre dall’anno in cui vengono assunti i corrispettivi impegni di bilancio.</div>\n</div>"]]}, "26a": {"label": "Articolo 26 bis", "heading": "Sostegno al conseguimento degli obiettivi di cui all'articolo 21 quater , paragrafo 3, del regolamento (UE) 2021/241", "anchor": "art_26a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che presentano alla Commissione, conformemente al regolamento (UE) 2021/241, un piano per la ripresa e la resilienza contenente un capitolo dedicato al piano REPowerEU possono chiedere, mediante una modifica del programma in conformità dell'articolo 24 del presente regolamento, che fino al 7,5 % della loro dotazione nazionale iniziale nell'ambito del FESR, del FSE+ e del Fondo di coesione sia incluso nelle priorità che contribuiscono al conseguimento degli obiettivi di cui all'articolo 21 <span class=\"italics\">quater</span>, paragrafo 3, del regolamento (UE) 2021/241, a condizione che tale sostegno contribuisca agli obiettivi specifici del fondo in questione stabiliti nei regolamenti specifici di ciascun fondo. La possibilità di tale richiesta non pregiudica la possibilità di trasferimento di risorse prevista dall'articolo 26 del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le risorse richieste dagli Stati membri ai sensi del presente articolo sono eseguite in conformità del presente regolamento e dei regolamenti specifici relativi ai fondi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le richieste di modifica di un programma indicano l'importo totale delle risorse che contribuiscono al conseguimento degli obiettivi di cui all'articolo 21 <span class=\"italics\">quater</span>, paragrafo 3, del regolamento (UE) 2021/241 ciascun anno per fondo e per categoria di regione, se applicabile.</div>\n</div>"]]}, "26b": {"label": "Articolo 26 ter", "heading": "Risorse trasferite dal Fondo sociale per il clima", "anchor": "art_26b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le risorse trasferite dal Fondo sociale per il clima istituito dal regolamento (UE) 2023/955 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">17</span>\n) sono attuate conformemente al presente regolamento e alle disposizioni che disciplinano il Fondo al quale le risorse sono trasferite e sono definitive. Tali risorse costituiscono entrate con destinazione specifica esterne ai fini dell’articolo 21, paragrafo 5, del regolamento (UE, Euratom) 2018/1046 e si aggiungono alle risorse di cui all’articolo 110 del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando attuano le risorse di cui al paragrafo 1 del presente articolo in regime di gestione concorrente, gli Stati membri presentano modifiche riguardanti uno o più programmi in conformità dell’articolo 24 del presente regolamento. Gli Stati membri pianificano l’uso di tali risorse per conseguire gli obiettivi climatici stabiliti per il bilancio dell’Unione conformemente all’articolo 6, paragrafo 1, del presente regolamento. Tali risorse contribuiscono al conseguimento degli obiettivi pertinenti del Fondo sociale per il clima di cui all’articolo 3 del regolamento (UE) 2023/955 e sono utilizzate per sostenere le misure e gli investimenti di cui all’articolo 8 di tale regolamento. Esse sono programmate nell’ambito di una o più priorità dedicate corrispondenti a uno o più obiettivi specifici del Fondo a cui sono trasferite le risorse e, se del caso, per una o più categorie di regioni, con l’indicazione della ripartizione annua delle risorse. Le risorse non sono prese in considerazione ai fini del calcolo della conformità ai requisiti in materia di concentrazione tematica di cui alle norme specifiche di ciascun Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se la Commissione ha già approvato la richiesta di uno Stato membro di modificare un programma relativo a un trasferimento di risorse dal Fondo sociale per il clima, per qualsiasi ulteriore trasferimento di risorse negli anni successivi lo Stato membro può presentare una notifica concernente le tabelle finanziarie anziché una modifica di programma, a condizione che le modifiche proposte riguardino esclusivamente un aumento delle risorse finanziarie, senza ulteriori modifiche del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 18 e all’articolo 86, paragrafo 1, secondo comma, del presente regolamento, le risorse trasferite a norma del presente articolo e dell’articolo 11, paragrafo 2, del regolamento (UE) 2023/955 non sono prese in considerazione ai fini del riesame intermedio e dell’importo di flessibilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 14, paragrafo 3, del regolamento (UE, Euratom) 2018/1046, il termine dopo il quale la Commissione procede al disimpegno degli importi a norma dell’articolo 105, paragrafo 1, del presente regolamento decorre dall’anno in cui sono assunti i corrispondenti impegni di bilancio. Le risorse non sono trasferite a programmi nell’ambito dell’obiettivo «Cooperazione territoriale europea» (Interreg).</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Trasferimento di risorse dal FESR e dal FSE+ al JTF", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono chiedere su base volontaria che l’importo delle risorse a disposizione del JTF per l’obiettivo «Investimenti a favore dell’occupazione e della crescita» in conformità dell’articolo 3 del regolamento JTF sia integrato con risorse provenienti dal FESR o dal FSE+ ovvero da una loro combinazione per la categoria di regioni in cui si trova il territorio interessato. Il totale delle risorse del FESR e del FSE+ trasferite al JTF non supera il triplo dell’importo della dotazione del JTF di cui all’articolo 110, paragrafo 1, lettera g). Le risorse trasferite dal FESR o dal FSE+ non superano il 15 % della dotazione a titolo rispettivamente del FESR e del FSE+ per lo Stato membro interessato. Gli Stati membri indicano in tali richieste l’importo totale trasferito ogni anno per categoria di regioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I trasferimenti a partire, rispettivamente, dalle risorse del FESR e del FSE+ alla priorità o alle priorità sostenute dal JTF riflettono le tipologie di intervento in base alle informazioni indicate nel programma a norma dell’articolo 22, paragrafo 3, lettera d), punto ix). Tali trasferimenti sono considerati definitivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le risorse del JTF, comprese quelle trasferite dal FESR e dal FSE+, sono attuate in conformità delle norme stabilite nel presente regolamento e nel regolamento JTF. Le norme stabilite nel regolamento FESR e FC e nel regolamento FSE+ non si applicano alle risorse del FESR e del FSE+ trasferite in conformità del paragrafo 1.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Sviluppo territoriale integrato", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">Qualora uno Stato membro sostenga lo sviluppo territoriale integrato, ciò avviene mediante strategie di sviluppo territoriale o locale nelle forme seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">investimenti territoriali integrati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppo locale di tipo partecipativo; o</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un altro strumento territoriale che fornisca sostegno alle iniziative elaborate dallo Stato membro.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Nel mettere in atto strategie di sviluppo locale o territoriale nell’ambito di più di un fondo, lo Stato membro garantisce la coerenza e il coordinamento tra i fondi in questione.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Strategie territoriali", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le strategie territoriali attuate a norma dell’articolo 28, lettera a) o c), contengono gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’area geografica interessata dalla strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’analisi delle esigenze di sviluppo e delle potenzialità dell’area, comprese le interconnessioni di tipo economico, sociale e ambientale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione dell’approccio integrato per dare risposta alle esigenze di sviluppo individuate e per realizzare le potenzialità dell’area;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione del coinvolgimento dei partner in conformità dell’articolo 8 nella preparazione e nell’attuazione della strategia.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Possono comprendere anche un elenco delle operazioni cui fornire sostegno.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le strategie territoriali rientrano nella responsabilità delle pertinenti autorità o dei pertinenti organismi a livello territoriale. I documenti strategici esistenti che riguardano le aree interessate possono essere usati per le strategie territoriali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l’elenco delle operazioni cui fornire sostegno non è stato inserito nella strategia territoriale, le pertinenti autorità o i pertinenti organismi a livello territoriale selezionano o partecipano alla selezione delle operazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">All’atto dell’elaborazione delle strategie territoriali, le autorità o organismi di cui al paragrafo 2 cooperano con le pertinenti autorità di gestione per determinare l’ambito di applicazione delle operazioni cui fornire sostegno a titolo del programma pertinente.</div>\n</div>"], [null, "<p class=\"norm\">Le operazioni selezionate sono coerenti con la strategia territoriale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se un’autorità o un organismo a livello territoriale adempie compiti che rientrano nella responsabilità dell’autorità di gestione, ad eccezione della selezione delle operazioni, l’autorità è individuata dall’autorità di gestione come organismo intermedio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Può essere fornito sostegno alla preparazione e alla progettazione delle strategie territoriali.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Investimenti territoriali integrati", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">Se una strategia territoriale di cui all’articolo 29 comprende investimenti che ricevono sostegno da uno o più fondi, da più di un programma o da più di una priorità dello stesso programma, le azioni possono essere attuate sotto forma di investimento territoriale integrato.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Sviluppo locale di tipo partecipativo", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro lo ritenga opportuno ai sensi dell’articolo 28, il FESR, il FSE+, il JTF e il FEAMPA sostengono lo sviluppo locale di tipo partecipativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro provvede affinché lo sviluppo locale di tipo partecipativo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia concentrato su aree subregionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia guidato da gruppi di azione locale, composti dai rappresentanti degli interessi socio-economici pubblici e privati, nei quali nessun singolo gruppo di interesse controlli il processo decisionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia attuato mediante strategie in conformità dell’articolo 32;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisca sostegno alle attività in rete, all’accessibilità, alle caratteristiche innovative del contesto locale e, se del caso, alla cooperazione con altri operatori territoriali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando è disponibile sostegno alle strategie di cui al paragrafo 2, lettera c), proveniente da più di un fondo, le pertinenti autorità di gestione organizzano un invito congiunto a presentare proposte per la selezione di tali strategie e formano un comitato congiunto per tutti i fondi interessati per sorvegliare l’attuazione di tali strategie. Le pertinenti autorità di gestione possono scegliere uno dei fondi interessati per sostenere tutti i costi di preparazione, di gestione e di animazione di cui all’articolo 34, paragrafo 1, lettere a) e c), in relazione a tali strategie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando l’attuazione di una tale strategia comprende sostegno proveniente da più di un fondo, le pertinenti autorità di gestione possono scegliere uno dei fondi interessati in qualità di fondo capofila.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatto salvo il rispetto dell’ambito di applicazione e delle regole di ammissibilità di ciascun fondo che partecipa al sostegno della strategia, si applicano le regole del fondo capofila. Le autorità degli altri fondi fanno affidamento sulle decisioni e sulle verifiche di gestione operate dall’autorità competente del fondo capofila.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le autorità del fondo capofila forniscono alle autorità degli altri fondi le informazioni necessarie alla sorveglianza e all’effettuazione dei pagamenti in conformità delle regole del regolamento specifico del fondo.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Strategie di sviluppo locale di tipo partecipativo", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le pertinenti autorità di gestione provvedono affinché ognuna delle strategie di cui all’articolo 31, paragrafo 2, lettera c), contenga gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’area geografica e la popolazione interessate dalla strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il processo di coinvolgimento della comunità locale nello sviluppo della strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’analisi delle esigenze di sviluppo e delle potenzialità dell’area;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi della strategia, tra cui target finali misurabili per i risultati, e le relative azioni previste;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità di gestione, sorveglianza e valutazione, finalizzate a dimostrare la capacità del gruppo di azione locale di attuare la strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un piano finanziario comprendente la dotazione prevista a carico di ciascun fondo nonché, se del caso, la dotazione prevista a carico del FEASR, e di ciascun programma interessato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Essa può anche contenere le tipologie di misure e operazioni da finanziare a titolo di ciascun fondo interessato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le pertinenti autorità di gestione definiscono i criteri per la selezione delle strategie, formano un comitato per lo svolgimento della selezione e approvano le strategie selezionate da tale comitato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le pertinenti autorità di gestione completano la prima tornata di selezione delle strategie e si assicurano che i gruppi di azione locale selezionati possano svolgere i propri compiti, indicati all’articolo 33, paragrafo 3, entro dodici mesi dalla data della decisione d’approvazione del programma o, nel caso di strategie che ricevono sostegno da più di un fondo, entro dodici mesi dalla data della decisione d’approvazione dell’ultimo programma interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La decisione di approvazione di una strategia dispone la dotazione di ciascun fondo e programma interessato e stabilisce le responsabilità dei compiti di gestione e di controllo del programma o dei programmi.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Gruppi di azione locale", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I gruppi di azione locale elaborano ed attuano le strategie di cui all’articolo 31, paragrafo 2, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità di gestione provvedono affinché i gruppi di azione locale siano inclusivi e scelgano al loro interno un partner capofila per le questioni amministrative e finanziarie, oppure si riuniscano in una struttura comune legalmente costituita.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I gruppi di azione locale svolgono in esclusiva i compiti seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppare la capacità degli operatori locali di elaborare e attuare operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere una procedura e criteri di selezione non discriminatori e trasparenti, che evitino conflitti di interessi e garantiscano che nessun singolo gruppo di interesse controlli le decisioni in materia di selezione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare e pubblicare gli inviti a presentare proposte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">selezionare le operazioni e fissare l’importo del sostegno e presentare le proposte all’organismo responsabile della verifica finale dell’ammissibilità prima dell’approvazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sorvegliare i progressi compiuti verso il conseguimento degli obiettivi della strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutare l’attuazione della strategia.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora gruppi di azione locale svolgano compiti non contemplati dal paragrafo 3 che rientrano nella responsabilità dell’autorità di gestione, o dell’organismo pagatore laddove il FEASR sia selezionato come fondo capofila, tali gruppi di azione locale sono designati dall’autorità di gestione come organismi intermedi conformemente alle norme specifiche di ciascun fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il gruppo di azione locale può essere un beneficiario e può attuare operazioni in conformità della strategia, a condizione che il gruppo di azione locale garantisca che sia rispettato il principio della separazione delle funzioni.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Sostegno dei fondi allo sviluppo locale di tipo partecipativo", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro provvede affinché il sostegno dei fondi allo sviluppo locale di tipo partecipativo comprenda:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo sviluppo delle capacità e azioni preparatorie a sostegno dell’elaborazione e della futura attuazione della strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione delle operazioni, tra cui le attività di cooperazione e la loro preparazione, selezionate nell’ambito della strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione, la sorveglianza e la valutazione della strategia e la relativa animazione, compresa l’agevolazione degli scambi tra portatori di interessi;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il sostegno di cui al paragrafo 1, lettera a), è ammissibile a prescindere dal fatto che la strategia sia successivamente selezionata per ricevere sostegno.</div>\n</div>"], [null, "<p class=\"norm\">Il sostegno di cui al paragrafo 1, lettera c), non supera il 25 % del contributo pubblico totale alla strategia.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Assistenza tecnica su iniziativa della Commissione", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione i fondi possono sostenere le azioni preparatorie, di sorveglianza, di controllo, di audit, di valutazione, di comunicazione anche istituzionale delle priorità politiche dell’Unione, di visibilità e tutte le azioni amministrative e di assistenza tecnica necessarie per l’attuazione del presente regolamento e, ove opportuno, con paesi terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le azioni di cui al paragrafo 1 possono comprendere in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistenza alla preparazione e alla valutazione dei progetti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostegno al rafforzamento istituzionale e allo sviluppo di capacità amministrative per la gestione efficace dei fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">studi legati alle relazioni della Commissione sui fondi e alla relazione sulla coesione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure connesse all’analisi, alla gestione, alla sorveglianza, allo scambio di informazioni e all’esecuzione dei fondi, nonché misure relative all’attuazione dei sistemi di controllo e all’assistenza tecnica e amministrativa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutazioni, relazioni di esperti, statistiche e studi, compresi quelli di natura generale, sul funzionamento attuale e futuro dei fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azioni di diffusione delle informazioni, di sostegno alla creazione di reti ove opportuno, di svolgimento di attività di comunicazione con particolare attenzione ai risultati e al valore aggiunto del sostegno dei fondi, azioni di sensibilizzazione e azioni destinate a promuovere la cooperazione e lo scambio di esperienze, anche con paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">installazione, funzionamento e interconnessione di sistemi informatici per la gestione, il monitoraggio, l’audit, il controllo e la valutazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azioni tese a migliorare i metodi di valutazione e lo scambio di informazioni sulle prassi di valutazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azioni relative allo svolgimento di audit;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzamento della capacità nazionale e regionale inerente alla pianificazione degli investimenti, alle esigenze di finanziamento, alla preparazione, progettazione e attuazione di strumenti finanziari, piani di azione comuni e grandi progetti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">divulgazione delle buone pratiche al fine di assistere gli Stati membri a rafforzare la capacità dei partner pertinenti di cui all’articolo 8, paragrafo 1, e le loro organizzazioni ombrello.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione dedica almeno il 15 % delle risorse per l’assistenza tecnica su iniziativa della Commissione all’ottenimento di una maggiore efficienza nella comunicazione al pubblico e di più forti sinergie tra le attività di comunicazione svolte su iniziativa della Commissione, ampliando la base di conoscenze sui risultati ottenuti, in particolare attraverso una raccolta e una diffusione dei dati più efficaci, valutazioni e relazioni, e soprattutto evidenziando il contributo dei fondi nel migliorare le condizioni di vita dei cittadini, come pure aumentando la visibilità del sostegno dei fondi e sensibilizzando in merito ai risultati e al valore aggiunto di tale sostegno. Le misure di informazione, comunicazione e visibilità relative ai risultati e al valore aggiunto del sostegno dei fondi, con particolare attenzione alle operazioni, sono portate avanti dopo la chiusura dei programmi, se del caso. Tali misure contribuiscono anche alla comunicazione istituzionale delle priorità politiche dell’Unione nella misura in cui si riferiscono agli obiettivi generali del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le azioni di cui al paragrafo 1 possono riguardare i periodi di programmazione precedenti e successivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce i propri piani quando è previsto un contributo dei fondi in conformità dell’articolo 110 del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">A seconda della finalità, le azioni di cui al presente articolo possono essere finanziate a titolo di spese operative o amministrative.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">In conformità dell’articolo 193, paragrafo 2, secondo comma, lettera a), del regolamento finanziario, in casi debitamente giustificati specificati nella decisione di finanziamento e per un periodo di tempo limitato, le azioni di assistenza tecnica su iniziativa della Commissione sovvenzionate nell’ambito del presente regolamento in regime di gestione diretta e i costi sottostanti possono essere considerati ammissibili a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2021, anche se tali azioni sono state realizzate e i costi sono stati sostenuti prima della presentazione della domanda di sovvenzione.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Assistenza tecnica degli Stati membri", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa di uno Stato membro i fondi possono sostenere azioni, che possono riguardare periodi di programmazione precedenti e successivi, necessarie per l’amministrazione e l’utilizzo efficaci dei fondi, anche per lo sviluppo delle capacità dei partner di cui all’articolo 8, paragrafo 1, nonché per finanziare lo svolgimento, tra l’altro, di funzioni quali la preparazione, la formazione, la gestione, la sorveglianza, la valutazione, la visibilità e la comunicazione.</div>\n</div>"], [null, "<p class=\"norm\">Gli importi relativi all’assistenza tecnica di cui al presente articolo e all’articolo 37 non sono presi in considerazione ai fini della concentrazione tematica conformemente alle norme specifiche di ciascun fondo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun fondo può sostenere azioni di assistenza tecnica ammissibili nell’ambito di uno degli altri fondi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il contributo dell’Unione per l’assistenza tecnica in uno Stato membro avviene a norma dell’articolo 51, lettera b) o e).</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro indica la propria scelta per quanto riguarda la forma di contributo dell’Unione per l’assistenza tecnica nell’accordo di partenariato in conformità dell’allegato II. Tale scelta si applica a tutti i programmi nello Stato membro interessato per l’intero periodo di programmazione e non può essere successivamente modificata.</p>"], [null, "<p class=\"norm\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, nonché per i programmi Interreg, il contributo dell’Unione per l’assistenza tecnica avviene unicamente a norma dell’articolo 51, lettera e).</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 bis.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 3 del presente articolo, non è concesso alcun contributo dell’Unione per l’assistenza tecnica a sostegno delle azioni di solidarietà quali definite all’articolo 2, punto 15), del regolamento AMIF e all’articolo 2, punto 11), del regolamento BMVI.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora il contributo dell’Unione per l’assistenza tecnica in uno Stato membro sia rimborsato ai sensi dell’articolo 51, lettera b), si applicano gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza tecnica assume la forma di una priorità relativa a un solo fondo in uno o più programmi, di un programma specifico o di una combinazione dei due;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo dei fondi destinato all’assistenza tecnica è limitato a quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del FESR nell’ambito dell’obiettivo «Investimenti a favore dell’occupazione e della crescita»: 3,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del Fondo di coesione: 2,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del FSE+: 4 % e per i programmi a norma dell’articolo 4, paragrafo 1, lettera m), del regolamento FSE+: 5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del JTF: 4 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il FESR, il FSE+ e il Fondo di coesione, qualora l’importo totale assegnato a uno Stato membro nell’ambito dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» non superi 1 miliardo di EUR: 6 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del FEAMPA: 6 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» che riguardano solo le regioni ultraperiferiche, la percentuale è aumentata di 1 punto percentuale.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora il contributo dell’Unione per l’assistenza tecnica sia rimborsato ai sensi dell’articolo 51, lettera e), si applicano gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo dei fondi destinato all’assistenza tecnica è individuato nell’ambito delle dotazioni finanziarie di ciascuna priorità del programma in conformità dell’articolo 22, paragrafo 3, lettera g), punto ii) – per il FEAMPA, nell’ambito di ciascun obiettivo specifico in conformità della lettera g), punto iii), di tale paragrafo. Esso non assume la forma di una priorità separata o di un programma specifico, a eccezione dei programmi sostenuti dall’AMIF, dall’ISF o dal BMVI, per i quali assume la forma di un obiettivo specifico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il rimborso è effettuato, applicando le percentuali indicate nei punti da i) a vii) alle spese ammissibili figuranti in ciascuna domanda di pagamento a norma dell’articolo 91, paragrafo 3, lettera a) o c), a seconda dei casi, e a carico dello stesso fondo a cui sono rimborsate le spese ammissibili, nei confronti di uno o più organismi che ricevono i pagamenti della Commissione in conformità dell’articolo 22, paragrafo 3, lettera k):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del FESR nell’ambito dell’obiettivo «Investimenti a favore dell’occupazione e della crescita»: 3,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del Fondo di coesione: 2,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del FSE+: 4 % e per i programmi a norma dell’articolo 4, paragrafo 1), lettera m), del regolamento FSE+: 5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del JTF: 4 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il FESR, il FSE+ e il Fondo di coesione, qualora l’importo totale assegnato a uno Stato membro nell’ambito dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» non superi 1 miliardo di EUR, la percentuale da rimborsare per l’assistenza tecnica: 6 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il sostegno del FEAMPA, dell’AMIF, dell’ISF e del BMVI: 6 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i programmi dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» che riguardano solo le regioni ultraperiferiche, la percentuale è aumentata di 1 punto percentuale.</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi destinati all’assistenza tecnica individuati nel programma corrispondono alle percentuali di cui alla lettera b), punti da i) a vi), per ciascuna priorità e ciascun fondo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le norme specifiche per l’assistenza tecnica per i programmi Interreg sono stabilite nel regolamento Interreg.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Finanziamento non collegato ai costi dell’assistenza tecnica degli Stati membri", "anchor": "art_37", "frags": [[null, "<p class=\"norm\">Oltre a quanto disposto all’articolo 36, lo Stato membro può proporre di intraprendere ulteriori azioni di assistenza tecnica per rafforzare la capacità e l’efficienza delle autorità e degli organismi pubblici, dei beneficiari e dei partner pertinenti, necessarie per l’amministrazione e l’utilizzo efficaci dei fondi.</p>"], [null, "<p class=\"norm\">Il sostegno destinato a tali azioni avviene sotto forma di finanziamento non collegato ai costi in conformità dell’articolo 95. Tale sostegno può anche assumere la forma di un programma specifico.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Comitato di sorveglianza", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro istituisce un comitato per sorvegliare l’attuazione del programma («comitato di sorveglianza») , previa consultazione dell’autorità di gestione, entro tre mesi dalla data della notifica allo Stato membro interessato della decisione di approvazione del programma.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro può istituire un unico comitato di sorveglianza per seguire più di un programma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun comitato di sorveglianza adotta il proprio regolamento interno, che comprende disposizioni riguardanti la prevenzione delle situazioni di conflitto di interessi e l’applicazione del principio di trasparenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il comitato di sorveglianza si riunisce almeno una volta all’anno ed esamina tutte le questioni che incidono sull’avanzamento del programma verso il conseguimento dei suoi obiettivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il regolamento interno del comitato di sorveglianza e i dati e le informazioni condivisi con detto comitato sono pubblicati sul sito web di cui all’articolo 49, paragrafo 1, fatto salvo l’articolo 69, paragrafo 5.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I paragrafi da 1 a 4 del presente articolo non si applicano ai programmi limitati all’obiettivo specifico di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+ e alla relativa assistenza tecnica.</div>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Composizione del comitato di sorveglianza", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro decide la composizione del comitato di sorveglianza e assicura una rappresentanza equilibrata delle autorità competenti e degli organismi intermedi dello Stato membro, come anche dei rappresentanti dei partner di cui all’articolo 8, paragrafo 1, attraverso un processo trasparente.</div>\n</div>"], [null, "<p class=\"norm\">Ciascun membro del comitato di sorveglianza ha diritto di voto. Il regolamento interno disciplina l’esercizio del diritto di voto e i dettagli della procedura in sede di comitato di sorveglianza conformemente al quadro istituzionale, giuridico e finanziario dello Stato membro interessato.</p>"], [null, "<p class=\"norm\">Il regolamento interno può consentire ai non membri, compresa la BEI, di partecipare ai lavori del comitato di sorveglianza.</p>"], [null, "<p class=\"norm\">Il comitato di sorveglianza è presieduto da un rappresentante dello Stato membro o dell’autorità di gestione.</p>"], [null, "<p class=\"norm\">L’elenco dei membri del comitato di sorveglianza è pubblicato sul sito web di cui all’articolo 49, paragrafo 1.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Rappresentanti della Commissione partecipano ai lavori del comitato di sorveglianza in veste consultiva e di sorveglianza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per l’AMIF, l’ISF e il BMVI, le agenzie decentrate competenti possono partecipare ai lavori del comitato di sorveglianza.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Funzioni del comitato di sorveglianza", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il comitato di sorveglianza esamina:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’attuazione del programma e nel conseguimento dei target intermedi e dei target finali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutte le questioni che incidono sulla performance del programma e le misure adottate per farvi fronte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo del programma al superamento delle sfide individuate nelle pertinenti raccomandazioni specifiche per paese che sono connesse all’attuazione del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli elementi della valutazione ex ante elencati all’articolo 58, paragrafo 3, e il documento strategico di cui all’articolo 59, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’effettuare le valutazioni e le sintesi delle valutazioni, nonché l’eventuale seguito dato agli esiti delle stesse;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione di azioni di comunicazione e visibilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’attuare operazioni di importanza strategica, se pertinente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il soddisfacimento delle condizioni abilitanti e la loro applicazione durante l’intero periodo di programmazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nello sviluppo della capacità amministrativa delle pubbliche amministrazioni, dei partner e dei beneficiari, se pertinente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni relative all’attuazione del contributo del programma al programma InvestEU conformemente all’articolo 14 o delle risorse trasferite conformemente all’articolo 26, se del caso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda i programmi sostenuti dal FEAMPA, il comitato di sorveglianza è consultato e, qualora lo ritenga opportuno, esprime un parere sulle eventuali modifiche del programma proposte dall’autorità di gestione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il comitato di sorveglianza approva:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la metodologia e i criteri utilizzati per la selezione delle operazioni, comprese le eventuali modifiche, fatto salvo l’articolo 33, paragrafo 3, lettere b), c) e d);su richiesta della Commissione, la metodologia e i criteri utilizzati per la selezione delle operazioni, comprese le eventuali modifiche, sono presentati alla Commissione stessa almeno 15 giorni lavorativi prima della loro presentazione al comitato di sorveglianza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le relazioni annuali in materia di performance per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, e la relazione finale in materia di performance per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione, dal JTF e dal FEAMPA;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il piano di valutazione e le eventuali modifiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le eventuali proposte di modifica di un programma avanzate dall’autorità di gestione, compresi i trasferimenti in conformità dell’articolo 24, paragrafo 5, e dell’articolo 26, a eccezione dei programmi sostenuti dal FEAMPA.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il comitato di sorveglianza può rivolgere raccomandazioni all’autorità di gestione, anche in merito a misure volte a ridurre l’onere amministrativo per i beneficiari.</div>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Riesame annuale della performance", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una volta all’anno sono organizzate riunioni di riesame tra la Commissione e ciascuno Stato membro per esaminare la performance di ciascun programma. Alle riunioni di riesame partecipano le autorità di gestione pertinenti.</div>\n</div>"], [null, "<p class=\"norm\">La riunione di riesame può riguardare più di un programma.</p>"], [null, "<p class=\"norm\">La riunione di riesame è presieduta dalla Commissione o, qualora lo Stato membro ne faccia richiesta, è presieduta congiuntamente dallo Stato membro e dalla Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, primo comma, per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI la riunione di riesame è organizzata almeno due volte durante il periodo di programmazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione, dal JTF e dal FEAMPA, lo Stato membro fornisce alla Commissione, almeno 1 mese prima della riunione di riesame, informazioni concise sugli elementi elencati all’articolo 40, paragrafo 1. Tali informazioni si basano sui dati più recenti di cui dispone lo Stato membro.</div>\n</div>"], [null, "<p class=\"norm\">Per i programmi limitati all’obiettivo specifico di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+, le informazioni da fornire, sulla base dei dati più recenti disponibili, sono limitate all’articolo 40, paragrafo 1, lettere a), b), e), f) e h) del presente regolamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo Stato membro e la Commissione possono convenire di non organizzare una riunione di riesame. In tal caso, il riesame può essere effettuato per iscritto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le conclusioni della riunione di riesame sono registrate in forma di verbale concordato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro dà seguito alle problematiche rilevate durante la riunione di riesame che incidono sull’attuazione del programma e informa la Commissione entro tre mesi in merito alle misure adottate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, lo Stato membro presenta una relazione annuale in materia di performance in conformità dei regolamenti specifici relativi a ciascun fondo.</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Trasmissione di dati", "anchor": "art_42", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione trasmette elettronicamente alla Commissione i dati cumulativi di ogni programma entro il 31 gennaio, il 30 aprile, il 31 luglio, il 30 settembre e il 30 novembre di ogni anno a eccezione dei dati richiesti al paragrafo 2, lettera b), e al paragrafo 3, che sono trasmessi elettronicamente entro il 31 gennaio e il 31 luglio di ogni anno, conformemente al modello riportato nell’allegato VII.</div>\n</div>"], [null, "<p class=\"norm\">Il primo invio è effettuato entro il 31 gennaio 2022 e l’ultimo entro il 31 gennaio 2030.</p>"], [null, "<p class=\"norm\">Per le priorità che sostengono l’obiettivo specifico di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+, i dati sono trasmessi annualmente entro il 31 gennaio.</p>"], [null, "<p class=\"norm\">Il regolamento FSE+ può stabilire norme specifiche relativamente alla frequenza della raccolta e della trasmissione degli indicatori di risultato a più lungo termine.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per ciascuna priorità, i dati sono ripartiti per obiettivo specifico e, se applicabile, per categoria di regione e si riferiscono agli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di operazioni selezionate, il loro costo totale ammissibile, il contributo dei fondi e le spese totali ammissibili dichiarate dai beneficiari all’autorità di gestione, tutti ripartiti per tipologia di intervento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i valori degli indicatori di output e di risultato per le operazioni selezionate e i valori conseguiti dalle operazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per gli strumenti finanziari sono forniti anche dati riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese ammissibili per tipologia di prodotto finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo dei costi e delle commissioni di gestione dichiarati come spese ammissibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo, per tipologia di prodotto finanziario, delle risorse pubbliche e private mobilitate in aggiunta ai fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli interessi e altre plusvalenze generate dal sostegno dei fondi agli strumenti finanziari, di cui all’articolo 60, e le risorse restituite imputabili al sostegno dei fondi, di cui all’articolo 62;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il valore totale dei prestiti e degli investimenti azionari o quasi azionari nei confronti di destinatari finali garantiti con le risorse del programma ed effettivamente versati ai destinatari finali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I dati presentati in conformità del presente articolo sono affidabili e rispecchiano i dati conservati elettronicamente di cui all’articolo 72, paragrafo 1, lettera e), alla fine del mese precedente al mese di presentazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione pubblica tutti i dati trasmessi alla Commissione, o ne indica il link, sul portale web di cui all’articolo 46, lettera b), o sul sito web di cui all’articolo 49, paragrafo 1.</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Relazione finale in materia di performance", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione, dal JTF dal FEAMPA ciascuna autorità di gestione presenta alla Commissione una relazione finale in materia di performance del programma entro il 15 febbraio 2031.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La relazione finale in materia di performance valuta il conseguimento degli obiettivi del programma in base agli elementi elencati all’articolo 40, paragrafo 1, ad eccezione delle informazioni presentate a norma dell’articolo 40, paragrafo 1, lettera d), di tale paragrafo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione esamina la relazione finale in materia di performance e informa l’autorità di gestione in merito ad eventuali osservazioni entro cinque mesi dalla data di ricevimento di detta relazione. Se sono formulate osservazioni, l’autorità di gestione fornisce tutte le informazioni necessarie al riguardo e, se opportuno, informa la Commissione entro tre mesi in merito alle misure adottate. La Commissione informa l’autorità di gestione dell’accettazione della relazione entro due mesi dal ricevimento di tutte le informazioni necessarie. Ove la Commissione non informi l’autorità di gestione entro i termini stabiliti, la relazione s’intende accettata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione pubblica le relazioni finali in materia di performance sul sito web di cui all’articolo 49, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta un atto di esecuzione che stabilisce il modello della relazione finale in materia di performance. Tale atto di esecuzione è adottato in conformità della procedura consultiva di cui all’articolo 115, paragrafo 2.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Valutazioni da parte dello Stato membro", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione effettua valutazioni dei programmi relativamente a uno o più dei criteri seguenti: efficacia, efficienza, rilevanza, coerenza e valore aggiunto dell’Unione, al fine di migliorare la qualità della progettazione e dell’attuazione dei programmi. Le valutazioni possono contemplare anche altri criteri pertinenti, quali inclusività, non discriminazione e visibilità, e riguardare più di un programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 30 giugno 2029 è inoltre effettuata una valutazione di ciascun programma per analizzarne l’impatto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le valutazioni sono affidate a esperti interni o esterni funzionalmente indipendenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione garantisce che siano predisposte le procedure necessarie per produrre e raccogliere i dati necessari alle valutazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione redige un piano di valutazione, che può riguardare più di un programma. Per l’AMIF, l’ISF e il BMVI il piano prevede una valutazione intermedia da completare entro il 31 marzo 2024.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione presenta il piano di valutazione al comitato di sorveglianza entro un anno dalla decisione di approvazione del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Tutte le valutazioni sono pubblicate sul sito web di cui all’articolo 49, paragrafo 1.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Valutazione da parte della Commissione", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione effettua una valutazione intermedia per esaminare l’efficacia, l’efficienza, la rilevanza, la coerenza e il valore aggiunto dell’Unione di ciascun fondo entro la fine del 2024. La Commissione può avvalersi di tutte le informazioni pertinenti già disponibili in conformità dell’articolo 128 del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione effettua una valutazione retrospettiva per esaminare l’efficacia, l’efficienza, la rilevanza, la coerenza e il valore aggiunto dell’Unione di ciascun fondo entro il 31 dicembre 2031. Nel caso del FESR, del FSE+, del Fondo di coesione e del FEAMPA, tale valutazione si concentra in particolare sull’impatto sociale, economico e territoriale di tali fondi in relazione agli obiettivi strategici di cui all’articolo 5, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione pubblica i risultati della valutazione retrospettiva sul proprio sito web e comunica tali risultati al Parlamento europeo, al Consiglio, al Comitato economico e sociale europeo e al Comitato delle regioni.</div>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Visibilità", "anchor": "art_46", "frags": [[null, "<p class=\"norm\">Ciascuno Stato membro garantisce:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la visibilità del sostegno in tutte le attività relative alle operazioni sostenute dai fondi, con particolare attenzione alle operazioni di importanza strategica;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la comunicazione ai cittadini dell’Unione del ruolo e dei risultati conseguiti dai fondi mediante un portale web unico che offra accesso a tutti i programmi che vedono coinvolto lo Stato membro interessato.</p>\n</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Emblema dell’Unione", "anchor": "art_47", "frags": [[null, "<p class=\"norm\">Gli Stati membri, le autorità di gestione e i beneficiari usano l’emblema dell’Unione in conformità dell’allegato IX nello svolgimento di attività di visibilità, trasparenza e comunicazione.</p>"]]}, "48": {"label": "Articolo 48", "heading": "Responsabili della comunicazione e reti di comunicazione", "anchor": "art_48", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro individua un coordinatore della comunicazione per le attività di visibilità, trasparenza e comunicazione in relazione al sostegno a carico dei fondi, anche per programmi compresi nell’obiettivo «Cooperazione territoriale europea» (Interreg) qualora lo Stato membro ospiti l’autorità di gestione. Il coordinatore della comunicazione può essere nominato al livello dell’organismo di cui all’articolo 71, paragrafo 6, e coordina le misure in materia di comunicazione e visibilità tra i programmi.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il coordinatore della comunicazione coinvolge nelle attività di visibilità, trasparenza e comunicazione gli organismi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le rappresentanze della Commissione europea e gli uffici di collegamento del Parlamento europeo negli Stati membri, oltre che i centri di informazione Europe Direct e altre reti pertinenti, organizzazioni di istruzione e di ricerca;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri partner pertinenti di cui all’articolo 8, paragrafo 1.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuna autorità di gestione individua un responsabile della comunicazione per ciascun programma. Un responsabile della comunicazione può essere responsabile di più di un programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione gestisce una rete composta dai coordinatori della comunicazione, dai responsabili della comunicazione e da rappresentanti della Commissione a fini di scambio di informazioni sulle attività di visibilità, trasparenza e comunicazione.</div>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Responsabilità dell’autorità di gestione", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione garantisce che, entro sei mesi dalla decisione di approvazione del programma, sia in funzione un sito web sul quale siano disponibili informazioni sui programmi sotto la sua responsabilità, che presenti gli obiettivi, le attività, le opportunità di finanziamento e i risultati del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione garantisce la pubblicazione sul sito web di cui al paragrafo 1, o sul portale web ‘unico di cui all’articolo 46, lettera b), di un calendario degli inviti a presentare proposte che sono stati pianificati, aggiornato almeno tre volte all’anno, con i dati indicativi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">area geografica interessata dall’invito a presentare proposte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">obiettivo strategico o obiettivo specifico interessato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipologia di richiedenti ammissibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">importo totale del sostegno per l’invito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di apertura e chiusura dell’invito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione mette a disposizione del pubblico l’elenco delle operazioni selezionate per ricevere sostegno dai fondi sul sito web in almeno una delle lingue ufficiali delle istituzioni dell’Unione e aggiorna l’elenco almeno ogni quattro mesi. A ciascuna operazione è attribuito un codice unico. L’elenco contiene gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone giuridiche, il nome del beneficiario e, nel caso di appalti pubblici, del contraente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il beneficiario è una persona fisica, nome e cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le operazioni nell’ambito del FEAMPA relative a un peschereccio, il numero di identificazione nel registro della flotta peschereccia dell’Unione di cui al regolamento di esecuzione (UE) 2017/218 della Commissione (\n<span class=\"superscript\">18</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la denominazione dell’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo scopo dell’operazione e i risultati attesi o conseguiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data di inizio dell’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data prevista o effettiva di completamento dell’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il costo totale dell’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fondo interessato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’obiettivo specifico interessato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il tasso di cofinanziamento dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’indicatore di località o di geolocalizzazione per l’operazione e il paese interessati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le operazioni mobili o che riguardano diverse località, la località del beneficiario se si tratta di una persona giuridica; o la regione a livello NUTS 2 se il beneficiario è una persona fisica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la tipologia di intervento dell’operazione in conformità dell’articolo 73, paragrafo 2, lettera g).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I dati di cui alle lettere b) e c) del primo comma sono rimossi due anni dopo la data della pubblicazione iniziale sul sito.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I dati di cui ai paragrafi 2 e 3 del presente articolo sono pubblicati sul sito web di cui al paragrafo 1 o nel portale web unico di cui all'articolo 46, lettera b) del presente regolamento, in formati aperti e leggibili meccanicamente, come stabilito all’articolo 5, paragrafo 1, della direttiva (UE) 2019/1024 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">19</span>\n), che consentano di ordinare, utilizzare in operazioni di ricerca, estrarre, comparare e riutilizzare i dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Prima della pubblicazione, l’autorità di gestione informa i beneficiari che i dati saranno resi pubblici a norma del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione provvede affinché i materiali inerenti alla comunicazione e alla visibilità, anche a livello di beneficiari, siano, su richiesta, messi a disposizione delle istituzioni, degli organi o organismi dell’Unione, e che all’Unione sia concessa una licenza a titolo gratuito, non esclusiva e irrevocabile che le consenta di utilizzare tali materiali e tutti i diritti preesistenti che ne derivano, in conformità dell’allegato IX. Ciò non comporta costi aggiuntivi significativi o un onere amministrativo rilevante per i beneficiari o per l’autorità di gestione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se è programmato un sostegno per gli obiettivi STEP di cui all'articolo 2 del regolamento (UE) 2024/795, l'autorità di gestione garantisce che tutte le informazioni che devono essere pubblicate conformemente al paragrafo 2 del presente articolo siano anche presentate alla Commissione nel formato di cui al paragrafo 4 del presente articolo ai fini della pubblicazione sul portale della sovranità stabilito a norma dell'articolo 6 del regolamento (UE) 2024/795, insieme a un calendario degli inviti a presentare proposte che sono stati pianificati, aggiornato almeno tre volte all'anno, e, il giorno della loro pubblicazione, al link agli inviti a presentare proposte.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "50": {"label": "Articolo 50", "heading": "Responsabilità dei beneficiari", "anchor": "art_50", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I beneficiari e gli organismi che attuano gli strumenti finanziari riconoscono il sostegno fornito dai fondi all’operazione, comprese le risorse reimpiegate a norma dell’articolo 62, nei modi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornendo, sul sito web, ove tale sito esista, e sui siti di social media ufficiali del beneficiario una breve descrizione dell’operazione, in proporzione al livello del sostegno, compresi le finalità e i risultati, ed evidenziando il sostegno finanziario ricevuto dall’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">apponendo una dichiarazione che ponga in evidenza il sostegno dell’Unione in maniera visibile sui documenti e sui materiali per la comunicazione riguardanti l’attuazione dell’operazione, destinati al pubblico o ai partecipanti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esponendo targhe o cartelloni permanenti chiaramente visibili al pubblico, in cui compare l’emblema dell’Unione conformemente alle caratteristiche tecniche di cui all’allegato IX non appena inizia l’attuazione materiale di operazioni che comportino investimenti materiali o siano installate le attrezzature acquistate, con riguardo a quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operazioni sostenute dal FESR e dal Fondo di coesione il cui costo totale supera 500 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operazioni sostenute dal FSE+, dal JTF, dal FEAMPA, dall’AMIF, dall’ISF o dal BMVI il cui costo totale supera 100 000  EUR;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le operazioni che non rientrano nell’ambito della lettera c), esponendo in un luogo facilmente visibile al pubblico almeno un poster di misura non inferiore a un formato A3 o un display elettronico equivalente recante informazioni sull’operazione che evidenzino il sostegno ricevuto dai fondi; ove sia una persona fisica, il beneficiario garantisce, nella misura del possibile, la disponibilità di informazioni adeguate, che mettano in evidenza il sostegno fornito dai fondi, in un luogo visibile al pubblico o mediante un display elettronico.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per operazioni di importanza strategica e operazioni il cui costo totale supera 10 000 000  EUR, organizzando un evento o un’attività di comunicazione, come opportuno, e coinvolgendo in tempo utile la Commissione e l’autorità di gestione responsabile.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Ove un beneficiario del FSE+ sia una persona fisica, o le operazioni siano sostenute a titolo dell’obiettivo specifico di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+, non si applica la prescrizione di cui al primo comma, lettera d).</p>"], [null, "<p class=\"norm\">In deroga al primo comma, lettere c) e d), per le operazioni sostenute dall’AMIF, dall’ISF e dal BMVI, il documento che specifica le condizioni per il sostegno può stabilire requisiti specifici per l’esposizione pubblica delle informazioni sul sostegno fornito dai fondi ove ciò sia giustificato da ragioni di sicurezza e di ordine pubblico in conformità dell’articolo 69, paragrafo 5.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per i fondi per piccoli progetti, il beneficiario rispetta gli obblighi di cui all’articolo 36, paragrafo 5, del regolamento Interreg.</div>\n</div>"], [null, "<p class=\"norm\">Per gli strumenti finanziari il beneficiario provvede, mediante clausole contrattuali, a che i destinatari finali rispettino le prescrizioni di cui al paragrafo 1, lettera c).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se il beneficiario non rispetta i propri obblighi di cui all’articolo 47 o ai paragrafi 1 e 2 del presente articolo e qualora non siano state poste in essere azioni correttive, l’autorità di gestione applica misure, tenuto conto del principio di proporzionalità, sopprimendo fino al 3 % del sostegno dei fondi all’operazione interessata.</p>\n</div>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Forme di contributo dell’Unione ai programmi", "anchor": "art_51", "frags": [[null, "<p class=\"norm\">Il contributo dell’Unione può assumere una delle forme seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamento non collegato ai costi delle operazioni pertinenti, in conformità dell’articolo 95, e basato su uno degli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il soddisfacimento di condizioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il conseguimento di risultati;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il rimborso del sostegno fornito ai beneficiari in conformità dei capi II e III del presente titolo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">costi unitari in conformità dell’articolo 94 che coprono tutte o determinate categorie specifiche di costi ammissibili, chiaramente individuate in anticipo con riferimento a un importo per unità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">somme forfettarie in conformità dell’articolo 94 che coprono in modo generale tutte o determinate categorie specifiche di costi ammissibili, chiaramente individuate in anticipo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamento a tasso forfettario in conformità dell’articolo 94 o dell’articolo 36, paragrafo 5, che copre categorie specifiche di costi ammissibili, chiaramente individuate in anticipo, applicando una percentuale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una combinazione delle forme di cui alle lettere da a) a e).</p>\n</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Forme di sostegno", "anchor": "art_52", "frags": [[null, "<p class=\"norm\">Gli Stati membri adoperano i contributi dei fondi per fornire ai beneficiari sostegno sotto forma di sovvenzioni, strumenti finanziari o premi o una combinazione di tali modalità.</p>"]]}, "53": {"label": "Articolo 53", "heading": "Forme di sovvenzioni", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le sovvenzioni fornite dagli Stati membri ai beneficiari possono assumere una delle forme seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimborso dei costi ammissibili effettivamente sostenuti da un beneficiario o da un partner privato nelle operazioni PPP e pagati per l’attuazione delle operazioni, contributi in natura e ammortamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">costi unitari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">somme forfettarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti a tasso forfettario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una combinazione delle forme di cui alle lettere da a) a d), a condizione che ciascuna forma copra diverse categorie di costi, o che siano utilizzati per progetti diversi facenti parte di un’operazione o per fasi successive di un’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti non collegati ai costi, purché tali sovvenzioni siano coperte da un rimborso del contributo dell’Unione a norma dell’articolo 95.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il costo totale di un’operazione non supera 200 000  EUR, il contributo fornito al beneficiario dal FESR, dal FSE+, dal JTF, dall’AMIF, dall’ISF e dal BMVI assume la forma di costi unitari, somme forfettarie o tassi forfettari, ad eccezione delle operazioni il cui sostegno configura un aiuto di Stato. Quando si ricorre al finanziamento a tasso forfettario possono essere rimborsate solo le categorie di costi cui si applica il tasso forfettario a norma del paragrafo 1, lettera a).</div>\n</div>"], [null, "<p class=\"norm\">In deroga al primo comma del presente paragrafo, l’autorità di gestione può convenire di esentare dall’obbligo di cui a tale comma alcune operazioni nel settore della ricerca e dell’innovazione, previa approvazione del comitato di sorveglianza. Inoltre le indennità e gli stipendi versati ai partecipanti possono essere rimborsati in conformità del paragrafo 1, lettera a).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli importi delle forme di sovvenzioni di cui alle lettere b), c) e d) del paragrafo 1 sono stabiliti in uno dei modi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un metodo di calcolo giusto, equo e verificabile, basato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">su dati statistici, altre informazioni obiettive o valutazioni di esperti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">su dati storici verificati dei singoli beneficiari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sull’applicazione delle normali prassi di contabilità dei costi dei singoli beneficiari;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progetti di bilancio redatti caso per caso e approvati ex ante dall’organismo che seleziona l’operazione, ove il costo totale dell’operazione non superi 200 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conformemente alle norme di applicazione dei corrispondenti costi unitari, somme forfettarie e tassi forfettari applicabili nelle politiche dell’Unione per tipologie analoghe di operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conformemente alle norme di applicazione dei corrispondenti costi unitari, somme forfettarie e tassi forfettari applicati in meccanismi di sovvenzione finanziati totalmente dallo Stato membro per tipologie analoghe di operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tassi forfettari e metodi specifici previsti dal presente regolamento o dai regolamenti specifici relativi a ciascun fondo o stabiliti sulla base degli stessi.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Finanziamento a tasso forfettario dei costi indiretti in materia di sovvenzioni", "anchor": "art_54", "frags": [[null, "<p class=\"norm\">Se si applica un tasso forfettario per coprire i costi indiretti di un’operazione, esso può basarsi su uno degli elementi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fino al 7 % dei costi diretti ammissibili, nel qual caso lo Stato membro non è tenuto a eseguire un calcolo per determinare il tasso applicabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fino al 15 % dei costi diretti ammissibili per il personale, nel qual caso lo Stato membro non è tenuto a eseguire un calcolo per determinare il tasso applicabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fino al 25 % dei costi diretti ammissibili, a condizione che il tasso sia calcolato in conformità dell’articolo 53, paragrafo 3, lettera a).</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Inoltre, se lo Stato membro ha calcolato un tasso forfettario in conformità dell’articolo 67, paragrafo 5, lettera a), del regolamento (UE) n. 1303/2013, tale tasso fisso può essere utilizzato per un’operazione analoga ai fini della lettera c) del presente articolo.</p>"]]}, "55": {"label": "Articolo 55", "heading": "Costi diretti per il personale in materia di sovvenzioni", "anchor": "art_55", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I costi diretti per il personale di un’operazione possono essere calcolati a un tasso forfettario fino al 20 % dei costi diretti di tale operazione diversi dai costi diretti per il personale, senza che lo Stato membro sia tenuto a eseguire un calcolo per determinare il tasso applicabile, a condizione che i costi diretti dell’operazione non comprendano appalti pubblici di lavori o di forniture o servizi il cui valore superi le soglie stabilite all’articolo 4 della direttiva 2014/24/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">20</span>\n) o all’articolo 15 della direttiva 2014/25/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">21</span>\n).</div>\n</div>"], [null, "<p class=\"norm\">Qualora sia applicato un tasso forfettario conformemente al primo comma per l’AMIF, l’ISF e il BMVI, tale tasso forfettario si applica unicamente ai costi diretti dell’operazione non oggetto di appalto pubblico.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di determinare i costi diretti per il personale si può calcolare una tariffa oraria in uno dei modi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dividendo i più recenti costi del lavoro lordi documentati per il personale, se annui, per 1 720  ore nel caso di lavoro a tempo pieno, o per la corrispondente quota proporzionale a 1 720  ore nel caso di lavoro a tempo parziale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dividendo i più recenti costi del lavoro lordi documentati per il personale, se mensili, per la media delle ore lavorate mensili della persona interessata in conformità delle norme nazionali applicabili menzionate nel contratto di lavoro o di impiego o nella decisione di nomina (denominati atto di impiego).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando si applica la tariffa oraria calcolata in conformità del paragrafo 2, il totale delle ore dichiarate per persona per un dato anno o mese non supera il numero di ore utilizzato per il calcolo della tariffa oraria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora non siano disponibili, i costi del lavoro annui lordi per il personale possono essere desunti dai costi del lavoro lordi per il personale disponibili documentati o dall’atto di impiego, debitamente rapportati a un periodo di dodici mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per le persone che lavorano all’operazione con un incarico a tempo parziale, i costi per il personale possono essere calcolati come percentuale fissa dei costi del lavoro lordi per il personale, corrispondente a una percentuale fissa del tempo di lavoro dedicato all’operazione mensilmente, senza l’obbligo di istituire un sistema separato di registrazione delle ore lavorate. Il datore di lavoro rilascia ai dipendenti un documento che stabilisce tale percentuale fissa.</div>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Finanziamento a tasso forfettario dei costi ammissibili diversi dai costi diretti per il personale in materia di sovvenzioni", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un tasso forfettario fino al 40 % dei costi diretti ammissibili per il personale può essere utilizzato per coprire i costi ammissibili residui di un’operazione. Lo Stato membro non è tenuto a eseguire un calcolo per determinare il tasso applicabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per le operazioni sostenute dal FESR dal FSE+, dal JTF, dall’AMIF, dall’ISF e dal BMVI, e, le retribuzioni e le indennità versate ai partecipanti sono considerate costi ammissibili aggiuntivi non inclusi nel tasso forfettario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il tasso forfettario di cui al paragrafo 1 non si applica ai costi per il personale calcolati in base al tasso forfettario di cui all’articolo 55, paragrafo 1.</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Sovvenzioni soggette a condizioni", "anchor": "art_57", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono prevedere sovvenzioni per i beneficiari soggette a condizioni, da restituire totalmente o parzialmente come precisato nel documento che specifica le condizioni per il sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I rimborsi da parte del beneficiario sono effettuati secondo le condizioni convenute dall’autorità di gestione e dal beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri reimpiegano le risorse restituite dal beneficiario allo stesso scopo o in linea con gli obiettivi del programma pertinente entro il 31 dicembre 2030 sotto forma di sovvenzioni soggette a condizioni o di strumento finanziario o tramite un’altra forma di sostegno. Gli importi restituiti e le informazioni sul loro reimpiego figurano nella relazione finale in materia di performance.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie per garantire che le risorse siano tenute in contabilità separate o con codici contabili appropriati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le risorse dell’Unione restituite in qualsiasi momento dai beneficiari, ma non reimpiegate entro il 31 dicembre 2030 sono restituite al bilancio dell’Unione conformemente all’articolo 88.</div>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Strumenti finanziari", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità di gestione possono fornire contributi di programma, da uno o più programmi, a strumenti finanziari esistenti o nuovi istituiti a livello nazionale, regionale, transnazionale o transfrontaliero e attuati direttamente dall’autorità di gestione, o sotto la sua responsabilità, che contribuiscono al conseguimento di obiettivi specifici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli strumenti finanziari forniscono sostegno ai destinatari finali solo per investimenti in beni materiali e immateriali nonché in capitale circolante, che si prevede siano finanziariamente sostenibili e che non reperiscono finanziamenti sufficienti da fonti di mercato. Tale sostegno è conforme alle norme applicabili dell’Unione in materia di aiuti di Stato.</div>\n</div>"], [null, "<p class=\"norm\">Tale sostegno è fornito solo per gli elementi degli investimenti che non sono materialmente completati o pienamente attuati alla data della decisione di investimento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sostegno opportuno dei fondi erogato mediante strumenti finanziari si basa su una valutazione ex ante redatta sotto la responsabilità dell’autorità di gestione. La valutazione ex ante è completata prima che le autorità di gestione eroghino contributi del programma a strumenti finanziari.</div>\n</div>"], [null, "<p class=\"norm inline-element\">La valutazione ex ante comprende almeno gli elementi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo proposto del contributo del programma a uno strumento finanziario e l’effetto leva stimato, accompagnati da una breve giustificazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i prodotti finanziari che si propone di offrire, compresa l’eventuale necessità di trattamento differenziato degli investitori;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il gruppo proposto di destinatari finali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo previsto dello strumento finanziario al conseguimento di obiettivi specifici.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La valutazione ex ante può essere riveduta o aggiornata, può riguardare una parte o l’intero territorio dello Stato membro, e può basarsi su valutazioni ex ante esistenti o aggiornate.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sostegno ai destinatari finali può essere combinato con il sostegno da qualsiasi fondo o altro strumento dell’Unione, e può riguardare la stessa voce di spesa. In tale caso il sostegno del fondo erogato a titolo dello strumento finanziario, che fa parte di un’operazione di strumenti finanziari, non è dichiarato alla Commissione al fine di ricevere sostegno in un’altra forma, da un altro fondo o da un altro strumento dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli strumenti finanziari possono essere combinati con un sostegno del programma sotto forma di sovvenzioni in una singola operazione di strumenti finanziari, all’interno di un unico accordo di finanziamento, nel quale le due forme distinte di sostegno sono erogate dall’organismo che attua lo strumento finanziario. In tal caso le regole applicabili agli strumenti finanziari si applicano a tale singola operazione di strumenti finanziari. Il sostegno del programma sotto forma di sovvenzioni è collegato direttamente allo strumento finanziario e necessario per lo stesso, e non supera il valore degli investimenti sostenuti dal prodotto finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Nel caso di sostegno combinato di cui ai paragrafi 4 e 5, si tiene una contabilità separata per ciascuna fonte di sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La somma di tutte le forme di sostegno combinato non supera l’importo totale della voce di spesa interessata. Le sovvenzioni non sono usate per rimborsare sostegno ricevuto da strumenti finanziari. Gli strumenti finanziari non sono usati per prefinanziare sovvenzioni.</div>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Attuazione degli strumenti finanziari", "anchor": "art_59", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli strumenti finanziari attuati direttamente dall’autorità di gestione possono fornire solo prestiti o garanzie. L’autorità di gestione stabilisce i termini e le condizioni dei contributi del programma allo strumento finanziario in un documento strategico che comprenda tutti gli elementi indicati nell’allegato X.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli strumenti finanziari attuati sotto la responsabilità dell’autorità di gestione possono consistere in una delle forme seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">investimento di risorse del programma nel capitale di una persona giuridica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">blocchi separati di conti finanziari o fiduciari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">L’autorità di gestione seleziona l’organismo che attua uno strumento finanziario.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione può procedere all’aggiudicazione diretta di un contratto per l’attuazione di uno strumento finanziario:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla BEI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a una banca o a un istituto di proprietà dello Stato costituiti come entità giuridiche che svolgono attività finanziarie su base professionale e soddisfano tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non vi è alcuna partecipazione diretta di capitali privati, a eccezione di forme di partecipazione di capitali privati prescritte dalle disposizioni legislative nazionali, in conformità dei trattati, che non comportano controllo o potere di veto né consentono l’esercizio di un’influenza determinante sulla banca o sull’istituto in questione, e a eccezione di forme di partecipazione di capitali privati che non conferiscono alcuna influenza sulle decisioni riguardanti la gestione corrente dello strumento finanziario sostenuto dai fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operano con un mandato pubblico, conferito dall’autorità competente di uno Stato membro a livello nazionale o regionale, che comprende, come parte o totalità dei loro compiti, lo svolgimento di attività di sviluppo economico che contribuiscono agli obiettivi dei fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolgono, come parte o totalità dei loro compiti, attività di sviluppo economico che contribuiscono agli obiettivi dei fondi in regioni, settori o ambiti strategici per i quali l’accesso ai finanziamenti da fonti di mercato non è generalmente disponibile o sufficiente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operano senza l’obiettivo primario di massimizzare i profitti, ma garantiscono la sostenibilità finanziaria a lungo termine delle loro attività;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantiscono che l’aggiudicazione diretta di un contratto di cui alla lettera b) non accordi alcun vantaggio diretto o indiretto ad attività commerciali attraverso misure adeguate conformemente al diritto applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono soggetti alla vigilanza di un’autorità indipendente conformemente al diritto applicabile;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri organismi, anche rientranti nell’ambito di applicazione dell’articolo 12 della direttiva 2014/24/UE.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se l’organismo selezionato dall’autorità di gestione attua un fondo di partecipazione, tale organismo può procedere a sua volta alla selezione di altri organismi per attuare fondi specifici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I termini e le condizioni dei contributi dei programmi a strumenti finanziari attuati in conformità del paragrafo 2 sono stabiliti in accordi di finanziamento tra:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i rappresentanti debitamente autorizzati dell’autorità di gestione e l’organismo che attua un fondo di partecipazione, se applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i rappresentanti debitamente autorizzati dell’autorità di gestione o, ove applicabile, dell’organismo che attua un fondo di partecipazione e l’organismo che attua un fondo specifico.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli accordi di finanziamento comprendono tutti gli elementi indicati nell’allegato X.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La responsabilità finanziaria dell’autorità di gestione non supera l’importo impegnato dall’autorità di gestione a favore dello strumento finanziario nell’ambito del pertinente accordo di finanziamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli organismi che attuano gli strumenti finanziari interessati, o, nel contesto di garanzie, l’organismo che fornisce i prestiti sottostanti, sostengono i destinatari finali, tenendo in debito conto gli obiettivi del programma e la potenziale autosufficienza finanziaria dell’investimento, come spiegata nel piano economico o in un documento equivalente. La selezione dei destinatari finali è trasparente e non dà luogo a conflitti di interessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il cofinanziamento nazionale di un programma può essere fornito dall’autorità di gestione o a livello di fondi di partecipazione, o a livello di fondi specifici, o a livello di investimenti a favore dei destinatari finali, in conformità delle norme specifiche di ciascun fondo. Se il cofinanziamento nazionale è fornito a livello di investimenti a favore dei destinatari finali, l’organismo che attua gli strumenti finanziari conserva le prove documentali che dimostrano l’ammissibilità delle spese sottostanti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione che attua direttamente lo strumento finanziario a norma del paragrafo 1 del presente articolo, o l’organismo che attua lo strumento finanziario a norma del paragrafo 2 del presente articolo, tengono contabilità separate o adottano un codice contabile per ciascuna priorità o, nel caso del FEAMPA, ciascun obiettivo specifico e, ove applicabile, ciascuna categoria di regioni per ciascun contributo del programma, e osservano la stessa distinzione per le risorse indicate rispettivamente agli articoli 60 e 62.</div>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Interessi e altre plusvalenze generate dal sostegno dei fondi agli strumenti finanziari", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sostegno erogato dai fondi agli strumenti finanziari è depositato su conti presso istituti finanziari domiciliati negli Stati membri ed è gestito secondo le regole della gestione attiva della tesoreria e il principio della sana gestione finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli interessi e le altre plusvalenze imputabili al sostegno dei fondi erogato a strumenti finanziari sono utilizzati per lo stesso obiettivo o gli stessi obiettivi del sostegno iniziale fornito dai fondi, compreso per il pagamento delle commissioni di gestione e il rimborso dei costi di gestione sostenuti dagli organismi che attuano lo strumento finanziario conformemente all’articolo 68, paragrafo 1, lettera d), nello stesso strumento finanziario oppure, se lo strumento finanziario è stato liquidato, in altri strumenti finanziari o altre forme di sostegno per ulteriori investimenti a favore di destinatari finali fino alla fine del periodo di ammissibilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli interessi e le altre plusvalenze di cui al paragrafo 2 non utilizzati in conformità di detta disposizione sono detratti dalla contabilità presentata per il periodo contabile finale.</div>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Trattamento differenziato degli investitori", "anchor": "art_61", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sostegno dei fondi a strumenti finanziari investiti a favore di destinatari finali e qualsiasi tipo di entrate generate da tali investimenti, comprese le risorse restituite, imputabili al sostegno dei fondi, possono essere utilizzati per il trattamento differenziato degli investitori che operano secondo il principio dell’economia di mercato mediante un’opportuna condivisione di rischi e profitti, tenendo conto del principio della sana gestione finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il livello di tale trattamento differenziato non supera quanto necessario per creare incentivi al fine di attrarre risorse private, accertato mediante un procedimento competitivo o una valutazione indipendente.</div>\n</div>"]]}, "62": {"label": "Articolo 62", "heading": "Reimpiego delle risorse imputabili al sostegno dei fondi", "anchor": "art_62", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le risorse restituite, prima della fine del periodo di ammissibilità, agli strumenti finanziari, provenienti da investimenti a favore di destinatari finali o dallo sblocco delle risorse accantonate per i contratti di garanzia, compresi i rimborsi di capitale e qualsiasi tipo di entrate generate imputabili al sostegno dei fondi, sono reimpiegate negli stessi strumenti finanziari o in altri per ulteriori investimenti a favore di destinatari finali, per coprire le perdite rispetto all’importo nominale del contributo dei fondi allo strumento finanziario risultante da interessi negativi, se tali perdite si verificano nonostante la gestione attiva della tesoreria, o da commissioni e costi di gestione associati a tali ulteriori investimenti, tenendo conto del principio della sana gestione finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le risorse di cui al paragrafo 1 restituite agli strumenti finanziari durante un periodo di almeno otto anni dopo la fine del periodo di ammissibilità siano reimpiegate in conformità degli obiettivi strategici del programma o dei programmi per i quali erano stati costituiti gli strumenti finanziari, nello stesso strumento finanziario o, in seguito al disimpegno di tali risorse dallo strumento finanziario, in altri strumenti finanziari o in altre forme di sostegno.</div>\n</div>"]]}, "63": {"label": "Articolo 63", "heading": "Ammissibilità", "anchor": "art_63", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ammissibilità delle spese è determinata in base a regole nazionali, salvo se regole specifiche sono previste nel presente regolamento o nei regolamenti specifici relativi ai fondi, o in base agli stessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le spese sono ammissibili al contributo dei fondi se sono state sostenute da un beneficiario o dal partner privato di un’operazione PPP e pagate per l’attuazione di operazioni tra la data di presentazione del programma alla Commissione, o il 1<span class=\"superscript\">o</span> gennaio 2021 se anteriore, e il 31 dicembre 2029.</div>\n</div>"], [null, "<p class=\"norm\">Per i costi rimborsati a norma dell’articolo 53, paragrafo 1, lettere b), c) e f), le azioni che costituiscono la base per il rimborso sono attuate tra la data di presentazione del programma alla Commissione, o il 1<span class=\"superscript\">o</span> gennaio 2021 se anteriore, e il 31 dicembre 2029.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per il FESR le spese relative a operazioni che riguardano più di una categoria di regioni come previsto all’articolo 108, paragrafo 2, di uno Stato membro sono assegnate alle categorie di regioni interessate su base proporzionale, secondo criteri obiettivi.</div>\n</div>"], [null, "<p class=\"norm\">Per il FSE+ le spese relative a operazioni possono essere assegnate a qualsiasi categoria di regioni del programma a condizione che l’operazione contribuisca al conseguimento degli obiettivi specifici del programma.</p>"], [null, "<p class=\"norm\">Per il JTF le spese relative a operazioni contribuiscono all’attuazione del pertinente piano territoriale per una transizione giusta.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un’operazione può essere attuata integralmente o parzialmente al di fuori di uno Stato membro, come anche al di fuori dell’Unione, a condizione che essa contribuisca al conseguimento degli obiettivi del programma</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per le sovvenzioni che assumono le forme di cui all’articolo 53, paragrafo 1, lettere b), c) e d), le spese ammissibili al contributo dei fondi sono pari agli importi calcolati in conformità dell’articolo 53, paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Non sono selezionate per ricevere sostegno dai fondi le operazioni materialmente completate o pienamente attuate prima che sia stata presentata la domanda di finanziamento a titolo del programma, a prescindere dal fatto che tutti i relativi pagamenti siano stati effettuati o meno. Il presente paragrafo non si applica all’indennizzo per i costi aggiuntivi nelle regioni ultra periferiche nel quadro del FEAMPA a norma dell’articolo 24 del regolamento FEAMPA, né al sostegno fornito tramite i finanziamenti supplementari per le regioni ultra periferiche a norma dell’articolo 110, paragrafo 1, lettera e), del presente regolamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">Il primo comma del presente paragrafo non si applica al sostegno fornito alle azioni di solidarietà quali definite all’articolo 2, punto 15), del regolamento AMIF e all’articolo 2, punto 11), del regolamento BMVI.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le spese che diventano ammissibili in seguito a una modifica del programma sono ammissibili dalla data di presentazione della corrispondente domanda alla Commissione.</div>\n</div>"], [null, "<p class=\"norm\">Per il FESR, il Fondo di coesione e il JTF le spese diventano ammissibili in seguito a una modifica del programma che si verifica quando è aggiunta al programma una nuova tipologia di intervento di cui alla tabella 1 dell’allegato I oppure, per il FEAMPA, per l’AMIF, l’ISF e il BMVI, nei regolamenti specifici relativi ai fondi.</p>"], [null, "<p class=\"norm\">Se un programma è modificato per dare risposta a una catastrofe naturale, il programma può prevedere che l’ammissibilità delle spese relative a tale modifica decorra dalla data in cui si è verificata la catastrofe naturale.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">Se un programma è modificato per introdurre un sostegno finanziario alle azioni di solidarietà quali definite all’articolo 2, punto 15), del regolamento AMIF e all’articolo 2, punto 11), del regolamento BMVI, il programma può prevedere che l’ammissibilità delle spese relative a tale modifica decorra dall’11 giugno 2024.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Quando è approvato un nuovo programma, le spese sono ammissibili dalla data di presentazione della corrispondente domanda alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un’operazione può ricevere sostegno da uno o più fondi o da uno o più programmi e da altri strumenti dell’Unione. In tali casi le spese dichiarate nella domanda di pagamento di uno dei fondi non devono essere dichiarate in uno dei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostegno a carico di un altro fondo o strumento dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostegno a carico dello stesso fondo a titolo di un altro programma.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">L’importo delle spese da indicare nella domanda di pagamento di un fondo può essere calcolato per ciascun fondo e per il programma o i programmi interessati su base proporzionale conformemente al documento che specifica le condizioni per il sostegno.</p>"]]}, "64": {"label": "Articolo 64", "heading": "Costi non ammissibili", "anchor": "art_64", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I seguenti costi non sono ammissibili al contributo dei fondi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli interessi passivi, a eccezione di quelli relativi a sovvenzioni concesse sotto forma di abbuono di interessi o di commissioni di garanzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’acquisto di terreni per un importo superiore al 10 % delle spese totali ammissibili dell’operazione interessata; per i siti in stato di degrado e per quelli precedentemente adibiti a uso industriale che comprendono edifici, tale limite è aumentato al 15 %; per gli strumenti finanziari, le percentuali indicate si applicano al contributo del programma versato al destinatario finale o, nel caso delle garanzie, all’importo del prestito sottostante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’imposta sul valore aggiunto («IVA») salvo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le operazioni il cui costo totale è inferiore a 5 000 000  EUR (IVA inclusa);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le operazioni il cui costo totale è pari ad almeno 5 000 000  EUR (IVA inclusa) nei casi in cui non sia recuperabile a norma della legislazione nazionale sull’IVA;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli investimenti realizzati dai destinatari finali nel contesto degli strumenti finanziari; se tali investimenti sono sostenuti da strumenti finanziari combinati con un sostegno del programma sotto forma di sovvenzioni di cui all’articolo 58, paragrafo 5, l’IVA non è ammissibile per la parte del costo dell’investimento corrispondente al sostegno del programma sotto forma di sovvenzioni, a meno che l’IVA per il costo dell’investimento non sia recuperabile a norma della legislazione nazionale sull’IVA o se la parte del costo dell’investimento corrispondente al sostegno del programma sotto forma di sovvenzioni è inferiore a 5 000 000  EUR (IVA inclusa);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i fondi per piccoli progetti e per gli investimenti effettuati dai destinatari finali nel contesto di fondi per piccoli progetti a titolo di Interreg.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La lettera b) del primo comma non si applica alle operazioni relative alla conservazione dell’ambiente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I regolamenti specifici relativi a ciascun fondo possono individuare ulteriori costi non ammissibili al contributo del fondo.</div>\n</div>"]]}, "65": {"label": "Articolo 65", "heading": "Stabilità delle operazioni", "anchor": "art_65", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro restituisce il contributo dei fondi a un’operazione che comporta investimenti in infrastrutture o investimenti produttivi, se entro cinque anni dal pagamento finale al beneficiario o entro il termine stabilito nella normativa sugli aiuti di Stato, ove applicabile, si verifica quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cessazione o trasferimento di un’attività produttiva al di fuori della regione di livello NUTS 2 in cui ha ricevuto sostegno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cambio di proprietà di un’infrastruttura che procuri un vantaggio indebito a un’impresa o a un organismo di diritto pubblico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">modifica sostanziale che alteri la natura, gli obiettivi o le condizioni di attuazione dell’operazione, con il risultato di comprometterne gli obiettivi originari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro può ridurre il termine definito al primo comma a tre anni, nei casi relativi al mantenimento degli investimenti o dei posti di lavoro creati dalle PMI.</p>"], [null, "<p class=\"norm\">Il rimborso da parte dello Stato membro dovuto al mancato rispetto del presente articolo è effettuato in proporzione del periodo di non conformità.</p>"], [null, "<p class=\"modref\">\n▼C2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le operazioni sostenute dal FSE+ o dal JTF in conformità dell’articolo 8, paragrafo 2, lettere k), l) e m) del regolamento JTF restituiscono il sostegno se sono soggette all’obbligo di mantenimento degli investimenti ai sensi della normativa sugli aiuti di Stato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I paragrafi 1 e 2 non si applicano a contributi del programma a favore o da parte di strumenti finanziari oppure a operazioni per le quali si verifichi la cessazione di un’attività produttiva a causa di un fallimento non fraudolento.</div>\n</div>"]]}, "66": {"label": "Articolo 66", "heading": "Delocalizzazione", "anchor": "art_66", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le spese a sostegno di una delocalizzazione non sono ammissibili al contributo dei fondi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se un contributo dei fondi configura un aiuto di Stato, l’autorità di gestione si accerta che il contributo non fornisca sostegno a una delocalizzazione in conformità dell’articolo 14, paragrafo 16, del regolamento (UE) n. 651/2014.</div>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Regole specifiche di ammissibilità in materia di sovvenzioni", "anchor": "art_67", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I contributi in natura sotto forma di forniture di opere, beni, servizi, terreni e immobili in relazione ai quali non è stato effettuato alcun pagamento giustificato da fatture o documenti di valore probatorio equivalente possono essere considerati ammissibili a condizione che siano soddisfatte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sostegno pubblico a favore dell’operazione che comprende contributi in natura non supera il totale delle spese ammissibili, esclusi i contributi in natura, al termine dell’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il valore attribuito ai contributi in natura non supera i costi generalmente accettati sul mercato in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il valore e la fornitura dei contributi in natura possono essere valutati e verificati in modo indipendente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso di terreni o immobili, può essere eseguito un pagamento ai fini di un contratto di locazione per un importo nominale annuo non superiore a una singola unità della valuta dello Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso di contributi in natura sotto forma di prestazione di lavoro non retribuita, il valore di tale prestazione è stabilito tenendo conto del tempo impiegato verificato e del tasso di remunerazione per una prestazione di lavoro equivalente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il valore dei terreni o immobili di cui al primo comma, lettera d), del presente paragrafo è certificato da un esperto qualificato e indipendente o da un organismo ufficiale debitamente autorizzato e non supera il limite di cui all’articolo 64, paragrafo 1, lettera b).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le spese di ammortamento per le quali non è stato effettuato alcun pagamento giustificato da fatture possono essere considerate ammissibili a condizione che siano soddisfatte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ciò è consentito dalle regole del programma in materia di ammissibilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo della spesa è debitamente giustificato da documenti giustificativi con valore probatorio equivalente alle fatture per costi ammissibili, se tali costi sono rimborsati nella forma di cui all’articolo 53, paragrafo 1, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i costi si riferiscono esclusivamente al periodo di sostegno all’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’acquisto dei beni ammortizzati non hanno contribuito sovvenzioni pubbliche.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "68": {"label": "Articolo 68", "heading": "Regole specifiche di ammissibilità in materia di strumenti finanziari", "anchor": "art_68", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le spese ammissibili di uno strumento finanziario sono costituite dall’importo totale del contributo del programma erogato allo strumento finanziario, oppure, nel caso di garanzie, accantonato per i contratti di garanzia dallo strumento finanziario, nel periodo di ammissibilità, e tale importo corrisponde:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai pagamenti ai destinatari finali, nel caso di prestiti e investimenti azionari o quasi azionari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle risorse accantonate per i contratti di garanzia, in essere o già giunti a scadenza, al fine di onorare eventuali attivazioni delle garanzie per perdite, calcolate in base al coefficiente di moltiplicazione stabilito per i rispettivi nuovi prestiti o investimenti azionari o quasi azionari sottostanti erogati a favore dei destinatari finali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai pagamenti versati ai destinatari finali o a loro beneficio, qualora gli strumenti finanziari siano combinati con altri contributi dell’Unione come singola operazione di strumenti finanziari in conformità dell’articolo 58, paragrafo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai pagamenti di commissioni di gestione e al rimborso dei costi di gestione sostenuti dagli organismi che attuano lo strumento finanziario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando uno strumento finanziario è attuato in più periodi di programmazione consecutivi, il sostegno può essere fornito ai destinatari finali, o a loro beneficio, inclusi costi e commissioni di gestione, sulla base degli accordi conclusi nel periodo di programmazione precedente, purché tale sostegno rispetti le regole di ammissibilità del periodo di programmazione successivo. In tali casi, l’ammissibilità delle spese presentate nelle domande di pagamento è determinata conformemente alle regole del rispettivo periodo di programmazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, lettera b), se il soggetto che beneficia delle garanzie non ha erogato l’importo pianificato di nuovi prestiti, investimenti azionari o quasi-azionari a favore dei destinatari finali secondo il coefficiente di moltiplicazione, le spese ammissibili sono proporzionalmente ridotte. Il coefficiente di moltiplicazione può essere riveduto se ciò è giustificato da cambiamenti successivi delle condizioni di mercato. Tale revisione non ha effetto retroattivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, lettera d), le commissioni di gestione dipendono dalla performance.</div>\n</div>"], [null, "<p class=\"norm\">Se gli organismi che attuano un fondo di partecipazione sono selezionati tramite aggiudicazione diretta di un contratto a norma dell’articolo 59, paragrafo 3, l’importo dei costi e delle commissioni di gestione versati a tali organismi che possono essere dichiarati spese ammissibili è soggetto a una soglia fino al 5 % dell’importo totale dei contributi del programma erogati ai destinatari finali in prestiti o accantonati per contratti di garanzia e fino al 7 % dell’importo totale dei contributi del programma erogati ai destinatari finali in investimenti azionari o quasi azionari.</p>"], [null, "<p class=\"norm\">Se gli organismi che attuano un fondo specifico sono selezionati tramite aggiudicazione diretta di un contratto a norma dell’articolo 59, paragrafo 3, l’importo dei costi e delle commissioni di gestione versati a tali organismi che possono essere dichiarati spese ammissibili è soggetto a una soglia fino al 7 % dell’importo totale dei contributi del programma erogati ai destinatari finali in prestiti o accantonati per contratti di garanzia e fino al 15 % dell’importo totale dei contributi del programma erogati ai destinatari finali in investimenti azionari o quasi azionari.</p>"], [null, "<p class=\"norm\">Se gli organismi che attuano un fondo di partecipazione o fondi specifici, o entrambi, sono selezionati tramite procedura competitiva in conformità del diritto applicabile, l’importo dei costi e delle commissioni di gestione è stabilito nell’accordo di finanziamento e rispecchia il risultato della procedura competitiva.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se le commissioni di istruttoria, o parte di esse, sono a carico dei destinatari finali, esse non sono dichiarate come spese ammissibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le spese ammissibili dichiarate in conformità del paragrafo 1 non superano la somma dell’importo totale del sostegno a carico dei fondi pagato ai fini di detto paragrafo e del corrispondente cofinanziamento nazionale.</div>\n</div>"]]}, "69": {"label": "Articolo 69", "heading": "Responsabilità degli Stati membri", "anchor": "art_69", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri dispongono di sistemi di gestione e controllo dei loro programmi in conformità del presente titolo e ne garantiscono il funzionamento secondo il principio della sana gestione finanziaria e i requisiti fondamentali elencati nell’allegato XI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri assicurano la legittimità e regolarità delle spese incluse nei conti presentati alla Commissione e adottano tutte le azioni necessarie per prevenire, individuare, rettificare e segnalare le irregolarità, comprese le frodi. Tali azioni comprendono la raccolta di informazioni sui titolari effettivi dei destinatari dei finanziamenti dell’Unione conformemente all’allegato XVII. Le norme relative alla raccolta e al trattamento di tali dati sono conformi alle norme applicabili in materia di protezione dei dati. La Commissione, l’Ufficio europeo per la lotta antifrode e la Corte dei conti hanno l’accesso di cui hanno bisogno a tali informazioni.</div>\n</div>"], [null, "<p class=\"norm\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI, gli obblighi relativi alla raccolta di informazioni sui titolari effettivi dei destinatari dei finanziamenti dell’Unione conformemente all’allegato XVII di cui al primo comma si applicano a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2023.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Su richiesta della Commissione, gli Stati membri adottano le azioni necessarie per assicurare il funzionamento efficace dei propri sistemi di gestione e controllo e la legittimità e regolarità delle spese presentate alla Commissione. Se l’azione consiste in un audit, possono parteciparvi funzionari o rappresentanti autorizzati della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri assicurano la qualità, l’accuratezza e l’affidabilità del sistema di sorveglianza e dei dati riguardanti gli indicatori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono la pubblicazione delle informazioni conformemente alle prescrizioni stabilite nel presente regolamento e nei regolamenti specifici relativi ai fondi, tranne quando il diritto dell’Unione o quello nazionale escludono la pubblicazione per ragioni di sicurezza, ordine pubblico, indagini penali o protezione dei dati personali in conformità del regolamento (UE) 2016/679.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri dispongono di sistemi e procedure atti ad assicurare che tutti i documenti necessari per la pista di controllo, di cui all’allegato XIII, siano conservati in conformità delle prescrizioni di cui all’articolo 82.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano disposizioni atte ad assicurare l’esame efficace delle denunce riguardanti i fondi. La definizione della portata, delle norme e delle procedure relative a tali modalità compete agli Stati membri conformemente ai relativi quadri istituzionali e giuridici. Ciò non pregiudica la possibilità generalmente prevista per i cittadini e i portatori di interesse di presentare denunce alla Commissione. Su richiesta della Commissione, gli Stati membri esaminano le denunce presentate alla Commissione che rientrano nell’ambito di applicazione dei loro programmi e informano la Commissione dei risultati di tali esami.</div>\n</div>"], [null, "<p class=\"norm\">Ai fini del presente articolo si intende per denuncia qualsiasi controversia tra beneficiari potenziali e selezionati in relazione alle operazioni proposte o selezionate e qualsiasi controversia con terzi in merito all’attuazione del programma o delle relative operazioni, a prescindere dalla classificazione dei mezzi di ricorso previsti dal diritto nazionale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono che tutti gli scambi di informazioni tra i beneficiari e le autorità del programma siano effettuati mediante sistemi elettronici per lo scambio di dati in conformità dell’allegato XIV.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri promuovono i vantaggi dello scambio di dati in formato elettronico e forniscono ai beneficiari tutto il sostegno necessario a questo riguardo.</p>"], [null, "<p class=\"norm\">In deroga al primo comma, l’autorità di gestione può accettare, in via eccezionale, su esplicita richiesta del beneficiario, scambi di informazioni in formato cartaceo, fermo restando il suo obbligo di registrare e conservare i dati in conformità dell’articolo 72, paragrafo 1, lettera e).</p>"], [null, "<p class=\"norm\">Per i programmi sostenuti dal FEAMPA, dall’AMIF, dall’ISF e dal BMVI, il primo comma si applica dal 1<span class=\"superscript\">o</span> gennaio 2023.</p>"], [null, "<p class=\"norm\">Il primo comma non si applica ai programmi o alle priorità di cui all’articolo 4, paragrafo 1, lettera m), del regolamento FSE+.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono che tutti gli scambi ufficiali di informazioni con la Commissione siano effettuati mediante un sistema elettronico per lo scambio di dati in conformità dell’allegato XV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Lo Stato membro garantisce o provvede a che le autorità di gestione forniscano previsioni dell’importo delle domande di pagamento intermedio che saranno presentate nell’anno civile in corso e in quello successivo entro il 31 gennaio e il 31 luglio in conformità dell’allegato VIII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Almeno al momento della presentazione della domanda di pagamento finale per il primo periodo contabile e non oltre il 30 giugno 2023, ciascuno Stato membro dispone di una descrizione del sistema di gestione e controllo in conformità del modello riportato nell’allegato XVI. Esso tiene aggiornata detta descrizione per rispecchiare tutte le modifiche successive.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Gli Stati membri segnalano le irregolarità conformemente ai criteri per determinare i casi di irregolarità da segnalare, i dati da fornire e il formato della segnalazione stabiliti all’allegato XII.</div>\n</div>"]]}, "70": {"label": "Articolo 70", "heading": "Poteri e responsabilità della Commissione", "anchor": "art_70", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione si accerta che gli Stati membri dispongano di sistemi di gestione e controllo conformi al presente regolamento e che tali sistemi funzionino in maniera efficace ed efficiente durante l’attuazione dei programmi. Ai fini delle proprie attività di audit, la Commissione redige una strategia di audit e un piano di audit basati sulla valutazione dei rischi.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione e le autorità di audit coordinano i propri piani di audit.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione effettua audit fino a tre anni civili dopo l’accettazione dei conti in cui erano state incluse le spese in questione. Tale periodo non si applica alle operazioni per le quali esiste un sospetto di frode.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini dei loro audit i funzionari o i rappresentanti autorizzati della Commissione hanno accesso a tutti i necessari registri, documenti e metadati, a prescindere dal supporto sul quale sono conservati, relativi alle operazioni sostenute dai fondi o ai sistemi di gestione e controllo e ricevono copie nel formato specifico richiesto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Agli audit in loco si applica anche quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione fornisce all’autorità competente per il programma un preavviso di almeno 15 giorni lavorativi prima dell’audit, salvo in casi urgenti; a tali audit possono partecipare funzionari o rappresentanti autorizzati dello Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’applicazione di disposizioni nazionali riserva determinati atti all’esame di agenti designati specificamente dalla legislazione nazionale, i funzionari e rappresentanti autorizzati della Commissione hanno accesso alle informazioni così raccolte, fatte salve le competenze degli organi giurisdizionali nazionali e nel pieno rispetto dei diritti fondamentali dei soggetti giuridici interessati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione trasmette le conclusioni preliminari dell’audit all’autorità competente dello Stato membro non oltre tre mesi dopo l’ultimo giorno dell’audit;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione trasmette la relazione di audit non oltre tre mesi dalla data in cui ha ricevuto una risposta completa dall’autorità competente dello Stato membro alle conclusioni preliminari dell’audit; se entro due mesi dalla data di ricevimento della risposta dello Stato membro la Commissione non chiede di fornire ulteriori informazioni o un documento riveduto, la risposta è considerata completa.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Al fine di rispettare i termini stabiliti al primo comma, lettere c) e d), del presente paragrafo, la Commissione mette a disposizione le conclusioni preliminari dell’audit e la relazione di audit in almeno una delle lingue ufficiali delle istituzioni dell’Unione.</p>"], [null, "<p class=\"norm\">I termini di cui al primo comma, lettere c) e d), del presente paragrafo possono essere prorogati ove sia ritenuto necessario e previo accordo tra la Commissione e l’autorità competente dello Stato membro.</p>"], [null, "<p class=\"norm\">Se è stato stabilito un termine per una risposta dello Stato membro alle conclusioni preliminari dell’audit o alla relazione di audit di cui al primo comma, lettere c) e d), del presente paragrafo, tale termine decorre dal momento in cui l’autorità competente dello Stato membro le riceve in almeno una delle lingue ufficiali dello Stato membro interessato.</p>"]]}, "71": {"label": "Articolo 71", "heading": "Autorità del programma", "anchor": "art_71", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini dell’articolo 63, paragrafo 3, del regolamento finanziario lo Stato membro individua per ciascun programma un’autorità di gestione e un’autorità di audit. Se uno Stato membro affida la funzione contabile a un organismo diverso dall’autorità di gestione in conformità dell’articolo 72, paragrafo 2, del presente regolamento, l’organismo in questione è altresì individuato come autorità del programma. Le stesse autorità possono essere responsabili di più di un programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’autorità di audit è un’autorità pubblica. Le attività di audit possono essere svolte da un organismo pubblico o privato diverso dall’autorità di audit, sotto la responsabilità di quest’ultima. L’autorità di audit e gli eventuali organismi che svolgono le attività di audit sotto la responsabilità dell’autorità di audit sono funzionalmente indipendenti dai soggetti sottoposti all’audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione può individuare uno o più organismi intermedi che svolgano determinati compiti sotto la sua responsabilità. Gli accordi tra l’autorità di gestione e gli organismi intermedi sono registrati per iscritto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri assicurano che sia rispettato il principio della separazione delle funzioni tra le autorità del programma e all’interno di queste.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se, in linea con i suoi obiettivi, un programma fornisce sostegno a titolo del FESR o del FSE+ a un programma cofinanziato da Orizzonte Europa, di cui all’articolo 10, paragrafo 1, lettera b), del regolamento Orizzonte Europa, l’organismo che attua il programma cofinanziato da Orizzonte Europa è individuato come organismo intermedio dall’autorità di gestione del programma pertinente, in conformità del paragrafo 3 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro, di propria iniziativa, può istituire un organismo di coordinamento che mantenga i contatti con la Commissione, le fornisca informazioni e coordini le attività delle autorità del programma in tale Stato membro.</div>\n</div>"]]}, "72": {"label": "Articolo 72", "heading": "Funzioni dell’autorità di gestione", "anchor": "art_72", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione è responsabile della gestione del programma allo scopo di conseguire gli obiettivi del programma. Essa ha in particolare le funzioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">selezionare le operazioni in conformità dell’articolo 73, ad eccezione delle operazioni di cui all’articolo 33, paragrafo 3, lettera d);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolgere i compiti di gestione del programma in conformità dell’articolo 74;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere il lavoro del comitato di sorveglianza in conformità dell’articolo 75;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">supervisionare gli organismi intermedi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">registrare e conservare elettronicamente i dati relativi a ciascuna operazione necessari a fini di sorveglianza, valutazione, gestione finanziaria, verifica e audit in conformità dell’allegato XVII e assicurare la sicurezza, l’integrità e la riservatezza dei dati e l’autenticazione degli utenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può affidare la funzione contabile di cui all’articolo 76 all’autorità di gestione o ad un altro organismo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI la funzione contabile è esercitata dall’autorità di gestione o sotto la sua responsabilità.</div>\n</div>"]]}, "73": {"label": "Articolo 73", "heading": "Selezione delle operazioni da parte dell’autorità di gestione", "anchor": "art_73", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per la selezione delle operazioni l’autorità di gestione stabilisce e applica criteri e procedure non discriminatori e trasparenti, garantisce l’accessibilità per le persone con disabilità, garantisce la parità di genere e tiene conto della Carta dei diritti fondamentali dell’Unione europea, del principio dello sviluppo sostenibile e della politica dell’Unione in materia ambientale in conformità dell’articolo 11 e dell’articolo 191, paragrafo 1, TFUE.</div>\n</div>"], [null, "<p class=\"norm\">I criteri e le procedure assicurano che le operazioni da selezionare siano definite in base alla priorità al fine di massimizzare il contributo del finanziamento dell’Unione al conseguimento degli obiettivi del programma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nella selezione delle operazioni l’autorità di gestione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le operazioni selezionate siano conformi al programma, ivi compresa la loro coerenza con le pertinenti strategie alla base del programma, e forniscano un contributo efficace al conseguimento degli obiettivi specifici del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le operazioni selezionate che rientrano nel campo di applicazione di una condizione abilitante siano coerenti con le corrispondenti strategie e con i documenti di programmazione redatti per il soddisfacimento di tale condizione abilitante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le operazioni selezionate presentino il miglior rapporto tra l’importo del sostegno, le attività intraprese e il conseguimento degli obiettivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica che il beneficiario disponga delle risorse e dei meccanismi finanziari necessari a coprire i costi di gestione e di manutenzione per le operazioni che comportano investimenti in infrastrutture o investimenti produttivi, in modo da garantirne la sostenibilità finanziaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le operazioni selezionate che rientrano nell’ambito di applicazione della direttiva 2011/92/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">22</span>\n) siano soggette a una valutazione dell’impatto ambientale o a una procedura di screening e che si sia tenuto debito conto della valutazione delle soluzioni alternative, in base alle prescrizioni di detta direttiva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica che, ove le operazioni siano cominciate prima della presentazione di una domanda di finanziamento all’autorità di gestione, sia stato osservato il diritto applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le operazioni selezionate rientrino nell’ambito di applicazione del fondo interessato e siano attribuite a una tipologia di intervento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che nelle operazioni non rientrino attività che erano parte di un’operazione oggetto di delocalizzazione in conformità dell’articolo 66 o che costituirebbero trasferimento di un’attività produttiva in conformità dell’articolo 65, paragrafo 1, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le operazioni selezionate non siano direttamente oggetto di un parere motivato della Commissione per infrazione a norma dell’articolo 258 TFUE che metta a rischio la legittimità e regolarità delle spese o l’esecuzione delle operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce l’immunizzazione dagli effetti del clima degli investimenti in infrastrutture la cui durata attesa è di almeno cinque anni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda la lettera b) del presente paragrafo, nel caso dell’obiettivo strategico 1, previsto all’articolo 3, paragrafo 1, lettera a), del regolamento FESR e del Fondo di coesione, solo le operazioni corrispondenti agli obiettivi specifici di cui ai sottopunti i) e iv) di tale punto devono essere coerenti con le corrispondenti strategie di specializzazione intelligente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione garantisce che il beneficiario riceva un documento che specifica tutte le condizioni per il sostegno a ciascuna operazione, comprese le prescrizioni specifiche riguardanti i prodotti o servizi da fornire, il piano di finanziamento, il termine di esecuzione e, se del caso, il metodo da applicare per determinare i costi dell’operazione e le condizioni di erogazione del sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per le operazioni che hanno ricevuto un marchio di eccellenza o per le operazioni che sono state selezionate per un programma cofinanziato da Orizzonte Europa, l’autorità di gestione può decidere di concedere sostegno a carico del FESR o del FSE+ direttamente, a condizione che tali operazioni soddisfino i requisiti di cui al paragrafo 2, lettere a), b) e g).</div>\n</div>"], [null, "<p class=\"norm\">Inoltre, alle operazioni di cui al primo comma le autorità di gestione possono applicare le categorie, gli importi massimi e i metodi di calcolo dei costi ammissibili stabiliti nel quadro del pertinente strumento dell’Unione. Tali elementi sono definiti nel documento di cui al paragrafo 3.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Quando l’autorità di gestione seleziona un’operazione di importanza strategica, essa informa la Commissione entro 1 mese e le fornisce tutte le informazioni pertinenti a tale operazione.</div>\n</div>"]]}, "74": {"label": "Articolo 74", "heading": "Gestione del programma da parte dell’autorità di gestione", "anchor": "art_74", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esegue verifiche di gestione per accertarsi che i prodotti e i servizi cofinanziati siano stati forniti, che l’operazione sia conforme al diritto applicabile, al programma e alle condizioni per il sostegno dell’operazione, e verifica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i costi da rimborsare a norma dell’articolo 53, paragrafo 1, lettera a), che l’importo delle spese dichiarate dai beneficiari in relazione a tali costi sia stato erogato e che i beneficiari tengano una contabilità separata o utilizzino codici contabili appropriati per tutte le transazioni relative all’operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i costi da rimborsare a norma dell’articolo 53, paragrafo 1, lettere b), c) e d), che siano state rispettate le condizioni per il rimborso della spesa al beneficiario;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce, subordinatamente alla disponibilità di finanziamento, che ciascun beneficiario riceva l’importo dovuto integralmente ed entro 80 giorni dalla data della presentazione della domanda di pagamento da parte del beneficiario; il termine può essere interrotto se le informazioni presentate dal beneficiario non consentono all’autorità di gestione di stabilire se l’importo è dovuto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pone in atto misure e procedure antifrode efficaci e proporzionate, tenendo conto dei rischi individuati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">previene, individua e rettifica le irregolarità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conferma che le spese registrate nei conti sono legittime e regolari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redige la dichiarazione di gestione in conformità del modello riportato nell’allegato XVIII;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In relazione al primo comma, lettera b), non si applica alcuna detrazione o ritenuta né si impone alcun onere specifico o di altro genere con effetto equivalente che porti alla riduzione degli importi dovuti ai beneficiari.</p>"], [null, "<p class=\"norm\">Per le operazioni PPP l’autorità di gestione esegue i pagamenti a un conto di garanzia istituito appositamente a nome del beneficiario per essere utilizzato in conformità dell’accordo di PPP.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le verifiche di gestione di cui al paragrafo 1, primo comma, la lettera a), sono basate sulla valutazione dei rischi e proporzionate ai rischi individuati ex ante e per iscritto.</div>\n</div>"], [null, "<p class=\"norm\">Le verifiche di gestione comprendono verifiche amministrative riguardanti le domande di pagamento presentate dai beneficiari e le verifiche in loco delle operazioni. Tali verifiche sono eseguite prima della presentazione dei conti in conformità dell’articolo 98.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l’autorità di gestione è anche un beneficiario del programma, le disposizioni per le verifiche di gestione garantiscono la separazione delle funzioni.</div>\n</div>"], [null, "<p class=\"norm\">Fatto salvo il paragrafo 2, il regolamento Interreg può stabilire norme specifiche sulle verifiche di gestione applicabili ai programmi Interreg. I regolamenti AMIF, ISF e BMVI possono stabilire norme specifiche sulle verifiche di gestione che sono applicabili quando il beneficiario è un’organizzazione internazionale.</p>"]]}, "75": {"label": "Articolo 75", "heading": "Sostegno all’attività del comitato di sorveglianza da parte dell’autorità di gestione", "anchor": "art_75", "frags": [[null, "<p class=\"norm\">L’autorità di gestione:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce tempestivamente al comitato di sorveglianza tutte le informazioni necessarie per lo svolgimento dei suoi compiti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede a dare seguito alle decisioni e alle raccomandazioni del comitato di sorveglianza.</p>\n</div>\n</div>"]]}, "76": {"label": "Articolo 76", "heading": "Funzione contabile", "anchor": "art_76", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Rientrano nella funzione contabile i compiti seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere e presentare le domande di pagamento alla Commissione in conformità degli articoli 91 e 92;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere e presentare i conti, confermarne la completezza, l’accuratezza e la veridicità in conformità dell’articolo 98 e conservare registrazioni elettroniche di tutti gli elementi dei conti, comprese le domande di pagamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">convertire in euro gli importi delle spese sostenute in un’altra valuta utilizzando il tasso di cambio contabile mensile della Commissione del mese nel quale la spesa in questione è registrata nei sistemi contabili dell’organismo responsabile dell’esecuzione dei compiti indicati nel presente articolo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La funzione contabile non comprende le verifiche a livello di beneficiari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, lettera c), il regolamento Interreg può stabilire un metodo diverso per la conversione in euro di importi di spese sostenute in un’altra valuta.</div>\n</div>"]]}, "77": {"label": "Articolo 77", "heading": "Funzioni dell’autorità di audit", "anchor": "art_77", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorità di audit è responsabile dello svolgimento degli audit dei sistemi, degli audit delle operazioni e degli audit dei conti al fine di fornire alla Commissione una garanzia indipendente del funzionamento efficace dei sistemi di gestione e controllo e della legittimità e regolarità delle spese incluse nei conti presentati alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le attività di audit sono svolte in conformità dei principi di audit riconosciuti a livello internazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di audit redige e presenta alla Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un parere di audit annuale conformemente all’articolo 63, paragrafo 7, del regolamento finanziario e al modello riportato nell’allegato XIX del presente regolamento e sulla base di tutte le attività di audit svolte, relativo a ciascuna delle componenti seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la completezza, la veridicità e l’accuratezza dei conti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la legittimità e regolarità delle spese incluse nei conti presentati alla Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il funzionamento efficace del sistema di gestione e controllo;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una relazione annuale di controllo conforme alle prescrizioni dell’articolo 63, paragrafo 5, lettera b), del regolamento finanziario, in conformità del modello riportato nell’allegato XX del presente regolamento, che corrobori il parere di audit di cui alla lettera a) del presente paragrafo e presenti una sintesi delle constatazioni, comprendente un’analisi della natura e della portata degli errori e delle carenze riscontrati nei sistemi, le azioni correttive proposte e attuate nonché il risultante tasso di errore totale e il risultante tasso di errore residuo per le spese inserite nei conti presentati alla Commissione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se ai fini degli audit delle operazioni sono stati raggruppati programmi come previsto all’articolo 79, paragrafo 2, secondo comma, le informazioni richieste nel paragrafo 3, lettera b), del presente articolo, possono essere raggruppate in una relazione unica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’autorità di audit trasmette alla Commissione le relazioni sugli audit di sistema appena conclusa la procedura in contraddittorio con i pertinenti soggetti sottoposti all’audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione e le autorità di audit si riuniscono periodicamente e, salvo diverso accordo, almeno una volta all’anno per esaminare la strategia di audit, la relazione annuale di controllo e il parere di audit, per coordinare i loro piani e metodi di audit, nonché per scambiarsi opinioni su questioni relative al miglioramento dei sistemi di gestione e controllo.</div>\n</div>"]]}, "78": {"label": "Articolo 78", "heading": "Strategia di audit", "anchor": "art_78", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Previa consultazione dell’autorità di gestione, l’autorità di audit predispone una strategia di audit che comprenda gli audit dei sistemi e gli audit delle operazioni, in base a una valutazione dei rischi, tenendo presente la descrizione del sistema di gestione e controllo prescritta dall’articolo 69, paragrafo 11. La strategia di audit comprende audit dei sistemi delle nuove autorità di gestione e autorità incaricate della funzione contabile. Tali audit sono effettuati entro ventuno mesi dalla decisione di approvazione del programma o della modifica del programma che individua tale autorità. La strategia di audit è redatta in conformità del modello riportato nell’allegato XXII ed è aggiornata annualmente dopo la prima relazione annuale di controllo e il parere di audit forniti alla Commissione. Può riguardare uno o più programmi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La strategia di audit è presentata alla Commissione su richiesta.</div>\n</div>"]]}, "79": {"label": "Articolo 79", "heading": "Audit delle operazioni", "anchor": "art_79", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli audit delle operazioni riguardano le spese dichiarate alla Commissione durante un periodo contabile in base ad un campione. Tale campione è rappresentativo e basato su metodi di campionamento statistici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se una popolazione è composta da meno di 300 unità di campionamento, può essere utilizzato un metodo di campionamento non statistico secondo il giudizio professionale dell’autorità di audit. In tali casi, la dimensione del campione deve essere sufficiente a consentire all’autorità di audit di redigere un parere di audit valido. Il metodo di campionamento non statistico copre almeno il 10 % delle unità di campionamento della popolazione del periodo contabile, selezionate in modo casuale.</div>\n</div>"], [null, "<p class=\"norm\">Il campione statistico può coprire uno o più programmi che ricevono sostegno dal FESR, dal FSE+, dal Fondo di coesione e dal JTF e, effettuata la stratificazione ove opportuno, uno o più periodi di programmazione secondo il giudizio professionale dell’autorità di audit.</p>"], [null, "<p class=\"norm\">Il campione di operazioni sostenute dal FEAMPA, dall’AMIF, dall’ISF e dal BMVI copre le operazioni sostenute da ciascun fondo separatamente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli audit delle operazioni comprendono le verifiche in loco dell’attuazione materiale dell’operazione solo se la tipologia di operazione in questione lo richiede.</div>\n</div>"], [null, "<p class=\"norm\">Il regolamento FSE+ può stabilire disposizioni specifiche per i programmi o le priorità di cui all’articolo 4, paragrafo 1, lettera m), di tale regolamento. I regolamenti AMIF, ISF e BMVI possono stabilire disposizioni specifiche sull’audit delle operazioni quando il beneficiario è un’organizzazione internazionale. Il regolamento Interreg può stabilire norme specifiche sugli audit delle operazioni applicabili ai programmi Interreg.</p>"], [null, "<p class=\"norm\">Gli audit sono effettuati sulla base delle norme in vigore al momento in cui sono state eseguite le attività nell’ambito dell’operazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare un atto delegato conformemente all’articolo 114 per integrare il presente articolo stabilendo metodologie di campionamento standardizzate pronte all’uso e le modalità per coprire uno o più periodi di programmazione.</div>\n</div>"]]}, "80": {"label": "Articolo 80", "heading": "Modalità di audit unico", "anchor": "art_80", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nello svolgimento degli audit, la Commissione e le autorità di audit tengono in debito conto i principi dell’audit unico e di proporzionalità in rapporto al livello di rischio per il bilancio dell’Unione. In particolare, in tal modo si intende evitare la duplicazione di audit e di verifiche di gestione di una stessa spesa dichiarata alla Commissione al fine di minimizzare i costi delle verifiche di gestione e degli audit e gli oneri amministrativi per i beneficiari.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione e le autorità di audit utilizzano in primo luogo tutte le informazioni e i dati delle registrazioni di cui all’articolo 72, paragrafo 1, lettera e), compresi i risultati delle verifiche di gestione, e richiedono e ottengono ulteriori documenti e dati di audit dai beneficiari interessati unicamente se, secondo il loro giudizio professionale, ciò è necessario per corroborare solide conclusioni di audit.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per i programmi per i quali la Commissione conclude che il parere dell’autorità di audit è affidabile e lo Stato membro interessato partecipa alla cooperazione rafforzata sull’istituzione della Procura europea, gli audit della Commissione si limitano alla verifica dell’operato dell’autorità di audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Prima della presentazione dei conti del periodo contabile in cui l’operazione è completata la Commissione o l’autorità di audit non effettuano più di un audit relativamente alle operazioni per le quali le spese totali ammissibili non superano 400 000  EUR per il FESR o il Fondo di coesione, 350 000  EUR per il JTF, 300 000  EUR per il FSE+ o 200 000  EUR per il FEAMPA, l’AMIF, l’ISF o il BMVI.</div>\n</div>"], [null, "<p class=\"norm\">Altre operazioni non sono soggette a più di un audit per periodo contabile da parte dell’autorità di audit o della Commissione prima della presentazione dei conti del periodo contabile in cui l’operazione è completata. Le operazioni non sono soggette a audit da parte della Commissione o dell’autorità di audit in qualsiasi anno nel quale è stato già svolto un audit dalla Corte dei conti, purché i risultati dell’audit svolto dalla Corte dei conti per tali operazioni possano essere utilizzati dall’autorità di audit o dalla Commissione al fine di ottemperare ai loro rispettivi compiti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 3, qualsiasi operazione può essere soggetta a più di un audit se l’autorità di audit conclude, in base al proprio giudizio professionale, che non è possibile redigere un parere di audit valido.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I paragrafi 2 e 3 non si applicano:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se esiste un rischio specifico di irregolarità o un sospetto di frode;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è necessario ripetere il lavoro dell’autorità di audit per ottenere garanzie in merito al suo funzionamento efficace;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se vi sono indizi di carenza grave nell’operato dell’autorità di audit.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "81": {"label": "Articolo 81", "heading": "Verifiche di gestione e audit degli strumenti finanziari", "anchor": "art_81", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione effettua verifiche di gestione in loco in conformità dell’articolo 74, paragrafo 1, solo a livello degli organismi che attuano lo strumento finanziario e, nel contesto dei fondi di garanzia, al livello degli organismi che attuano i nuovi prestiti sottostanti. L’autorità di gestione può basarsi su verifiche realizzate da organismi esterni e non effettuare verifiche di gestione sul posto, purché disponga di sufficienti elementi di prova della competenza di questi organismi esterni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione non effettua verifiche sul posto a livello della BEI o di altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione.</div>\n</div>"], [null, "<p class=\"norm\">La BEI o le altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione forniscono, però, all’autorità di gestione relazioni di controllo a sostegno delle domande di pagamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’autorità di audit effettua audit dei sistemi e audit delle operazioni in conformità dell' articolo 77, 79 o 83, se del caso, a livello degli organismi che attuano lo strumento finanziario e, nel contesto dei fondi di garanzia, a livello degli organismi che attuano i nuovi prestiti sottostanti. I risultati dell’audit realizzato dai revisori esterni di organismi che attuano lo strumento finanziario possono essere presi in considerazione dall’autorità di audit ai fini della garanzia globale di affidabilità e, su detta base, l’autorità di audit può decidere di limitare le proprie attività di audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel contesto dei fondi di garanzia, gli organismi responsabili degli audit dei programmi possono condurre audit degli organismi che forniscono i nuovi prestiti sottostanti soltanto se si verificano una o più delle situazioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i documenti giustificativi, che comprovano il sostegno versato a titolo dello strumento finanziario ai destinatari finali, non sono disponibili a livello dell’autorità di gestione o a livello degli organismi che attuano lo strumento finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">vi sono prove che i documenti disponibili a livello dell’autorità di gestione o a livello degli organismi che attuano lo strumento finanziario non costituiscono una registrazione attendibile e completa del sostegno fornito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’autorità di audit non effettua audit a livello della BEI o delle altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione per gli strumenti finanziari da queste attuati.</div>\n</div>"], [null, "<p class=\"norm\">La BEI o le altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione forniscono però alla Commissione e all’autorità di audit una relazione annuale di audit redatta dai loro revisori esterni entro la fine di ciascun anno civile. La relazione comprende gli elementi indicati nell’allegato XXI e costituisce la base dell’operato dell’autorità di audit.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La BEI o le altre istituzioni finanziarie internazionali forniscono alle autorità del programma tutti i documenti necessari per metterle in grado di ottemperare ai loro obblighi.</div>\n</div>"]]}, "82": {"label": "Articolo 82", "heading": "Disponibilità dei documenti", "anchor": "art_82", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve le norme in materia di aiuti di Stato, l’autorità di gestione garantisce che tutti i documenti giustificativi riguardanti un’operazione sostenuta dai fondi siano conservati al livello opportuno per un periodo di cinque anni a decorrere dal 31 dicembre dell’anno in cui è effettuato l’ultimo pagamento dell’autorità di gestione al beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il periodo di cui al paragrafo 1 si interrompe in caso di procedimento giudiziario o su richiesta della Commissione.</div>\n</div>"]]}, "83": {"label": "Articolo 83", "heading": "Modalità proporzionate migliorate", "anchor": "art_83", "frags": [[null, "<p class=\"norm\">Gli Stati membri possono applicare le seguenti modalità proporzionate migliorate per il sistema di gestione e controllo di un programma se sono soddisfatte le condizioni esposte all’articolo 84:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all’articolo 74, paragrafo 1, lettera a), e all’articolo 74, paragrafo 2, l’autorità di gestione può applicare solo procedure nazionali per effettuare verifiche di gestione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all’articolo 77, paragrafo 1, con riguardo agli audit dei sistemi e all’articolo 79, paragrafi 1 e 3, con riguardo agli audit delle operazioni, l’autorità di audit può limitare la propria attività di audit ad audit delle operazioni che interessano un campione basato su una selezione statistica di 30 unità di campionamento per il programma o gruppo di programmi interessato.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Ai fini delle verifiche di gestione di cui al primo comma, lettera a), l’autorità di gestione può basarsi su verifiche effettuate da organismi esterni purché disponga di sufficienti elementi di prova della competenza di tali organismi.</p>"], [null, "<p class=\"norm\">Per il primo comma, lettera b), se la popolazione è composta da meno di 300 unità di campionamento, l’autorità di audit può applicare un metodo di campionamento non statistico in conformità dell’articolo 79, paragrafo 2.</p>"], [null, "<p class=\"norm\">La Commissione limita i propri audit alla revisione dell’operato dell’autorità di audit mediante ripetizione dell’audit, unicamente a livello di questa, salvo che le informazioni disponibili suggeriscano carenza grave nell’operato dell’autorità di audit.</p>"]]}, "84": {"label": "Articolo 84", "heading": "Condizioni di applicazione delle modalità proporzionate migliorate", "anchor": "art_84", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può applicare le modalità proporzionate migliorate di cui all’articolo 83 in qualsiasi momento durante il periodo di programmazione, se la Commissione ha confermato, nelle proprie relazioni annuali di attività pubblicate per gli ultimi due anni prima di tale decisione dello Stato membro, che il sistema di gestione e controllo del programma funziona efficacemente e che il tasso di errore totale per ciascun anno è pari o inferiore al 2 %. In sede di valutazione del funzionamento efficace del sistema di gestione e controllo del programma la Commissione tiene conto della partecipazione dello Stato membro in questione alla cooperazione rafforzata sull’istituzione della Procura europea.</div>\n</div>"], [null, "<p class=\"norm\">Se uno Stato membro decide di applicare le modalità proporzionate migliorate di cui all’articolo 83, esso notifica alla Commissione l’applicazione di tali modalità. In tal caso, le modalità si applicano dal periodo contabile successivo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">All’inizio del periodo di programmazione lo Stato membro può applicare le modalità proporzionate migliorate di cui all’articolo 83, purché le condizioni esposte nel paragrafo 1 del presente articolo siano soddisfatte in relazione a un programma analogo attuato nel periodo 2014-2020 e se le modalità di gestione e controllo stabilite per il programma 2021-2027 sono basate in gran misura su quelle relative al programma precedente. In tal caso le modalità si applicano dall’avvio del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro stabilisce o aggiorna di conseguenza la descrizione del sistema di gestione e controllo e la strategia di audit di cui all’articolo 69, paragrafo 11, e all’articolo 78.</div>\n</div>"]]}, "85": {"label": "Articolo 85", "heading": "Modulazione durante il periodo di programmazione", "anchor": "art_85", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se la Commissione o l’autorità di audit concludono, in base agli audit effettuati e alla relazione annuale di controllo, che le condizioni di cui all’articolo 84 non sono più soddisfatte, la Commissione chiede all’autorità di audit di effettuare ulteriori attività di audit in conformità dell’articolo 69, paragrafo 3, e di accertarsi che siano adottate azioni correttive.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se la successiva relazione annuale di controllo conferma che le condizioni continuano a non essere soddisfatte, limitando in tal modo la garanzia di funzionamento efficace dei sistemi di gestione e controllo e di legittimità e regolarità delle spese fornita alla Commissione, la Commissione chiede all’autorità di audit di effettuare audit dei sistemi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione, dopo aver dato allo Stato membro la possibilità di presentare osservazioni, può informare lo Stato membro che le modalità proporzionate migliorate di cui all’articolo 83 non si applicano più dal periodo contabile successivo.</div>\n</div>"]]}, "86": {"label": "Articolo 86", "heading": "Impegni di bilancio", "anchor": "art_86", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La decisione di approvazione del programma in conformità dell’articolo 23 costituisce una decisione di finanziamento ai sensi dell’articolo 110, paragrafo 1, del regolamento finanziario e la sua notifica allo Stato membro costituisce un impegno giuridico.</div>\n</div>"], [null, "<p class=\"norm\">Tale decisione specifica il contributo totale dell’Unione per fondo e per anno. Tuttavia, per i programmi dell’obiettivo «Investimenti a favore dell’occupazione e della crescita», è mantenuto un importo pari al 50 % del contributo per gli anni 2026 e il 2027 («importo di flessibilità») per programma in ciascuno Stato membro, importo che è definitivamente assegnato al programma solo dopo l’adozione della decisione della Commissione in seguito al riesame intermedio in conformità dell’articolo 18.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio dell’Unione per ciascun programma sono assunti dalla Commissione in rate annuali per ciascun fondo nel periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 111, paragrafo 2, del regolamento finanziario, gli impegni di bilancio per la prima frazione fanno seguito all’adozione del programma da parte della Commissione.</div>\n</div>"]]}, "87": {"label": "Articolo 87", "heading": "Uso dell’euro", "anchor": "art_87", "frags": [[null, "<p class=\"norm\">Tutti gli importi che figurano nei programmi, nelle relazioni o dichiarazioni degli Stati membri alla Commissione sono espressi in euro.</p>"]]}, "88": {"label": "Articolo 88", "heading": "Rimborso", "anchor": "art_88", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualsiasi importo dovuto al bilancio dell’Unione è rimborsato entro il termine indicato nell’ordine di riscossione emesso in conformità dell’articolo 98 del regolamento finanziario. La data di scadenza è l’ultimo giorno del secondo mese successivo all’emissione dell’ordine.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualsiasi ritardo nel provvedere al rimborso dà luogo all’applicazione di interessi di mora, a decorrere dalla data di scadenza e fino alla data del pagamento effettivo. Il tasso d’interesse è un punto e mezzo percentuale al di sopra del tasso applicato dalla Banca centrale europea alle sue principali operazioni di rifinanziamento il primo giorno lavorativo del mese della data di scadenza.</div>\n</div>"]]}, "89": {"label": "Articolo 89", "heading": "Tipologie di pagamenti", "anchor": "art_89", "frags": [[null, "<p class=\"norm\">I pagamenti avvengono sotto forma di prefinanziamento, di pagamenti intermedi e pagamenti del saldo dei conti del periodo contabile.</p>"]]}, "90": {"label": "Articolo 90", "heading": "Prefinanziamento", "anchor": "art_90", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione versa il prefinanziamento in base al sostegno totale a carico dei fondi indicato nella decisione di approvazione del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il prefinanziamento per ciascun fondo è versato in rate annuali prima del 1<span class=\"superscript\">o</span> luglio di ogni anno, subordinatamente alla disponibilità dei finanziamenti, come indicato nel seguito:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2021: 0,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2022: 0,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2023: 0,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2024: 0,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2025: 0,5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2026: 0,5 %.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se un programma è adottato dopo il 1<span class=\"superscript\">o</span> luglio 2021, le rate precedenti sono versate nell’anno di adozione.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">Un prefinanziamento supplementare dello 0,5 % è versato nel 2022 immediatamente dopo l’entrata in vigore del presente regolamento e nel 2023 è versato un prefinanziamento supplementare dello 0,5 % per i programmi sostenuti dal FESR, dal FSE+ o dal Fondo di coesione nell’ambito dell’obiettivo “Investimenti a favore dell’occupazione e della crescita”. Se un programma è adottato dopo il 31 dicembre 2022, la rata per il 2022 è versata nell’anno di adozione.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, le regole specifiche sul prefinanziamento per i programmi Interreg sono stabilite nel regolamento Interreg.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, le regole specifiche sul prefinanziamento per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI sono stabilite nei regolamenti specifici relativi ai fondi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione effettua la liquidazione contabile dell’importo versato a titolo di prefinanziamento ogni anno per il 2021 e il 2022, ad eccezione del prefinanziamento supplementare di cui al paragrafo 2, terzo comma, del presente articolo. La Commissione effettua la liquidazione contabile di tutti gli altri importi versati a titolo di prefinanziamento non oltre il periodo contabile finale a norma dell’articolo 100.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Per i programmi sostenuti dall’AMIF, dall’ISF e dal BMVI la Commissione effettua la liquidazione contabile dell’importo versato a titolo di prefinanziamento non oltre il periodo contabile finale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Eventuali interessi generati dal prefinanziamento sono utilizzati per il programma in questione allo stesso modo dei fondi e sono registrati nei conti del periodo contabile finale.</div>\n</div>"]]}, "91": {"label": "Articolo 91", "heading": "Domande di pagamento", "anchor": "art_91", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro presenta al massimo sei domande di pagamento per programma, per fondo e per periodo contabile. Ogni anno può essere presentata una domanda di pagamento in qualsiasi momento durante ogni periodo di tempo compreso tra le date seguenti: 28 febbraio, 31 maggio, 31 luglio, 31 ottobre, 30 novembre e 31 dicembre.</div>\n</div>"], [null, "<p class=\"norm\">L’ultima domanda di pagamento presentata entro il 31 luglio si considera domanda di pagamento finale per il periodo contabile terminato il 30 giugno.</p>"], [null, "<p class=\"norm\">Il primo comma non si applica ai programmi Interreg.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le domande di pagamento sono ammissibili solo se è stato presentato il più recente pacchetto di affidabilità dovuto di cui all’articolo 98.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le domande di pagamento sono presentate alla Commissione in conformità del modello riportato nell’allegato XXIII e comprendono per ciascuna priorità e, se del caso, categoria di regioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale delle spese ammissibili sostenute dai beneficiari e pagate nell’attuazione delle operazioni collegate a obiettivi specifici per cui sono soddisfatte le condizioni abilitanti e delle operazioni collegate a obiettivi specifici per cui non sono soddisfatte le condizioni abilitanti, ma contribuiscono al soddisfacimento delle condizioni abilitanti, come contabilizzato nel sistema dell’organismo che svolge la funzione contabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo per l’assistenza tecnica calcolato in conformità dell’articolo 36, paragrafo 5, lettera b), se del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale del contributo pubblico fornito o da fornire collegato a obiettivi specifici per cui sono soddisfatte le condizioni abilitanti, e delle operazioni collegate a obiettivi specifici per cui non sono soddisfatte le condizioni abilitanti ma contribuiscono al soddisfacimento delle condizioni abilitanti, come contabilizzato nel sistema dell’organismo che svolge la funzione contabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale delle spese ammissibili sostenute dai beneficiari e pagate nell’attuazione delle operazioni collegate a obiettivi specifici per cui non sono soddisfatte le condizioni abilitanti ad eccezione delle operazioni che contribuiscono al soddisfacimento delle condizioni abilitanti, come contabilizzato nel sistema dell’organismo che svolge la funzione contabile.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 3, lettera a), si applicano le disposizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il contributo dell’Unione si esplica come previsto all’articolo 51, lettera a), gli importi inclusi in una domanda di pagamento sono gli importi giustificati dai progressi nel soddisfacimento delle condizioni, o nel conseguimento dei risultati, in conformità della decisione di cui all’articolo 95, paragrafo 2, o dell’atto delegato di cui all’articolo 95, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il contributo dell’Unione si esplica come previsto all’articolo 51, lettere c), d) ed e), gli importi inclusi in una domanda di pagamento sono gli importi determinati in conformità della decisione di cui all’articolo 94, paragrafo 3, o dell’atto delegato di cui all’articolo 94, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le forme di sovvenzioni di cui all’articolo 53, paragrafo 1, primo comma, lettere b), c) e d), gli importi inclusi in una domanda di pagamento sono i costi calcolati sulla base applicabile.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 3, nel caso degli aiuti di Stato, la domanda di pagamento può includere gli anticipi versati al beneficiario dall’organismo che concede l’aiuto alle condizioni cumulative seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali anticipi sono soggetti a una garanzia fornita da una banca o da qualunque altra istituzione finanziaria stabilita nello Stato membro o sono coperti da uno strumento fornito a garanzia da un ente pubblico o dallo Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali anticipi non eccedono il 40 % dell’importo totale dell’aiuto da concedere a un beneficiario per una determinata operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali anticipi sono coperti dalle spese sostenute dai beneficiari nell’attuazione dell’operazione e sono giustificati da fatture quietanzate o da documenti contabili di valore probatorio equivalente presentati al più tardi entro tre anni dall’anno in cui è stato versato l’anticipo oppure entro il 31 dicembre 2029, se anteriore; in caso contrario, la successiva domanda di pagamento è rettificata di conseguenza.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Ciascuna domanda di pagamento contenente anticipi di questo tipo indica separatamente l’importo complessivo versato come anticipo dal programma, l’importo che è stato coperto dalle spese sostenute dai beneficiari entro tre anni dal pagamento dell’anticipo in conformità della lettera c) e l’importo che non è stato coperto dalle spese sostenute dai beneficiari e per il quale il periodo di tre anni non è ancora trascorso.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 3, lettera c), del presente articolo, nel caso dei regimi di aiuto a norma dell’articolo 107 TFUE, il contributo pubblico corrispondente alle spese incluse in una domanda di pagamento deve essere stato versato ai beneficiari dall’organismo che concede l’aiuto.</div>\n</div>"]]}, "92": {"label": "Articolo 92", "heading": "Elementi specifici degli strumenti finanziari nelle domande di pagamento", "anchor": "art_92", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se gli strumenti finanziari sono attuati in conformità dell’articolo 59, paragrafo 1, le domande di pagamento in conformità dell’allegato XXIII comprendono gli importi totali versati o, nel caso di garanzie, gli importi accantonati per i contratti di garanzia, dall’autorità di gestione a favore dei destinatari finali di cui all’articolo 68, paragrafo 1, lettere a), b) e c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se gli strumenti finanziari sono attuati in conformità dell’articolo 59, paragrafo 2, le domande di pagamento che comprendono spese per gli strumenti finanziari sono presentate in conformità delle condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo incluso nella prima domanda di pagamento deve essere stato versato agli strumenti finanziari e può rappresentare fino al 30 % dell’importo totale dei contributi del programma impegnati per strumenti finanziari a norma del pertinente accordo di finanziamento, in conformità della pertinente priorità e categoria di regioni, se applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo incluso nelle domande successive di pagamento presentate durante il periodo di ammissibilità include le spese ammissibili di cui all’articolo 68, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione effettua la liquidazione contabile dell’importo contenuto nella prima domanda di pagamento di cui al paragrafo 2, lettera a), non oltre il periodo contabile finale.</div>\n</div>"], [null, "<p class=\"norm\">Nelle domande di pagamento esso è indicato separatamente.</p>"]]}, "93": {"label": "Articolo 93", "heading": "Regole comuni per i pagamenti", "anchor": "art_93", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 15, paragrafi 5 e 6, e subordinatamente alla disponibilità di finanziamenti, la Commissione effettua i pagamenti intermedi entro 60 giorni dalla data di ricevimento della domanda di pagamento da parte della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun pagamento è imputato all’impegno di bilancio aperto meno recente del fondo e della categoria di regioni in questione. A titolo di pagamenti intermedi la Commissione rimborsa il 95 % degli importi figuranti nella domanda di pagamento, ottenuto applicando il tasso di cofinanziamento per ciascuna priorità al totale delle spese ammissibili o al contributo pubblico, a seconda dei casi. La Commissione determina gli importi residui da rimborsare o da recuperare in sede di calcolo del saldo dei conti a norma dell’articolo 100.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sostegno dei fondi a una priorità per mezzo dei pagamenti intermedi non supera l’importo del sostegno dei fondi alla priorità stabilito nella decisione che approva il programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se il contributo dell’Unione si esplica in una delle forme previste all’articolo 51, la Commissione non versa più dell’importo richiesto dallo Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sostegno dei fondi a una priorità per mezzo del pagamento del saldo del periodo contabile finale non supera nessuno degli importi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo pubblico dichiarato nelle domande di pagamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sostegno dei fondi versato o da versare ai beneficiari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo richiesto dallo Stato membro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Al fine di calcolare il massimale di cui al primo comma, lettera b), del presente articolo non si tiene conto degli importi rimborsati a norma dell’articolo 36, paragrafo 5.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Su richiesta di uno Stato membro i pagamenti intermedi possono essere aumentati del 10 % in aggiunta al tasso di cofinanziamento applicabile a ciascuna priorità per i fondi, se lo Stato membro soddisfa una delle condizioni seguenti dopo il 1<span class=\"superscript\">o</span> luglio 2021:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro riceve un prestito dall’Unione a norma del regolamento (UE) n. 407/2010 del Consiglio (\n<span class=\"superscript\">23</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro riceve assistenza finanziaria a medio termine nell’ambito del meccanismo europeo di stabilità, come stabilito dal trattato che istituisce il meccanismo europeo di stabilità del 2 febbraio 2012 o come indicato nel regolamento (CE) n. 332/2002, subordinatamente all’attuazione di un programma di aggiustamento macroeconomico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">allo Stato membro interessato è stata concessa assistenza finanziaria subordinata all’attuazione di un programma di aggiustamento macroeconomico come specificato nel regolamento (UE) n. 472/2013.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il tasso maggiorato, che non può superare il 100 %, si applica alle domande di pagamento fino alla fine dell’anno civile nel quale termina l’assistenza finanziaria.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il paragrafo 6 non si applica ai programmi Interreg.</div>\n</div>"]]}, "94": {"label": "Articolo 94", "heading": "Contributo dell’Unione in base a costi unitari, somme forfettarie e tassi forfettari", "anchor": "art_94", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione può rimborsare il contributo dell’Unione a un programma in base a costi unitari, somme forfettarie e tassi forfettari in conformità dell’articolo 51, sulla base degli importi e dei tassi approvati tramite una decisione in conformità del paragrafo 3 del presente articolo o stabiliti nell’atto delegato di cui al paragrafo 4 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per avvalersi di un contributo dell’Unione al programma in base a costi unitari, somme forfettarie e tassi forfettari, gli Stati membri presentano una proposta alla Commissione in conformità dei modelli riportati negli allegati V e VI nel contesto della presentazione del programma o di una richiesta di modifica.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Gli importi e i tassi proposti dallo Stato membro sono stabiliti in base a quanto segue e valutati dall’autorità di audit:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un metodo di calcolo giusto, equo e verificabile, basato su uno degli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">su dati statistici, altre informazioni oggettive o valutazioni di esperti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati storici verificati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’applicazione delle consuete prassi di contabilità dei costi;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progetti di bilancio;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">norme riguardanti i corrispondenti costi unitari, somme forfettarie e tassi forfettari applicabili nelle politiche dell’Unione per una tipologia analoga di operazioni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">norme riguardanti i corrispondenti costi unitari, somme forfettarie e tassi forfettari applicabili in regimi di sovvenzione finanziati totalmente dallo Stato membro per una tipologia analoga di operazioni.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La decisione di approvazione del programma o della sua modifica indica le tipologie di operazioni cui si applica il rimborso in base a costi unitari, somme forfettarie e tassi forfettari, la definizione e gli importi cui si applicano tali costi unitari, somme forfettarie e tassi forfettari e i metodi per l’adeguamento degli importi.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri rimborsano i beneficiari ai fini del presente articolo. Tale rimborso può assumere qualsiasi forma di sostegno.</p>"], [null, "<p class=\"norm\">Gli audit della Commissione e dello Stato membro e le verifiche di gestione effettuate dagli Stati membri mirano esclusivamente a verificare il rispetto delle condizioni per il rimborso da parte della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla Commissione è inoltre conferito il potere di adottare un atto delegato conformemente all’articolo 114 per integrare il presente articolo definendo a livello di Unione costi unitari, somme forfettarie, tassi forfettari, i loro importi e i metodi di adeguamento nelle modalità di cui al paragrafo 2, secondo comma, lettere da a) a d) del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il presente articolo non si applica al contributo dell’Unione per l’assistenza tecnica rimborsato a norma dell’articolo 51, lettera e).</div>\n</div>"]]}, "95": {"label": "Articolo 95", "heading": "Contributo dell’Unione basato su finanziamenti non collegati ai costi", "anchor": "art_95", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può rimborsare il contributo dell’Unione a una priorità, o a parti della stessa, di programmi basati su finanziamenti non collegati ai costi in conformità dell’articolo 51, sulla base degli importi approvati tramite una decisione in conformità del paragrafo 2 del presente articolo o stabiliti nell’atto delegato di cui al paragrafo 4 del presente articolo. Per avvalersi di un contributo dell’Unione al programma basato su finanziamenti non collegati ai costi, gli Stati membri presentano una proposta alla Commissione in conformità dei modelli riportati negli allegati V e VI nel contesto di un programma o di una richiesta di modifica dello stesso. La proposta contiene gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’individuazione della priorità interessata e l’importo totale coperto dai finanziamenti non collegati ai costi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione della parte del programma e della tipologia di operazioni coperte dai finanziamenti non collegati ai costi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione delle condizioni da soddisfare o dei risultati da conseguire e un cronoprogramma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i risultati tangibili intermedi che fanno scattare il rimborso della Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le unità di misura;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il calendario del rimborso da parte della Commissione e i relativi importi collegati ai progressi nel soddisfacimento delle condizioni o nel conseguimento dei risultati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità di verifica dei risultati tangibili intermedi, del soddisfacimento delle condizioni o del conseguimento dei risultati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli eventuali metodi di adeguamento degli importi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le disposizioni per garantire la pista di controllo in conformità dell’allegato XIII che dimostri il soddisfacimento delle condizioni o il conseguimento dei risultati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il tipo di metodologia di rimborso che si prevede di utilizzare per rimborsare il beneficiario o i beneficiari nell’ambito della priorità o di parti di una priorità dei programmi di cui al presente articolo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La decisione che approva il programma o la richiesta di modifica dello stesso contiene tutti gli elementi di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri rimborsano i beneficiari ai fini del presente articolo. Tale rimborso può assumere qualsiasi forma di sostegno.</div>\n</div>"], [null, "<p class=\"norm\">Gli audit della Commissione e dello Stato membro e le verifiche di gestione effettuate dagli Stati membri mirano esclusivamente a verificare il rispetto delle condizioni per il rimborso da parte della Commissione o il conseguimento dei risultati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare un atto delegato conformemente all’articolo 114 per integrare il presente articolo definendo gli importi a livello Unione relativi ai finanziamenti non collegati ai costi per tipologia di operazione, i metodi di adeguamento degli importi e le condizioni da soddisfare o i risultati da conseguire.</p>\n</div>\n</div>"]]}, "96": {"label": "Articolo 96", "heading": "Interruzione dei termini di pagamento", "anchor": "art_96", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può interrompere il termine di pagamento, tranne che per il prefinanziamento, per un periodo massimo di sei mesi se è soddisfatta una delle condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">vi sono elementi di prova che facciano presumere una carenza grave per la quale non sono state adottate misure correttive;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione deve effettuare verifiche supplementari essendo pervenute informazioni secondo le quali le spese di una domanda di pagamento possono essere collegate a un’irregolarità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può acconsentire a prorogare di tre mesi il periodo di interruzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione limita l’interruzione a quella parte delle spese che è viziata dagli elementi di cui al paragrafo 1, salvo qualora non sia possibile individuare la parte delle spese interessata. La Commissione informa per iscritto lo Stato membro e l’autorità di gestione in merito ai motivi dell’interruzione, chiedendo a essi di porre rimedio alla situazione. La Commissione pone fine all’interruzione appena sono adottate le misure correttive per gli elementi di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le norme specifiche del FEAMPA possono stabilire motivi specifici per l’interruzione dei pagamenti in relazione al mancato rispetto delle norme applicabili nella politica comune della pesca.</div>\n</div>"]]}, "97": {"label": "Articolo 97", "heading": "Sospensione dei pagamenti", "anchor": "art_97", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può sospendere la totalità o una parte dei pagamenti, ad eccezione del prefinanziamento, dopo aver dato allo Stato membro la possibilità di presentare osservazioni, se è soddisfatta una delle condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro ha omesso di adottare le azioni necessarie per porre rimedio alla situazione che ha dato origine a un’interruzione ai sensi dell’articolo 96;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esiste una carenza grave;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese figuranti nelle domande di pagamento sono collegate a un’irregolarità che non è stata rettificata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esiste un parere motivato della Commissione in relazione a una procedura di infrazione ai sensi dell’articolo 258 TFUE riguardo a una questione che mette a rischio la legittimità e la regolarità delle spese.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione pone fine alla sospensione della totalità o di una parte dei pagamenti dopo che lo Stato membro ha adottato misure che pongono rimedio agli elementi figuranti nel paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le norme specifiche del FEAMPA possono stabilire motivi specifici per la sospensione dei pagamenti in relazione al mancato rispetto delle norme applicabili nella politica comune della pesca.</div>\n</div>"]]}, "98": {"label": "Articolo 98", "heading": "Contenuto e presentazione dei conti", "anchor": "art_98", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per ciascun periodo contabile per il quale sono state presentate domande di pagamento lo Stato membro presenta alla Commissione entro il 15 febbraio i seguenti documenti («pacchetto di affidabilità») riferiti al periodo contabile precedente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i conti in conformità del modello riportato nell’allegato XXIV;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la dichiarazione di gestione di cui all’articolo 74, paragrafo 1, lettera f), in conformità del modello riportato nell’allegato XVIII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il parere di audit annuale di cui all’articolo 77, paragrafo 3, lettera a), in conformità del modello riportato nell’allegato XIX;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la relazione annuale di controllo di cui all’articolo 77, paragrafo 3, lettera b), in conformità del modello riportato nell’allegato XX.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il termine di cui al paragrafo 1 può essere eccezionalmente prorogato dalla Commissione al 1<span class=\"superscript\">o</span> marzo, previa comunicazione dello Stato membro interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I conti comprendono, a livello di ciascuna priorità e, ove applicabile, di ciascun fondo e categoria di regioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale delle spese ammissibili registrate nel sistema contabile dell’organismo che svolge la funzione contabile e figuranti nella domanda finale di pagamento per il periodo contabile e l’importo totale del corrispondente contributo pubblico fornito o da fornire collegato a obiettivi specifici per cui sono soddisfatte le condizioni abilitanti e delle operazioni collegate a obiettivi specifici per cui non sono soddisfatte le condizioni abilitanti, ma contribuiscono al soddisfacimento delle condizioni abilitanti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi ritirati durante il periodo contabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi di contributo pubblico pagati agli strumenti finanziari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ciascuna priorità, una spiegazione delle eventuali differenze tra gli importi dichiarati a norma della lettera a) e gli importi dichiarati nelle domande di pagamento per lo stesso periodo contabile.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il pacchetto di affidabilità non riguarda l’importo totale delle spese ammissibili sostenute dai beneficiari e pagate nell’attuazione delle operazioni o del corrispondente contributo pubblico fornito o da fornire collegati a obiettivi specifici per cui non sono soddisfatte le condizioni abilitanti, ad eccezione delle operazioni che contribuiscono al soddisfacimento delle condizioni abilitanti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I conti non sono ammissibili se gli Stati membri non hanno adottato le azioni correttive necessarie per ridurre a un livello pari o inferiore al 2 % il tasso di errore residuo in merito alla legittimità e regolarità delle spese incluse nei conti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri detraggono in particolare dai conti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese irregolari che sono state oggetto di rettifiche finanziarie in conformità dell’articolo 103;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese che sono oggetto di una valutazione in corso della loro legittimità e regolarità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli altri importi necessari per ridurre il tasso di errore residuo delle spese dichiarate nei conti a un livello pari o inferiore al 2 %.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro può inserire le spese di cui al primo comma, lettera b), in una domanda di pagamento nei periodi contabili successivi una volta che ne siano state confermate la legittimità e regolarità.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può rettificare gli importi irregolari da esso individuati dopo la presentazione dei conti in cui figuravano tali importi effettuando gli adeguamenti corrispondenti per il periodo contabile in cui è individuata l’irregolarità, fatto salvo l’articolo 104.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Nel contesto del pacchetto di affidabilità lo Stato membro presenta per l’ultimo periodo contabile la relazione finale in materia di performance di cui all’articolo 43 o l’ultima relazione annuale in materia di performance per l’AMIF, l’ISF o il BMVI.</div>\n</div>"]]}, "99": {"label": "Articolo 99", "heading": "Esame dei conti", "anchor": "art_99", "frags": [[null, "<p class=\"norm\">La Commissione si accerta che i conti siano completi, accurati e veritieri entro il 31 maggio dell’anno successivo alla fine del periodo contabile, salvo se si applica l’articolo 102.</p>"]]}, "100": {"label": "Articolo 100", "heading": "Calcolo del saldo", "anchor": "art_100", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di determinare l’importo imputabile ai fondi per il periodo contabile e gli adeguamenti conseguenti in relazione ai pagamenti allo Stato membro, la Commissione tiene presente quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi figuranti nei conti di cui all’articolo 98, paragrafo 3, lettera a), ai quali va applicato il tasso di cofinanziamento per ciascuna priorità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale dei pagamenti intermedi effettuati dalla Commissione durante tale periodo contabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per il FESR, il FSE+, il Fondo di coesione, il JTF e il FEAMPA, per gli anni 2021 e 2022, l’importo del prefinanziamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora esista un importo da recuperare a carico dello Stato membro, tale importo è oggetto di un ordine di riscossione emesso dalla Commissione, che viene eseguito, ove possibile, mediante compensazione con gli importi dovuti allo Stato membro nei pagamenti successivi per lo stesso programma. Tale recupero non costituisce una rettifica finanziaria e non riduce il sostegno dei fondi al programma. L’importo recuperato costituisce un’entrata con destinazione specifica conformemente all’articolo 21, paragrafo 3, del regolamento finanziario.</div>\n</div>"]]}, "101": {"label": "Articolo 101", "heading": "Procedura di esame dei conti", "anchor": "art_101", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La procedura di <span class=\"italics\">cui</span> all’articolo 102 si applica in uno dei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’autorità di audit ha emesso un parere di audit con riserve o negativo per motivi di completezza, accuratezza e veridicità dei conti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione dispone di elementi di prova che mettono in dubbio l’affidabilità del parere di audit senza riserve.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In tutti gli altri casi la Commissione calcola gli importi imputabili ai fondi in conformità dell’articolo 100 e procede ai pertinenti pagamenti o recuperi prima del 1<span class=\"superscript\">o</span> luglio. Tale pagamento o recupero costituisce accettazione dei conti.</div>\n</div>"]]}, "102": {"label": "Articolo 102", "heading": "Procedura di esame dei conti in contraddittorio", "anchor": "art_102", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se l’autorità di audit emette un parere di audit con riserve o negativo per motivi di completezza, accuratezza e veridicità dei conti, la Commissione richiede allo Stato membro di rivedere tali conti e ripresentare i documenti di cui all’articolo 98, paragrafo 1, entro 1 mese.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Se, entro il termine di cui al primo comma:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il parere di audit è senza riserve, si applica l’articolo 100 e la Commissione versa l’eventuale importo aggiuntivo dovuto o procede al recupero entro due mesi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il parere di audit è ancora con riserve o i documenti non sono stati ripresentati dallo Stato membro, si applicano i paragrafi 2, 3 e 4.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il parere di audit è ancora con riserve per motivi di completezza, accuratezza e veridicità dei conti o se il parere di audit è ancora inaffidabile, la Commissione informa lo Stato membro in merito all’importo imputabile ai fondi per il periodo contabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro accetta l’importo di cui al paragrafo 2 del presente articolo entro 1 mese, la Commissione versa entro due mesi l’eventuale importo aggiuntivo dovuto o procede al recupero in conformità dell’articolo 100.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro non accetta l’importo di cui al paragrafo 2 del presente articolo, la Commissione stabilisce l’importo imputabile ai fondi per il periodo contabile. Tale atto non costituisce una rettifica finanziaria e non riduce il sostegno dei fondi al programma. La Commissione versa entro due mesi l’eventuale importo aggiuntivo dovuto o procede al recupero in conformità dell’articolo 100.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda il periodo contabile finale, la Commissione paga o recupera il saldo annuale dei conti per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione, dal JTF e dal FEAMPA entro due mesi dalla data di accettazione della relazione finale in materia di performance di cui all’articolo 43.</div>\n</div>"]]}, "103": {"label": "Articolo 103", "heading": "Rettifiche finanziarie effettuate dagli Stati membri", "anchor": "art_103", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri proteggono il bilancio dell’Unione e applicano rettifiche finanziarie sopprimendo totalmente o parzialmente il sostegno dei fondi a un’operazione o a un programma se le spese dichiarate alla Commissione risultano irregolari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le rettifiche finanziarie sono registrate nei bilanci del periodo contabile nel quale è decisa la soppressione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sostegno dei fondi soppresso può essere reimpiegato dallo Stato membro nell’ambito del programma interessato, a esclusione dell’operazione oggetto della rettifica in questione o, laddove la rettifica finanziaria riguardi un’irregolarità sistemica, delle operazioni interessate da tale irregolarità sistemica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le norme specifiche del FEAMPA possono stabilire motivi specifici per le rettifiche finanziarie effettuate dagli Stati membri in relazione al mancato rispetto delle norme applicabili nella politica comune della pesca.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga ai paragrafi 1, 2 e 3, nelle operazioni che comprendono strumenti finanziari il contributo soppresso a norma del presente articolo, in seguito a un’irregolarità isolata, può essere reimpiegato nell’ambito della stessa operazione alle condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’irregolarità che dà luogo alla soppressione del contributo è individuata a livello del destinatario finale, solo per altri destinatari finali nell’ambito dello stesso strumento finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’irregolarità che dà luogo alla soppressione del contributo è individuata a livello dell’organismo che attua il fondo specifico, qualora uno strumento finanziario sia attuato mediante una struttura con un fondo di partecipazione, unicamente a favore di altri organismi che attuano fondi specifici.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se l’irregolarità che dà luogo alla soppressione del contributo è individuata a livello dell’organismo che attua il fondo di partecipazione, o al livello dell’organismo che attua il fondo specifico qualora uno strumento finanziario sia attuato mediante una struttura priva di fondo di partecipazione, il contributo soppresso non è reimpiegato nell’ambito della stessa operazione.</p>"], [null, "<p class=\"norm\">Laddove sia effettuata una rettifica finanziaria per un’irregolarità sistemica, il contributo soppresso non è reimpiegato per alcuna operazione interessata da tale irregolarità sistemica.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli organismi che attuano gli strumenti finanziari rimborsano agli Stati membri i contributi del programma viziati da irregolarità, unitamente agli interessi e a qualsiasi altra plusvalenza generata da tali contributi.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Gli organismi che attuano gli strumenti finanziari non rimborsano agli Stati membri gli importi di cui al primo comma, purché tali organismi dimostrino che per una data irregolarità sono soddisfatte le condizioni cumulative seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’irregolarità si è verificata a livello dei destinatari finali o, nel caso di un fondo di partecipazione, a livello degli organismi che attuano fondi specifici o dei destinatari finali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli organismi che attuano gli strumenti finanziari hanno adempiuto i propri obblighi in relazione ai contributi del programma viziati dall’irregolarità, in conformità del diritto applicabile, e hanno agito con il livello di professionalità, trasparenza e diligenza atteso da un organismo professionale esperto nell’attuazione di strumenti finanziari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non è stato possibile recuperare gli importi viziati da irregolarità, sebbene gli organismi che attuano gli strumenti finanziari abbiano fatto ricorso a tutti gli strumenti di legge e contrattuali applicabili con la dovuta diligenza.</p>\n</div>\n</div>"]]}, "104": {"label": "Articolo 104", "heading": "Rettifiche finanziarie effettuate dalla Commissione", "anchor": "art_104", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione apporta rettifiche finanziarie riducendo il sostegno dei fondi a un programma, se essa conclude che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esiste una carenza grave che ha messo a rischio il sostegno dei fondi già versato al programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese figuranti nei conti accettati sono irregolari e non sono state individuate e segnalate dallo Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro non ha ottemperato ai propri obblighi a norma dell’articolo 97 prima dell’avvio della procedura di rettifica finanziaria da parte della Commissione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nell’applicare le rettifiche finanziarie a tasso forfettario o estrapolate la Commissione agisce in conformità dell’allegato XXV.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Prima di decidere in merito a una rettifica finanziaria, la Commissione informa lo Stato membro delle proprie conclusioni e gli dà la possibilità di presentare, entro due mesi, osservazioni e di dimostrare che la portata reale dell’irregolarità è inferiore alla valutazione della Commissione. Il termine può essere prorogato se convenuto di comune accordo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro non accetta le conclusioni della Commissione, è da questa convocato per un’audizione, in modo che la Commissione abbia a disposizione tutte le informazioni e osservazioni pertinenti per poter trarre conclusioni in merito all’applicazione della rettifica finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione decide in merito a una rettifica finanziaria tenendo conto della portata, della frequenza e delle implicazioni finanziarie delle irregolarità o carenze gravi mediante un atto di esecuzione entro dieci mesi dalla data dell’audizione o della presentazione di informazioni aggiuntive, secondo la richiesta della Commissione.</div>\n</div>"], [null, "<p class=\"norm\">Per decidere in merito a una rettifica finanziaria la Commissione tiene presenti tutte le informazioni e osservazioni presentate.</p>"], [null, "<p class=\"norm\">Se uno Stato membro accetta la rettifica finanziaria per i casi di cui al paragrafo 1, primo comma, lettere a) e c), prima dell’adozione della decisione di cui al presente paragrafo, primo comma, esso può reimpiegare gli importi in questione. Tale possibilità non si applica nel caso di una rettifica finanziaria ai sensi del paragrafo 1, primo comma, lettera b).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le norme specifiche del FEAMPA possono stabilire motivi specifici per le rettifiche finanziarie effettuate dalla Commissione in relazione al mancato rispetto delle norme applicabili nella politica comune della pesca.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le norme specifiche del JTF possono stabilire motivi specifici per le rettifiche finanziarie effettuate dalla Commissione in relazione al mancato conseguimento dei target finali definiti per il JTF.</p>\n</div>\n</div>"]]}, "105": {"label": "Articolo 105", "heading": "Principi e regole del disimpegno", "anchor": "art_105", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione disimpegna l’importo di un programma non impiegato per il prefinanziamento in conformità dell’articolo 90, o per il quale non è stata presentata una domanda di pagamento in conformità degli articoli 91 e 92, entro il 31 dicembre del terzo anno civile successivo all’anno degli impegni di bilancio per gli anni dal 2021 al 2026.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La quota di impegni ancora aperta al 31 dicembre 2029 è disimpegnata se il pacchetto di affidabilità e la relazione finale in materia di performance per i programmi sostenuti dal FESR, dal FSE+, dal Fondo di coesione, dal JTF e dal FEAMPA non sono stati presentati alla Commissione entro il termine di cui all’articolo 43, paragrafo 1.</div>\n</div>"]]}, "106": {"label": "Articolo 106", "heading": "Eccezioni alle regole di disimpegno", "anchor": "art_106", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’importo interessato dal disimpegno è ridotto degli importi equivalenti alla parte dell’impegno di bilancio per la quale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le operazioni sono sospese in virtù di un procedimento giudiziario o di un ricorso amministrativo con effetto sospensivo; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non è stato possibile presentare una domanda di pagamento per cause di forza maggiore che incidono gravemente sull’attuazione dell’intero programma o di parte dello stesso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le autorità nazionali che invocano circostanze di forza maggiore ne dimostrano le conseguenze dirette sull’attuazione dell’intero programma o di parte dello stesso.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 31 gennaio lo Stato membro invia alla Commissione informazioni in merito alle eccezioni di cui al paragrafo 1, primo comma, lettere a) e b), per l’importo che era da dichiarare entro il 31 dicembre dell’anno precedente.</div>\n</div>"]]}, "107": {"label": "Articolo 107", "heading": "Procedura di disimpegno", "anchor": "art_107", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Sulla base delle informazioni pervenute al 31 gennaio, la Commissione informa lo Stato membro circa l’importo del disimpegno risultante da tali informazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro dispone di due mesi per accettare l’importo oggetto del disimpegno o per trasmettere osservazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 30 giugno lo Stato membro presenta alla Commissione un piano di finanziamento modificato che riflette, per l’anno civile interessato, la riduzione del sostegno a una o più priorità del programma. Per i programmi che ricevono sostegno da più di un fondo, l’importo del sostegno è ridotto per ciascun fondo in proporzione agli importi oggetto del disimpegno che non erano stati impiegati nell’anno civile interessato.</div>\n</div>"], [null, "<p class=\"norm\">In caso di mancata presentazione, la Commissione modifica il piano di finanziamento riducendo il contributo dei fondi per l’anno civile interessato. Tale riduzione riguarda ciascuna priorità in proporzione agli importi oggetto del disimpegno che non erano stati impiegati nell’anno civile interessato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione modifica la decisione che approva il programma entro il 31 ottobre.</div>\n</div>"]]}, "108": {"label": "Articolo 108", "heading": "Copertura geografica del sostegno nell’ambito dell’obiettivo «Investimenti a favore dell’occupazione e della crescita»", "anchor": "art_108", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il FESR, il FSE+ e il Fondo di coesione sostengono l’obiettivo «Investimenti a favore dell’occupazione e della crescita» in tutte le regioni corrispondenti al livello 2 della classificazione comune delle unità territoriali per la statistica («regioni di livello NUTS 2») , istituita dal regolamento (CE) n. 1059/2003, modificato dal regolamento (UE) 2016/2066.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le risorse del FESR e del FSE+ per l’obiettivo «Investimenti a favore dell’occupazione e della crescita» sono ripartite fra le seguenti tre categorie di regioni di livello NUTS 2:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regioni meno sviluppate, il cui PIL pro capite è inferiore al 75 % della media del PIL pro capite dell’UE-27 («regioni meno sviluppate») ;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regioni in transizione, il cui PIL pro capite è compreso tra il 75 % e il 100 % della media del PIL pro capite dell’UE-27 («regioni in transizione»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">regioni più sviluppate, il cui PIL pro capite è superiore al 100 % della media del PIL pro capite dell’UE-27 («regioni più sviluppate»).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La classificazione delle regioni in una delle tre categorie di regioni è determinata in base al rapporto tra il PIL pro capite di ciascuna regione, misurato in standard di potere di acquisto («SpA») e calcolato in base ai dati dell’Unione per il periodo 2015-2017, e il PIL medio pro capite dell’UE-27 per lo stesso periodo di riferimento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Fondo di coesione sostiene gli Stati membri il cui reddito nazionale lordo (RNL) pro capite, misurato in SpA e calcolato in base ai dati dell’Unione per il periodo 2015-2017, è inferiore al 90 % dell’RNL medio pro capite dell’UE-27 per lo stesso periodo di riferimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta mediante atto di esecuzione una decisione che stabilisce l’elenco delle regioni che soddisfano i criteri di una delle tre categorie di regioni e degli Stati membri che soddisfano i criteri di cui al paragrafo 3. Tale elenco è valido dal 1<span class=\"superscript\">o</span> gennaio 2021 al 31 dicembre 2027.</div>\n</div>"]]}, "109": {"label": "Articolo 109", "heading": "Risorse per la coesione economica, sociale e territoriale", "anchor": "art_109", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le risorse per la coesione economica, sociale e territoriale disponibili per gli impegni di bilancio per il periodo 2021-2027 nell’ambito del QFP ammontano a 330 234 776 621  EUR a prezzi 2018 per il FESR, il FSE+ e il Fondo di coesione e a 7 500 000 000  EUR a prezzi 2018 per il JTF.</div>\n</div>"], [null, "<p class=\"norm\">Le risorse di cui al primo comma sono integrate da un importo di 10 000 000 000  EUR a prezzi 2018 per le misure di cui all’articolo 1, paragrafo 2, del regolamento (UE) 2020/2094 (\n<span class=\"superscript\">24</span>\n) del Consiglio ai fini del regolamento JTF. Tale importo costituisce un’entrata con destinazione specifica esterna ai fini dell’articolo 21, paragrafo 5, del regolamento finanziario.</p>"], [null, "<p class=\"norm\">Ai fini della programmazione e successiva imputazione al bilancio dell’Unione, gli importi di cui al primo e secondo comma sono indicizzati in ragione del 2 % annuo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione adotta mediante atto di esecuzione una decisione che stabilisce la ripartizione annua delle risorse globali per il FESR, il FSE+ e il Fondo di coesione per Stato membro a titolo dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» e, se applicabile, per categoria di regioni, in conformità delle metodologie di cui all’allegato XXVI.</div>\n</div>"], [null, "<p class=\"norm\">Tale decisione stabilisce altresì la ripartizione annua delle risorse globali per Stato membro a titolo dell’obiettivo «Cooperazione territoriale europea» (Interreg).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo 0,35 % delle risorse di cui al paragrafo 1, primo e secondo comma, previa deduzione del sostegno all’MCE di cui all’articolo 110, paragrafo 3, è destinato all’assistenza tecnica su iniziativa della Commissione.</div>\n</div>"]]}, "110": {"label": "Articolo 110", "heading": "Risorse per gli obiettivi «Investimenti a favore dell’occupazione e della crescita» e «Cooperazione territoriale europea» (Interreg)", "anchor": "art_110", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le risorse destinate all’obiettivo «Investimenti a favore dell’occupazione e della crescita» nell’ambito del QFP ammontano al 97,6 % delle risorse globali (ossia, in totale, 329 684 776 621  EUR) e sono assegnate nel modo seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 61,3 % (ossia, in totale, 202 226 984 629  EUR) è destinato alle regioni meno sviluppate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 14,5 % (ossia, in totale, 47 771 802 082  EUR) è destinato alle regioni in transizione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’8,3 % (ossia, in totale, 27 202 682 372  EUR) è destinato alle regioni più sviluppate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 12,9 % (ossia, in totale, 42 555 570 217  EUR) è destinato agli Stati membri che beneficiano del Fondo di coesione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo 0,6 % (ossia, in totale, 1 927 737 321  EUR) è destinato a finanziamenti supplementari per le regioni ultraperiferiche di cui all’articolo 349 TFUE e le regioni di livello NUTS 2 che rispondono ai criteri di cui all’articolo 2 del protocollo n. 6 dell’atto di adesione del 1994;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo 0,2 % (ossia, in totale, 500 000 000  EUR) è destinato agli investimenti in materia di innovazione interregionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 2,3 % (ossia, in totale, 7 500 000 000  EUR) è destinato al Fondo per una transizione giusta.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo delle risorse disponibili per il FSE+ a titolo dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» ammonta a 87 319 331 844  EUR.</div>\n</div>"], [null, "<p class=\"norm\">L’importo dei finanziamenti supplementari per le regioni di cui al paragrafo 1, lettera e), assegnato al FSE+ ammonta a 472 980 447  EUR.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’importo del sostegno del Fondo di coesione da trasferire all’MCE ammonta a 10 000 000 000  EUR. Esso è erogato per progetti relativi a infrastrutture di trasporto, tenendo conto delle esigenze di investimenti in infrastrutture degli Stati membri e delle regioni, mediante la pubblicazione di bandi specifici in conformità del regolamento MCE esclusivamente negli Stati membri ammissibili ai finanziamenti del Fondo di coesione.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione adotta mediante un atto di esecuzione una decisione che stabilisce l’importo da trasferire dalla dotazione del Fondo di coesione di ciascuno Stato membro all’MCE, determinato su base proporzionale per l’intero periodo.</p>"], [null, "<p class=\"norm\">La dotazione del Fondo di coesione di ciascuno Stato membro è ridotta di conseguenza.</p>"], [null, "<p class=\"norm\">Gli stanziamenti annuali corrispondenti al sostegno del Fondo di coesione di cui al primo comma sono iscritti nelle pertinenti linee di bilancio dell’MCE a partire dall’esercizio di bilancio 2021.</p>"], [null, "<p class=\"norm\">Il 30 % delle risorse trasferite all’MCE immediatamente dopo il trasferimento sono messe a disposizione di tutti gli Stati membri ammissibili al finanziamento del Fondo di coesione per finanziare progetti riguardanti infrastrutture di trasporto ai sensi del regolamento MCE.</p>"], [null, "<p class=\"norm\">Ai bandi specifici di cui al primo comma si applicano le norme applicabili al settore dei trasporti conformemente al regolamento MCE. Fino al 31 dicembre 2023, la selezione dei progetti ammissibili al finanziamento rispetta le dotazioni nazionali nell’ambito del Fondo di coesione nella misura del 70 % delle risorse trasferite all’MCE.</p>"], [null, "<p class=\"norm\">Dal 1<span class=\"superscript\">o</span> gennaio 2024 le risorse trasferite all’MCE che non sono state impegnate per un progetto riguardante infrastrutture di trasporto sono messe a disposizione di tutti gli Stati membri ammissibili al finanziamento del Fondo di coesione, per finanziare progetti riguardanti infrastrutture di trasporto ai sensi del regolamento MCE.</p>"], [null, "<p class=\"norm\">Al fine di sostenere gli Stati membri ammissibili al finanziamento del Fondo di coesione con difficoltà nella concezione di progetti che presentino una maturità o una qualità sufficienti, o entrambi, nonché un valore aggiunto sufficiente per l’Unione, è riservata particolare attenzione alle azioni di sostegno al programma intese a rafforzare la capacità istituzionale e l’efficienza delle amministrazioni e dei servizi pubblici in relazione allo sviluppo e all’attuazione dei progetti elencati nel regolamento MCE.</p>"], [null, "<p class=\"norm\">La Commissione fa tutto il possibile per consentire agli Stati membri ammissibili al finanziamento del Fondo di coesione di raggiungere, entro la fine del periodo 2021-2027, il massimo assorbimento possibile dell’importo trasferito all’MCE, anche attraverso l’organizzazione di bandi aggiuntivi.</p>"], [null, "<p class=\"norm\">Particolare attenzione e sostegno ai sensi dell’ottavo e del nono comma sono prestati agli Stati membri il cui RNL pro capite, misurato in SpA per il periodo 2015-2017, è inferiore al 60 % dell’RNL medio pro capite dell’UE-27.</p>"], [null, "<p class=\"norm\">Agli Stati membri il cui RNL pro capite, misurato in SpA per il periodo 2015-2017, è inferiore al 60 % dell’RNL medio pro capite dell’UE-27 è garantito, fino al 31 dicembre 2024, il 70 % del 70 % dell’importo da essi trasferito all’MCE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un importo pari a 400 000 000  EUR delle risorse destinate all’obiettivo «Investimenti a favore dell’occupazione e della crescita» è assegnato all’Iniziativa urbana europea attuata dalla Commissione in regime di gestione diretta o indiretta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Un importo pari a 175 000 000  EUR delle risorse del FSE+ destinate all’obiettivo «Investimenti a favore dell’occupazione e della crescita» è assegnato alla cooperazione transnazionale a sostegno di soluzioni innovative in regime di gestione diretta o indiretta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’importo di cui al paragrafo 1, lettera f), è stanziato dalle risorse del FESR nell’ambito dell’obiettivo «Investimenti a favore dell’occupazione e della crescita» a favore di investimenti in materia di innovazione interregionale in regime di gestione diretta o indiretta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le risorse per l’obiettivo «Cooperazione territoriale europea» (Interreg) ammontano al 2,4 % delle risorse globali disponibili per gli impegni di bilancio a titolo dei fondi per il periodo 2021-2027 (ossia, in totale, 8 050 000 000  EUR).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L’importo di cui all’articolo 109, paragrafo 1, secondo comma, fa parte delle risorse destinate all’obiettivo «Investimenti a favore dell’occupazione e della crescita».</div>\n</div>"]]}, "111": {"label": "Articolo 111", "heading": "Trasferibilità delle risorse", "anchor": "art_111", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può accogliere la proposta formulata da uno Stato membro nella presentazione dell’accordo di partenariato o nel contesto del riesame intermedio di trasferire:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un importo supplementare non superiore al 5 % delle dotazioni iniziali per le regioni meno sviluppate alle regioni in transizione o alle regioni più sviluppate e dalle regioni in transizione alle regioni più sviluppate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dalle dotazioni per le regioni più sviluppate o per le regioni in transizione alle regioni meno sviluppate e dalle regioni più sviluppate alle regioni in transizione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In deroga al primo comma, lettera a), la Commissione può accettare un trasferimento aggiuntivo fino al 10 % delle dotazioni totali per le regioni meno sviluppate alle regioni in transizione o alle regioni più sviluppate all’interno degli Stati membri il cui RNL pro capite, misurato in SpA per il periodo 2015-2017, è inferiore al 90 % dell’RNL medio pro capite dell’UE-27. Le risorse di eventuali trasferimenti supplementari sono utilizzate per contribuire agli obiettivi strategici di cui all’articolo 5, paragrafo 1, lettere a) e b).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le dotazioni totali a ciascuno Stato membro per l’obiettivo «Investimenti a favore dell’occupazione e della crescita» e per l’obiettivo «Cooperazione territoriale europea» (Interreg) non ammettono trasferimenti tra tali obiettivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Al fine di preservare il contributo effettivo dei fondi alle azioni di cui all’articolo 5, paragrafo 2, e in deroga al paragrafo 2 del presente articolo, in circostanze debitamente giustificate e subordinate alla condizione di cui al paragrafo 4 del presente articolo, la Commissione può accogliere, mediante un atto di esecuzione, la proposta di uno Stato membro nella sua prima presentazione dell’accordo di partenariato di trasferire una parte dei suoi stanziamenti per l’obiettivo «Cooperazione territoriale europea» (Interreg) all’obiettivo «Investimenti a favore dell’occupazione e della crescita».</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La quota dell’obiettivo «Cooperazione territoriale europea» (Interreg) nello Stato membro che formula la proposta di cui al paragrafo 3 non è inferiore al 35 % del totale assegnato a detto Stato membro per l’obiettivo «Investimenti a favore dell’occupazione e della crescita» e l’obiettivo «Cooperazione territoriale europea» (Interreg), e dopo il trasferimento non è inferiore al 25 % del totale.</div>\n</div>"]]}, "112": {"label": "Articolo 112", "heading": "Determinazione dei tassi di cofinanziamento", "anchor": "art_112", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La decisione che approva un programma fissa il tasso di cofinanziamento e l’importo massimo del sostegno dei fondi per ciascuna priorità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per ciascuna priorità, la decisione della Commissione indica se il relativo tasso di cofinanziamento debba applicarsi a uno degli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al contributo totale, compreso il contributo pubblico e privato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al contributo pubblico.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il tasso di cofinanziamento per l’obiettivo «Investimenti a favore dell’occupazione e della crescita» a livello di ciascuna priorità non è superiore al:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">85 % per le regioni meno sviluppate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">70 % per le regioni in transizione classificate come regioni meno sviluppate nel periodo 2014-2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">60 % per le regioni in transizione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">50 % per le regioni più sviluppate classificate come regioni in transizione o il cui PIL pro capite era inferiore al 100 % nel periodo 2014-2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">40 % per le regioni più sviluppate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I tassi di cofinanziamento di cui al primo comma, lettera a), si applicano anche alle regioni ultraperiferiche, compresa la dotazione aggiuntiva per le regioni ultraperiferiche.</p>"], [null, "<p class=\"norm\">Il tasso di cofinanziamento per il Fondo di coesione a livello di ciascuna priorità non è superiore all’85 %.</p>"], [null, "<p class=\"norm\">Il regolamento FSE+ può stabilire tassi di cofinanziamento superiori in conformità degli articoli 10 e 14 di tale regolamento.</p>"], [null, "<p class=\"norm inline-element\">Il tasso di cofinanziamento applicabile alla regione in cui si situa il territorio o i territori individuati nei piani territoriali per una transizione giusta per la priorità sostenuta dal JTF non è superiore:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’85 % per le regioni meno sviluppate;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al 70 % per le regioni in transizione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al 50 % per le regioni più sviluppate.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il tasso di cofinanziamento per i programmi Interreg non è superiore all’80 % salvo nei casi in cui il regolamento Interreg stabilisce tassi di cofinanziamento superiori per i programmi Interreg della sezione D e di cooperazione esterna transfrontaliera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I tassi massimi di cofinanziamento di cui ai paragrafi 3 e 4 sono aumentati di dieci punti percentuali per le priorità interamente realizzate attraverso lo sviluppo locale di tipo partecipativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le misure di assistenza tecnica attuate su iniziativa o per conto della Commissione possono essere finanziate a un tasso del 100 %.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora nell’ambito di un programma venga stabilita una priorità distinta a sostegno di operazioni volte a promuovere l’integrazione socioeconomica dei cittadini di paesi terzi, è applicato un tasso di cofinanziamento fino al 100 % alle spese dichiarate nelle domande di pagamento sino alla fine del periodo contabile che termina il 30 giugno 2024. Dopo tale data si applica il tasso di cofinanziamento indicato nel programma conformemente ai tassi massimi di cofinanziamento elencati ai paragrafi 3 e 4.</div>\n</div>"], [null, "<p class=\"norm\">L’importo totale programmato nell’ambito di tali priorità in uno Stato membro non supera il 5 % della dotazione nazionale iniziale a titolo del FESR e del FSE+ combinati.</p>"], [null, "<p class=\"norm\">La Commissione riesamina il tasso di cofinanziamento entro il 30 giugno 2024.</p>"], [null, "<p class=\"norm\">Almeno il 30 % della dotazione finanziaria di tale priorità distinta è attribuito a operazioni i cui beneficiari sono autorità locali o organizzazioni della società civile che operano in comunità locali. Gli Stati membri riferiscono in merito al rispetto di tale condizione nella relazione finale in materia di performance di cui all’articolo 43. Se tale condizione non è soddisfatta, il rimborso da parte della Commissione nell’ambito della priorità in questione è ridotto proporzionalmente per garantire che tale condizione sia rispettata nel calcolo del saldo finale da versare al programma.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "113": {"label": "Articolo 113", "heading": "Delega di potere per quanto riguarda taluni allegati", "anchor": "art_113", "frags": [[null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 114 per modificare gli allegati del presente regolamento, ad eccezione degli allegati III, IV, XI, XIII, XIV, XVII e XXVI, al fine di adeguarli ai cambiamenti intercorsi durante il periodo di programmazione.</p>"]]}, "114": {"label": "Articolo 114", "heading": "Esercizio della delega", "anchor": "art_114", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui agli articoli 79, paragrafo 4, 94, paragrafo 4, 95, paragrafo 4, e all’articolo 113 è conferito alla Commissione per un periodo indeterminato a decorrere dal 1<span class=\"superscript\">o</span> luglio 2021.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui agli articoli 79, paragrafo 4, 94, paragrafo 4, 95, paragrafo 4, all’articolo 113 e all’articolo 117, paragrafo 2, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione dell’atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell’accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi degli articoli 79, paragrafo 4, 94, paragrafo 4, e 95, paragrafo 4, dell’articolo 113 e dell’articolo 117, paragrafo 2 entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "115": {"label": "Articolo 115", "heading": "Procedura di comitato", "anchor": "art_115", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 4 del regolamento (UE) n. 182/2011.</div>\n</div>"]]}, "116": {"label": "Articolo 116", "heading": "Riesame", "anchor": "art_116", "frags": [[null, "<p class=\"norm\">Il Parlamento europeo e il Consiglio procedono al riesame del presente regolamento entro il 31 dicembre 2027 a norma dell’articolo 177 TFUE.</p>"]]}, "117": {"label": "Articolo 117", "heading": "Disposizioni transitorie", "anchor": "art_117", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il regolamento (UE) n. 1303/2013 o qualsiasi altro atto applicabile al periodo di programmazione 2014-2020 continua ad applicarsi solo ai programmi operativi e alle operazioni sostenuti dal FESR, dal Fondo social europeo, dal Fondo di coesione e dal Fondo europeo per gli affari marittimi e la pesca in tale periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare un atto delegato per stabilire un codice europeo di condotta sul partenariato conferito alla Commissione dall’articolo 5, paragrafo 3, del regolamento (UE) n. 1303/2013, resta in vigore per il periodo di programmazione 2021-2027. La delega di potere è esercitata conformemente all’articolo 114 del presente regolamento.</div>\n</div>"]]}, "118": {"label": "Articolo 118", "heading": "Condizioni delle operazioni soggette a esecuzione scaglionata", "anchor": "art_118", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione può selezionare un’operazione che consiste nella seconda fase di un’operazione selezionata per ricevere sostegno e avviata a norma del regolamento (UE) n. 1303/2013, purché siano soddisfatte le condizioni cumulative seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’operazione, così come selezionata per ricevere sostegno a norma del regolamento (UE) n. 1303/2013, presenta due fasi distinguibili sotto l’aspetto finanziario e piste di controllo distinte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il costo totale dell’operazione di cui alla lettera a) è superiore a 5 000 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese incluse in una domanda di pagamento relativa alla prima fase non sono incluse in nessuna domanda di pagamento riguardante la seconda fase;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la seconda fase dell’operazione ottempera al diritto applicabile ed è ammissibile al sostegno del FESR, del FSE+, del Fondo di coesione o del FEAMPA a norma del presente regolamento o dei regolamenti specifici relativi ai fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro si impegna a completare durante il periodo di programmazione e a rendere operativa la seconda fase finale nella relazione finale di attuazione, o nel contesto del Fondo europeo per gli affari marittimi e la pesca nell’ultima relazione di attuazione annuale, presentata in conformità dell’articolo 141 del regolamento (UE) n. 1303/2013.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le disposizioni del presente regolamento si applicano alla seconda fase dell’operazione.</div>\n</div>"]]}, "118a": {"label": "Articolo 118 bis", "heading": "Condizioni delle operazioni soggette a esecuzione scaglionata selezionate per il sostegno prima del 29 giugno 2022 a norma del regolamento (UE) n. 1303/2013", "anchor": "art_118a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 118, laddove un’operazione con un costo totale superiore a 1 000 000  EUR sia stata selezionata per ricevere sostegno e avviata prima del 29 giugno 2022 a norma del regolamento (UE) n. 1303/2013 e dei regolamenti specifici dei fondi, (UE) n. 1301/2013 (\n<span class=\"superscript\">25</span>\n), (UE) n. 1304/2013 (\n<span class=\"superscript\">26</span>\n), (UE) n. 1300/2013 (\n<span class=\"superscript\">27</span>\n), (UE) n. 1299/2013 (\n<span class=\"superscript\">28</span>\n) e (UE) n. 508/2014 (\n<span class=\"superscript\">29</span>\n) del Parlamento europeo e del Consiglio, tale operazione è considerata ammissibile al sostegno a norma del presente regolamento e dei corrispondenti regolamenti specifici di ciascun fondo nel periodo di programmazione 2021-2027.</div>\n</div>"], [null, "<p class=\"norm inline-element\">In deroga all’articolo 73, paragrafi 1 e 2, l’autorità di gestione può decidere di concedere direttamente un sostegno a tale operazione a norma del presente regolamento, purché siano soddisfatte le condizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’operazione presenta due fasi che sono distinguibili sotto l’aspetto finanziario, e piste di controllo distinte;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’operazione rientra tra le azioni programmate nell’ambito di un particolare obiettivo specifico ed è attribuita a un tipo di intervento conformemente all’allegato I;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese incluse in una domanda di pagamento relativa alla prima fase non sono incluse in nessuna domanda di pagamento riguardante la seconda fase;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro si impegna a completare durante il periodo di programmazione e a rendere operativa la seconda fase finale nella relazione finale di attuazione, o nel contesto del Fondo europeo per gli affari marittimi e la pesca nell’ultima relazione di attuazione annuale, presentata in conformità dell’articolo 141 del regolamento (UE) n. 1303/2013.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il presente articolo non si applica alle operazioni volte a far fronte alle sfide migratorie conseguenti all’aggressione militare da parte della Federazione russa, sostenute avvalendosi della possibilità di cui all’articolo 98, paragrafo 4, primo e secondo comma, del regolamento (UE) n. 1303/2013.</p>\n</div>\n</div>"]]}, "119": {"label": "Articolo 119", "heading": "Entrata in vigore", "anchor": "art_119", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"]]}}, "recitals": {}};